#include <memory>
#include <functional>
#include <iostream>
#include <thread>
#include <chrono>

// ─── The Problem ──────────────────────────────────────────────────────────────
// A class wants to pass 'this' to an async callback.
// If the object is destroyed before the callback fires, 'this' is dangling.
// Solution: extend the object's lifetime by capturing a shared_ptr to it.
// But inside a member function, how do you get a shared_ptr to yourself?
// Answer: inherit from enable_shared_from_this.

class Session : public std::enable_shared_from_this<Session> {
public:
    explicit Session(int id) : id_{id} {}
    ~Session() { std::cout << "~Session(" << id_ << ")\n"; }

    // Returns a shared_ptr to this — only works if the object is already
    // managed by a shared_ptr (i.e., made via make_shared or shared_ptr ctor)
    std::shared_ptr<Session> ptr() { return shared_from_this(); }

    void start() {
        // Capture shared_ptr, not raw 'this'
        // This extends our lifetime until the async op completes.
        auto self = shared_from_this();  // ref count incremented

        auto callback = [self]() {       // self captured by value → another +1
            std::this_thread::sleep_for(std::chrono::milliseconds{100});
            std::cout << "Session " << self->id_ << " async callback fired\n";
            // self's ref count decrements when lambda is destroyed
        };

        std::thread{std::move(callback)}.detach();
        std::cout << "Session " << id_ << " started async op\n";
    }

    void data_ready(std::vector<uint8_t> data) {
        // Chain another async op, extending lifetime again
        auto self = shared_from_this();
        auto work = [self, d = std::move(data)]() mutable {
            std::cout << "Processing " << d.size() << " bytes for session " << self->id_ << "\n";
        };
        std::thread{std::move(work)}.detach();
    }

private:
    int id_;
};

// ─── Common mistakes ──────────────────────────────────────────────────────────
struct BadSession {
    // BAD: calling shared_from_this() before any shared_ptr exists
    // (e.g., in constructor) → throws std::bad_weak_ptr
    BadSession() {
        // auto self = shared_from_this();  // CRASH: no shared_ptr owns us yet
    }

    // BAD: calling shared_from_this() on a stack-allocated object
    // Stack objects are never managed by shared_ptr
};

int main() {
    std::cout << "Creating session\n";
    {
        auto session = std::make_shared<Session>(42);  // MUST use make_shared
        session->start();
        // session shared_ptr goes out of scope here
        // but Session is NOT destroyed yet — the lambda holds a ref
    }
    std::cout << "Local shared_ptr gone, waiting for callback...\n";
    std::this_thread::sleep_for(std::chrono::milliseconds{200});
    // ~Session fires here, after callback completes
}
```

**How it works internally:**
`enable_shared_from_this` stores a `weak_ptr<T>` inside the object. When the first `shared_ptr<T>` is created (via `make_shared` or `shared_ptr` constructor), that `weak_ptr` is initialized. `shared_from_this()` then calls `weak_ptr::lock()` to produce a new `shared_ptr` that shares ownership.

**Rules:**
1. Never call `shared_from_this()` in the constructor — the weak_ptr hasn't been seeded yet.
2. Never create a `shared_ptr<T>` from a raw `this` inside a member function — creates a second independent ownership group.
3. The object MUST be heap-allocated and already managed by at least one `shared_ptr`.

```cpp
#include <mutex>
#include <thread>
#include <stdexcept>
#include <string>
#include <iostream>
#include <cassert>

// ─── Hierarchical Mutex ───────────────────────────────────────────────────────
// Each mutex has a numeric level. Threads must always acquire mutexes in
// strictly descending level order. Violation is detected immediately.
class HierarchicalMutex {
public:
    explicit HierarchicalMutex(unsigned level, std::string name = "")
        : level_{level}, name_{std::move(name)} {}

    void lock() {
        check_for_hierarchy_violation();
        mu_.lock();
        update_hierarchy_value();
    }

    bool try_lock() {
        check_for_hierarchy_violation();
        if (!mu_.try_lock()) return false;
        update_hierarchy_value();
        return true;
    }

    void unlock() noexcept {
        if (this_thread_hierarchy_value_ != level_)
            throw std::logic_error{"Hierarchy invariant broken on unlock"};
        this_thread_hierarchy_value_ = prev_hierarchy_value_;
        mu_.unlock();
    }

    unsigned level() const noexcept { return level_; }
    const std::string& name() const noexcept { return name_; }

private:
    void check_for_hierarchy_violation() const {
        if (this_thread_hierarchy_value_ <= level_) {
            throw std::logic_error{
                "Hierarchy violation: trying to lock '" + name_ +
                "' (level=" + std::to_string(level_) +
                ") while holding a mutex at level=" +
                std::to_string(this_thread_hierarchy_value_)
            };
        }
    }

    void update_hierarchy_value() noexcept {
        prev_hierarchy_value_       = this_thread_hierarchy_value_;
        this_thread_hierarchy_value_ = level_;
    }

    std::mutex mu_;
    const unsigned level_;
    const std::string name_;
    unsigned prev_hierarchy_value_{0};  // per-lock (restored on unlock)

    // thread_local: each thread has its own "current deepest level held"
    static inline thread_local unsigned this_thread_hierarchy_value_{UINT_MAX};
};

// ─── Demo ─────────────────────────────────────────────────────────────────────
HierarchicalMutex db_mutex    {1000, "database"};
HierarchicalMutex cache_mutex { 500, "cache"};
HierarchicalMutex log_mutex   { 100, "log"};

void correct_order() {
    std::lock_guard db{db_mutex};      // 1000 — highest first
    std::lock_guard ca{cache_mutex};   // 500  — OK: 1000 > 500
    std::lock_guard lg{log_mutex};     // 100  — OK: 500 > 100
    std::cout << "[correct] all locks acquired\n";
}

void wrong_order() {
    std::lock_guard ca{cache_mutex};   // 500
    // DETECTED: trying to acquire 1000 while holding 500
    std::lock_guard db{db_mutex};      // throws logic_error
}

int main() {
    correct_order();

    try {
        wrong_order();
    } catch (const std::logic_error& e) {
        std::cout << "Deadlock risk detected: " << e.what() << "\n";
    }
}
```

This is an O(1) runtime check per lock acquisition. In production, wrap with `#ifdef DEBUG` to zero-cost in release builds. The pattern is described in Williams' "C++ Concurrency in Action" — it catches real deadlock bugs during development without requiring formal analysis.

```cpp
#include <ranges>
#include <string>
#include <string_view>
#include <vector>
#include <iostream>
#include <algorithm>
#include <sstream>

// ─── Domain types ─────────────────────────────────────────────────────────────
enum class Severity { DEBUG, INFO, WARN, ERROR, FATAL };

struct LogEntry {
    Severity    severity;
    std::string timestamp;
    std::string message;
};

// ─── Parsing helpers ──────────────────────────────────────────────────────────
Severity parse_severity(std::string_view s) {
    if (s == "DEBUG") return Severity::DEBUG;
    if (s == "INFO")  return Severity::INFO;
    if (s == "WARN")  return Severity::WARN;
    if (s == "ERROR") return Severity::ERROR;
    return Severity::FATAL;
}

// Parse "SEVERITY TIMESTAMP message..." format
std::optional<LogEntry> parse_line(std::string_view line) {
    auto sp1 = line.find(' ');
    if (sp1 == std::string_view::npos) return std::nullopt;
    auto sp2 = line.find(' ', sp1 + 1);
    if (sp2 == std::string_view::npos) return std::nullopt;

    return LogEntry{
        parse_severity(line.substr(0, sp1)),
        std::string{line.substr(sp1 + 1, sp2 - sp1 - 1)},
        std::string{line.substr(sp2 + 1)}
    };
}

int main() {
    // Simulated log lines — in production, this could be a generator from a file
    std::vector<std::string> raw_logs = {
        "DEBUG 10:00:01 connection pool initialized",
        "INFO  10:00:02 server started on :8080",
        "WARN  10:00:03 high memory usage detected",
        "ERROR 10:00:04 failed to connect to database",
        "DEBUG 10:00:05 retry attempt 1",
        "ERROR 10:00:06 timeout after 30s",
        "INFO  10:00:07 graceful shutdown initiated",
        "FATAL 10:00:08 unrecoverable error in core",
    };

    // ─── Ranges pipeline — everything is lazy ─────────────────────────────────
    auto pipeline =
        raw_logs
        | std::views::transform([](const std::string& line) {
              return parse_line(line);           // std::optional<LogEntry>
          })
        | std::views::filter([](const auto& opt) {
              return opt.has_value();            // drop malformed lines
          })
        | std::views::transform([](auto& opt) -> LogEntry& {
              return opt.value();               // unwrap optional
          })
        | std::views::filter([](const LogEntry& e) {
              return e.severity >= Severity::WARN; // only WARN and above
          })
        | std::views::take(3);                   // first 3 results only

    // ─── Materialize ─────────────────────────────────────────────────────────
    for (const LogEntry& entry : pipeline) {
        const char* sev_names[] = {"DEBUG","INFO","WARN","ERROR","FATAL"};
        std::cout << "[" << sev_names[static_cast<int>(entry.severity)] << "] "
                  << entry.timestamp << " — " << entry.message << "\n";
    }
    // Output:
    // [WARN]  10:00:03 — high memory usage detected
    // [ERROR] 10:00:04 — failed to connect to database
    // [ERROR] 10:00:06 — timeout after 30s

    // ─── Range algorithms compose with pipelines ──────────────────────────────
    // Count errors without materializing a vector:
    long error_count = std::ranges::count_if(
        raw_logs
        | std::views::transform([](const std::string& l){ return parse_line(l); })
        | std::views::filter([](const auto& o){ return o.has_value(); })
        | std::views::transform([](auto& o) -> const LogEntry& { return *o; }),
        [](const LogEntry& e){ return e.severity == Severity::ERROR; }
    );
    std::cout << "Error count: " << error_count << "\n";  // 2
}
```

**Laziness matters:** `views::take(3)` short-circuits the pipeline — only 4 lines are ever examined (3 WARN+ found at positions 3,4,6). Without ranges, a naive loop-and-collect would process all 8 lines before filtering. For a file with millions of lines, this is the difference between O(N) work and O(result_size) work.

