#include <tuple>       // for std::tuple_size, std::tuple_element
#include <utility>     // for std::index_sequence
#include <string>
#include <iostream>

// ─── Custom type we want to support structured bindings ───────────────────────
struct Color {
    uint8_t r, g, b, a;

    // Named access — ergonomic API
    uint8_t red()   const noexcept { return r; }
    uint8_t green() const noexcept { return g; }
    uint8_t blue()  const noexcept { return b; }
    uint8_t alpha() const noexcept { return a; }
};

// ─── Step 1: Specialize std::tuple_size<Color> ────────────────────────────────
// Tells the compiler how many bindings to create
template<>
struct std::tuple_size<Color>
    : std::integral_constant<std::size_t, 4> {};

// ─── Step 2: Specialize std::tuple_element<I, Color> ─────────────────────────
// Tells the compiler the type of the I-th binding
template<std::size_t I>
struct std::tuple_element<I, Color> {
    static_assert(I < 4, "Color index out of range");
    using type = uint8_t;  // all four components are uint8_t
};

// ─── Step 3: Provide get<I>(Color) overloads (ADL-findable) ──────────────────
// Must be in the same namespace as Color OR in std (we use global ADL here).
template<std::size_t I>
uint8_t get(const Color& c) noexcept {
    if constexpr (I == 0) return c.r;
    else if constexpr (I == 1) return c.g;
    else if constexpr (I == 2) return c.b;
    else                        return c.a;
}

template<std::size_t I>
uint8_t& get(Color& c) noexcept {
    if constexpr (I == 0) return c.r;
    else if constexpr (I == 1) return c.g;
    else if constexpr (I == 2) return c.b;
    else                        return c.a;
}

// ─── Another example: a key-value pair with different types per element ────────
template<typename K, typename V>
struct KVPair {
    K key;
    V value;
};

template<typename K, typename V>
struct std::tuple_size<KVPair<K,V>>
    : std::integral_constant<std::size_t, 2> {};

template<std::size_t I, typename K, typename V>
struct std::tuple_element<I, KVPair<K,V>> {
    using type = std::conditional_t<I == 0, K, V>;
};

template<std::size_t I, typename K, typename V>
auto& get(KVPair<K,V>& kv) noexcept {
    if constexpr (I == 0) return kv.key;
    else                   return kv.value;
}

template<std::size_t I, typename K, typename V>
const auto& get(const KVPair<K,V>& kv) noexcept {
    if constexpr (I == 0) return kv.key;
    else                   return kv.value;
}

int main() {
    // ── Color structured binding ───────────────────────────────────────────
    Color sky{135, 206, 235, 255};
    auto [r, g, b, a] = sky;
    std::cout << "RGBA: " << (int)r << " " << (int)g
              << " " << (int)b << " " << (int)a << "\n";  // 135 206 235 255

    // Modify via reference binding
    auto& [rr, rg, rb, ra] = sky;
    rr = 100;  // modifies sky.r directly
    std::cout << "Modified r: " << (int)sky.r << "\n";  // 100

    // ── KVPair structured binding ─────────────────────────────────────────
    KVPair<std::string, int> entry{"timeout", 30};
    auto& [key, val] = entry;
    std::cout << key << " = " << val << "\n";  // timeout = 30
    val = 60;  // modifies entry.value

    // ── Works in range-for ────────────────────────────────────────────────
    std::vector<KVPair<std::string, int>> config = {
        {"port", 8080}, {"workers", 4}, {"timeout", 30}
    };
    for (const auto& [k, v] : config)
        std::cout << k << ": " << v << "\n";
}
```

**Three-step protocol for structured bindings:**
1. `std::tuple_size<T>` — how many identifiers to declare.
2. `std::tuple_element<I, T>` — the type of the I-th identifier.
3. `get<I>(obj)` — how to extract the I-th value (via ADL or member function).

If your type is a simple aggregate (struct with only public members, no base classes, no user-declared constructors), structured bindings work automatically without any specializations — the compiler uses member access directly.

```cpp
#include <optional>
#include <string>
#include <string_view>
#include <charconv>
#include <iostream>
#include <functional>
#include <vector>

// ─── C++23 monadic optional operations (backport for C++20) ──────────────────
// std::optional already has these in C++23.
// For C++20, we build free-function wrappers.

template<typename T, typename F>
auto and_then(std::optional<T> opt, F&& f) {
    // F: T -> optional<U>
    using Result = std::invoke_result_t<F, T>;
    if (!opt) return Result{std::nullopt};
    return std::invoke(std::forward<F>(f), *opt);
}

template<typename T, typename F>
auto transform(std::optional<T> opt, F&& f) {
    // F: T -> U  (wraps result in optional)
    using U = std::invoke_result_t<F, T>;
    if (!opt) return std::optional<U>{};
    return std::optional<U>{std::invoke(std::forward<F>(f), *opt)};
}

template<typename T, typename F>
std::optional<T> or_else(std::optional<T> opt, F&& f) {
    // F: () -> optional<T>  (recovery function)
    if (opt) return opt;
    return std::invoke(std::forward<F>(f));
}

// ─── Parsing primitives ────────────────────────────────────────────────────────
std::optional<int> parse_int(std::string_view s) {
    int v;
    auto [ptr, ec] = std::from_chars(s.data(), s.data() + s.size(), v);
    if (ec != std::errc{}) return std::nullopt;
    return v;
}

std::optional<std::string_view> get_field(std::string_view csv, int field_idx) {
    int idx = 0;
    std::size_t pos = 0;
    while (pos <= csv.size()) {
        auto end = csv.find(',', pos);
        if (end == std::string_view::npos) end = csv.size();
        if (idx == field_idx) return csv.substr(pos, end - pos);
        ++idx;
        pos = end + 1;
    }
    return std::nullopt;
}

std::optional<int> clamp_positive(int v) {
    if (v <= 0) return std::nullopt;
    return v;
}

// ─── Config parser: chain operations with and_then/transform/or_else ──────────
struct Config {
    int port;
    int workers;
    int timeout_ms;
};

std::optional<Config> parse_config_line(std::string_view line) {
    // line format: "port,workers,timeout_ms"
    // Each step returns nullopt on failure, propagating through the chain.

    auto port = and_then(get_field(line, 0), parse_int);
    port = and_then(port, clamp_positive);
    port = and_then(port, [](int p) -> std::optional<int> {
        return (p < 65536) ? std::optional{p} : std::nullopt;
    });

    auto workers = and_then(get_field(line, 1), parse_int);
    workers = or_else(workers, []{ return std::optional<int>{1}; });  // default = 1

    auto timeout = and_then(get_field(line, 2), parse_int);
    timeout = transform(timeout, [](int t) { return t * 1000; });     // s -> ms, maps value
    timeout = or_else(timeout, []{ return std::optional<int>{5000}; }); // default 5s

    if (!port || !workers || !timeout) return std::nullopt;
    return Config{*port, *workers, *timeout};
}

int main() {
    // Success case
    if (auto cfg = parse_config_line("8080,4,30")) {
        std::cout << "port="    << cfg->port
                  << " workers=" << cfg->workers
                  << " timeout=" << cfg->timeout_ms << "ms\n";
        // port=8080 workers=4 timeout=30000ms
    }

    // Missing fields use defaults
    if (auto cfg = parse_config_line("3000,,")) {
        std::cout << "port=" << cfg->port
                  << " workers=" << cfg->workers   // default 1
                  << " timeout=" << cfg->timeout_ms << "ms\n";  // default 5000
    }

    // Invalid port — chain produces nullopt
    if (!parse_config_line("-1,4,30"))
        std::cout << "invalid config rejected\n";

    // C++23 member syntax (if available):
    // auto result = get_field(line, 0)
    //                 .and_then(parse_int)
    //                 .and_then(clamp_positive);
}
```

**Monadic operation semantics:**
- `and_then(opt, f)`: if `opt` has value, call `f(*opt)` which returns `optional<U>`; else propagate nullopt.
- `transform(opt, f)`: if `opt` has value, call `f(*opt)` returning `U`, wrap in `optional<U>`; else nullopt.
- `or_else(opt, f)`: if `opt` is empty, call `f()` for a recovery `optional<T>`; else pass through.

This eliminates nested `if (opt) { if (inner_opt) {...} }` chains in favor of linear, readable pipelines.

