#include <type_traits>
#include <vector>
#include <list>
#include <optional>
#include <memory>
#include <tuple>
#include <variant>
#include <iostream>

// Detect if T is a specialization of Template (variadic type params)
template<typename T, template<typename...> class Template>
struct is_specialization : std::false_type {};

template<typename... Args, template<typename...> class Template>
struct is_specialization<Template<Args...>, Template> : std::true_type {};

template<typename T, template<typename...> class Template>
constexpr bool is_specialization_v = is_specialization<T, Template>::value;

// Concept wrapper
template<typename T, template<typename...> class Template>
concept Specialization = is_specialization_v<T, Template>;

// Specific helpers
template<typename T> constexpr bool is_optional_v    = is_specialization_v<T, std::optional>;
template<typename T> constexpr bool is_vector_v      = is_specialization_v<T, std::vector>;
template<typename T> constexpr bool is_shared_ptr_v  = is_specialization_v<T, std::shared_ptr>;

// Concept-constrained function: only accepts vector specializations
template<Specialization<std::vector> V>
void process_vector(const V& v) {
    std::cout << "vector of " << v.size() << " elements\n";
}

// Flatten optional<optional<T>> -> optional<T>
template<typename T>
    requires is_optional_v<T> && is_optional_v<typename T::value_type>
auto flatten(T opt_opt) -> typename T::value_type {
    if (!opt_opt) return std::nullopt;
    return *opt_opt;
}

// Unwrap optional if it is one, else return as-is
template<typename T>
auto unwrap_or(const T& val, auto fallback) {
    if constexpr (is_optional_v<std::decay_t<T>>)
        return val.value_or(fallback);
    else
        return val;
}

int main() {
    static_assert( is_specialization_v<std::vector<int>,     std::vector>);
    static_assert( is_specialization_v<std::list<float>,     std::list>);
    static_assert( is_specialization_v<std::optional<int>,   std::optional>);
    static_assert( is_specialization_v<std::shared_ptr<int>, std::shared_ptr>);
    static_assert( is_specialization_v<std::tuple<int,double,char>, std::tuple>);
    static_assert( is_specialization_v<std::variant<int,float>,     std::variant>);
    static_assert(!is_specialization_v<int,        std::vector>);
    static_assert(!is_specialization_v<std::string,std::vector>);

    static_assert( is_optional_v<std::optional<int>>);
    static_assert(!is_optional_v<int>);
    static_assert(!is_optional_v<std::vector<int>>);

    process_vector(std::vector<int>{1,2,3});
    process_vector(std::vector<std::string>{"a","b"});
    // process_vector(std::list<int>{});  // compile error

    std::cout << unwrap_or(std::optional<int>{42}, 0)  << "\n"; // 42
    std::cout << unwrap_or(99, 0) << "\n";                       // 99

    std::optional<std::optional<int>> nested{std::optional<int>{7}};
    std::cout << flatten(nested).value_or(-1) << "\n"; // 7
    std::cout << "All checks passed\n";
}
```

**How it works:** The partial specialization `is_specialization<Template<Args...>, Template>` matches when `T` is exactly `Template` applied to some `Args...`. The primary template catches everything else with `false_type`. This works for any template with type-only parameters (vector, optional, tuple, variant, shared_ptr). Non-type template parameters like `std::array<T,N>` require a separate specialization:
```cpp
template<typename T, std::size_t N>
struct is_specialization<std::array<T,N>, std::array> : std::true_type {};
```

```cpp
#include <atomic>
#include <cstdint>
#include <optional>
#include <memory>

template<typename T>
class LockFreeStack {
    struct Node {
        T value;
        Node* next;
        explicit Node(T v) : value(std::move(v)), next(nullptr) {}
    };

    // Tagged pointer: low 16 bits = ABA counter, upper bits = pointer
    // On x86-64 user space, top 16 bits of ptr are unused — we use a
    // separate counter packed into a struct for clarity.
    struct TaggedPtr {
        Node* ptr;
        uintptr_t tag;
    };

    std::atomic<TaggedPtr> head_{{nullptr, 0}};

public:
    void push(T val) {
        Node* node = new Node(std::move(val));
        TaggedPtr old_head = head_.load(std::memory_order_relaxed);
        TaggedPtr new_head;
        do {
            node->next = old_head.ptr;
            new_head = {node, old_head.tag + 1};
        } while (!head_.compare_exchange_weak(
            old_head, new_head,
            std::memory_order_release,
            std::memory_order_relaxed));
    }

    std::optional<T> pop() {
        TaggedPtr old_head = head_.load(std::memory_order_acquire);
        TaggedPtr new_head;
        do {
            if (!old_head.ptr) return std::nullopt;
            new_head = {old_head.ptr->next, old_head.tag + 1};
        } while (!head_.compare_exchange_weak(
            old_head, new_head,
            std::memory_order_acquire,
            std::memory_order_acquire));

        T val = std::move(old_head.ptr->value);
        delete old_head.ptr; // Safe only in single-consumer or with hazard ptrs
        return val;
    }
};
```

**ABA problem:** Thread 1 reads head=A, preempted. Thread 2 pops A, pushes new node that reuses A's address. Thread 1's CAS succeeds incorrectly — the tag counter prevents this by making {A, tag=1} != {A, tag=0}.

**Memory ordering rationale:**
- `push`: `release` on success ensures node writes are visible before pointer is published.
- `pop`: `acquire` on load ensures we see all writes to the node before reading it.

**Production note:** This `delete` in `pop` is unsafe under concurrent access (use epoch-based reclamation or hazard pointers for a real implementation).

```cpp
#include <shared_mutex>
#include <unordered_map>
#include <string>
#include <optional>
#include <print>

template<typename K, typename V>
class RWCache {
    mutable std::shared_mutex mu_;
    std::unordered_map<K, V> data_;

public:
    // Multiple threads can read concurrently
    std::optional<V> get(const K& key) const {
        std::shared_lock lock(mu_); // shared (read) lock
        auto it = data_.find(key);
        if (it == data_.end()) return std::nullopt;
        return it->second;
    }

    // Only one thread writes; blocks all readers
    void put(const K& key, V value) {
        std::unique_lock lock(mu_); // exclusive (write) lock
        data_.emplace(key, std::move(value));
    }

    // Upgrade pattern: check then write atomically
    V get_or_insert(const K& key, std::invocable<> auto factory) {
        {
            std::shared_lock lock(mu_);
            auto it = data_.find(key);
            if (it != data_.end()) return it->second;
        }
        // Drop shared lock before upgrading — no direct upgrade in C++
        std::unique_lock lock(mu_);
        // Re-check after acquiring exclusive lock (double-checked locking)
        auto [it, inserted] = data_.emplace(key, factory());
        return it->second;
    }

    std::size_t size() const {
        std::shared_lock lock(mu_);
        return data_.size();
    }
};

int main() {
    RWCache<std::string, int> cache;
    cache.put("x", 10);

    // Concurrent reads are non-blocking relative to each other
    auto val = cache.get("x");
    std::println("x = {}", val.value_or(-1));

    // get_or_insert with lazy factory
    int computed = cache.get_or_insert("y", []{ return 99; });
    std::println("y = {}", computed);
}
```

**Key rules:**
- `std::shared_lock` → multiple concurrent holders allowed (readers).
- `std::unique_lock` → exclusive, blocks all others (writer).
- There is no lock upgrade in C++. Drop shared lock, reacquire as unique, and re-check invariants.
- Mark methods `const` + mutex `mutable` for logical const-correctness.

```cpp
#include <condition_variable>
#include <mutex>
#include <queue>
#include <thread>
#include <optional>
#include <print>

template<typename T>
class BoundedQueue {
    std::queue<T> buf_;
    const std::size_t cap_;
    std::mutex mu_;
    std::condition_variable not_full_;
    std::condition_variable not_empty_;
    bool closed_ = false;

public:
    explicit BoundedQueue(std::size_t cap) : cap_(cap) {}

    // Producer side — blocks when full
    bool push(T item) {
        std::unique_lock lock(mu_);
        not_full_.wait(lock, [this]{
            return buf_.size() < cap_ || closed_;
        });
        if (closed_) return false;
        buf_.push(std::move(item));
        not_empty_.notify_one();
        return true;
    }

    // Consumer side — blocks when empty
    std::optional<T> pop() {
        std::unique_lock lock(mu_);
        not_empty_.wait(lock, [this]{
            return !buf_.empty() || closed_;
        });
        if (buf_.empty()) return std::nullopt; // queue closed and drained
        T item = std::move(buf_.front());
        buf_.pop();
        not_full_.notify_one();
        return item;
    }

    void close() {
        std::lock_guard lock(mu_);
        closed_ = true;
        not_full_.notify_all();
        not_empty_.notify_all();
    }
};

int main() {
    BoundedQueue<int> q(4);

    std::jthread producer([&](std::stop_token st) {
        for (int i = 0; i < 20 && !st.stop_requested(); ++i) {
            if (!q.push(i)) break;
            std::println("Produced {}", i);
        }
        q.close();
    });

    std::jthread consumer([&] {
        while (auto item = q.pop())
            std::println("Consumed {}", *item);
    });
}
```

**Critical patterns:**
- Always use a **predicate** with `wait()` to guard against spurious wakeups.
- Check `closed_` inside the predicate so waiters wake on close.
- `notify_one()` is sufficient when only one consumer/producer needs to wake; use `notify_all()` on close.
- Hold the lock when modifying shared state; release it only when waiting.

```cpp
#include <mutex>
#include <memory>
#include <print>

// Pattern 1: Meyers Singleton (C++11+ — local static is thread-safe)
class MeyersSingleton {
public:
    static MeyersSingleton& instance() {
        static MeyersSingleton inst; // Guaranteed initialized once, thread-safe
        return inst;
    }

    void do_work() { std::println("Meyers singleton working"); }

private:
    MeyersSingleton() = default;
    MeyersSingleton(const MeyersSingleton&) = delete;
    MeyersSingleton& operator=(const MeyersSingleton&) = delete;
};

// Pattern 2: call_once with unique_ptr (useful when you need pointer semantics
// or deferred initialization with external dependencies)
class ConfigurableSingleton {
    int config_;
    explicit ConfigurableSingleton(int cfg) : config_(cfg) {}

    static std::unique_ptr<ConfigurableSingleton> inst_;
    static std::once_flag flag_;

public:
    static ConfigurableSingleton& instance(int cfg = 0) {
        std::call_once(flag_, [cfg]{
            inst_ = std::make_unique<ConfigurableSingleton>(cfg);
        });
        return *inst_;
    }

    int config() const { return config_; }
};

std::unique_ptr<ConfigurableSingleton> ConfigurableSingleton::inst_;
std::once_flag ConfigurableSingleton::flag_;

int main() {
    // Meyers: simple, preferred in most cases
    MeyersSingleton::instance().do_work();

    // call_once: first call with cfg=42 wins
    auto& c1 = ConfigurableSingleton::instance(42);
    auto& c2 = ConfigurableSingleton::instance(99); // ignored
    std::println("Config: {}", c1.config()); // 42
    std::println("Same? {}", &c1 == &c2);   // true
}
```

**Why Meyers wins:** The C++11 standard mandates that local static initialization is thread-safe (§6.7). Zero overhead, no mutex, no raw pointer. Use it unless you need the singleton to be explicitly destroyable or configurable at first call.

**Pitfall:** Avoid the pre-C++11 double-checked locking pattern with raw pointers — it was broken without fences. The above patterns are correct and simpler.

```cpp
#include <future>
#include <thread>
#include <stdexcept>
#include <print>

// Basic promise/future value transfer
void compute(std::promise<int> prom, int x) {
    try {
        if (x < 0)
            throw std::invalid_argument("negative input");
        prom.set_value(x * x);
    } catch (...) {
        prom.set_exception(std::current_exception()); // propagate to future
    }
}

int main() {
    // --- Happy path ---
    std::promise<int> p1;
    std::future<int> f1 = p1.get_future();
    std::thread t1(compute, std::move(p1), 7);
    std::println("7^2 = {}", f1.get());
    t1.join();

    // --- Exception propagation ---
    std::promise<int> p2;
    std::future<int> f2 = p2.get_future();
    std::thread t2(compute, std::move(p2), -1);
    t2.join();
    try {
        f2.get(); // rethrows stored exception
    } catch (const std::exception& e) {
        std::println("Caught: {}", e.what()); // "negative input"
    }

    // --- shared_future: broadcast one result to many waiters ---
    std::promise<std::string> p3;
    std::shared_future<std::string> sf = p3.get_future().share();

    auto reader = [sf]{ // copyable
        std::println("Got: {}", sf.get());
    };

    std::thread t3(reader), t4(reader);
    p3.set_value("hello");
    t3.join(); t4.join();
}
```

**Key behaviors:**
- `promise::set_value` / `set_exception` can only be called **once** — second call throws `std::future_error`.
- `future::get()` can also be called only once; use `shared_future` for multiple consumers.
- If a promise is destroyed without `set_value/exception`, the future receives `broken_promise` exception.
- Exception propagates across thread boundaries transparently — no manual error codes needed.

```cpp
#include <atomic>
#include <thread>
#include <vector>
#include <print>

class Spinlock {
    std::atomic_flag flag_ = ATOMIC_FLAG_INIT;

public:
    void lock() noexcept {
        // Exponential backoff to reduce cache-line thrashing
        int backoff = 1;
        while (flag_.test_and_set(std::memory_order_acquire)) {
            for (int i = 0; i < backoff; ++i)
                __builtin_ia32_pause(); // x86 PAUSE: reduces pipeline stalls
            if (backoff < 1024) backoff <<= 1;
        }
    }

    void unlock() noexcept {
        flag_.clear(std::memory_order_release);
    }

    // RAII guard
    struct Guard {
        Spinlock& sl;
        explicit Guard(Spinlock& s) : sl(s) { sl.lock(); }
        ~Guard() { sl.unlock(); }
    };

    [[nodiscard]] Guard guard() { return Guard{*this}; }
};

// Usage
Spinlock sl;
int shared_counter = 0;

void increment(int n) {
    for (int i = 0; i < n; ++i) {
        auto g = sl.guard();
        ++shared_counter;
    }
}

int main() {
    std::vector<std::jthread> threads;
    for (int i = 0; i < 8; ++i)
        threads.emplace_back(increment, 100'000);
    threads.clear(); // joins all
    std::println("Counter: {}", shared_counter); // 800000
}
```

**When spinlocks win over std::mutex:**
- Critical section is **< ~100 ns** (mutex lock/unlock costs ~25-50 ns in kernel path)
- Thread count <= core count (no context switch waste)
- Lock is almost never contended

**When mutexes win:**
- Critical section > a few microseconds (spinning wastes a whole core)
- High contention — spinning burns CPU that other threads could use
- Running on a hypervisor or oversubscribed system

**The backoff loop:** Without it, all spinning threads hammer the same cache line, causing O(N²) cache-coherence traffic. PAUSE instruction yields the CPU pipeline and reduces this dramatically.

```cpp
#include <thread>
#include <unordered_map>
#include <string>
#include <print>
#include <random>

// thread_local = one independent instance per thread
// Initialized lazily on first access by each thread
thread_local std::unordered_map<std::string, int> tl_cache;

// Per-thread RNG — avoids mutex on std::mt19937
thread_local std::mt19937 tl_rng{std::random_device{}()};

int expensive_lookup(const std::string& key) {
    auto it = tl_cache.find(key);
    if (it != tl_cache.end()) return it->second;

    // Simulate expensive computation
    int result = std::uniform_int_distribution<int>(1, 1000)(tl_rng);
    tl_cache.emplace(key, result);
    return result;
}

void worker(int id) {
    // Each thread has its own tl_cache — no mutex needed
    for (auto& k : {"alpha", "beta", "gamma", "alpha"}) {
        int v = expensive_lookup(k);
        std::println("Thread {} key={} val={} cache_size={}",
            id, k, v, tl_cache.size());
    }
    // tl_cache for this thread destroyed when thread exits
}

// thread_local with custom destructor via class
class PerThreadLogger {
public:
    PerThreadLogger() {
        std::println("Logger created for thread {}",
            std::this_thread::get_id());
    }
    ~PerThreadLogger() {
        std::println("Logger destroyed for thread {}",
            std::this_thread::get_id());
    }
    void log(std::string_view msg) { std::println("[LOG] {}", msg); }
};

thread_local PerThreadLogger logger;

int main() {
    std::vector<std::jthread> threads;
    for (int i = 0; i < 3; ++i)
        threads.emplace_back(worker, i);
}
```

**Lifetime rules:**
- `thread_local` with static storage duration: initialized before first use on each thread.
- Destroyed when the thread exits (reverse construction order, like statics).
- For the **main thread**, lifetime = program lifetime (same as `static`).
- No synchronization needed — each thread owns its instance entirely.

**Common uses:** Per-thread allocators, RNG state, profiling buffers, connection pools.

```cpp
#include <mutex>
#include <print>
#include <thread>

struct Account {
    int id;
    double balance;
    std::mutex mu;

    Account(int i, double b) : id(i), balance(b) {}
};

// WRONG: lock order not consistent → deadlock risk
void transfer_unsafe(Account& from, Account& to, double amount) {
    std::lock_guard lk1(from.mu); // Thread A locks from, Thread B locks to
    std::lock_guard lk2(to.mu);   // Both deadlock waiting for the other
    from.balance -= amount;
    to.balance   += amount;
}

// CORRECT: scoped_lock acquires multiple mutexes deadlock-free
// Uses a deadlock-avoidance algorithm (equivalent to std::lock)
void transfer(Account& from, Account& to, double amount) {
    std::scoped_lock lock(from.mu, to.mu); // atomic multi-lock
    from.balance -= amount;
    to.balance   += amount;
    std::println("Transferred {} from acc#{} to acc#{}",
        amount, from.id, to.id);
}

int main() {
    Account alice{1, 1000.0}, bob{2, 500.0};

    // Two threads transferring in opposite directions — classic deadlock scenario
    std::jthread t1([&]{ transfer(alice, bob, 100.0); });
    std::jthread t2([&]{ transfer(bob, alice, 50.0); });
    // Both complete without deadlock

    std::println("Alice: {}, Bob: {}", alice.balance, bob.balance);
}
```

**How scoped_lock avoids deadlock:**
Internally calls `std::lock(m1, m2, ...)` which uses a try-and-back-off strategy: if it can't acquire all mutexes, it releases what it has and retries in a different order. This breaks the circular wait condition.

**scoped_lock vs lock_guard:**
- `lock_guard<M>` → single mutex, zero overhead, prefer this for one mutex.
- `scoped_lock<M...>` → variadic, handles N mutexes safely, slight overhead.
- `unique_lock` → movable, supports deferred lock and timed lock (most flexible).

**Deadlock avoidance rules (without scoped_lock):**
1. Always acquire locks in a consistent global order.
2. Never hold a lock while calling user-supplied callbacks.
3. Prefer scoped_lock when you must hold 2+ mutexes.

```cpp
#include <mutex>
#include <stdexcept>
#include <print>
#include <thread>

// Strategy 1: Consistent global lock order by address
void ordered_lock(std::mutex& a, std::mutex& b) {
    std::mutex* first  = &a < &b ? &a : &b;
    std::mutex* second = &a < &b ? &b : &a;
    first->lock();
    second->lock();
}

// Strategy 2: try_lock with backoff (non-blocking)
bool try_transfer(std::mutex& m1, std::mutex& m2) {
    std::unique_lock lk1(m1, std::try_to_lock);
    if (!lk1) return false;
    std::unique_lock lk2(m2, std::try_to_lock);
    if (!lk2) return false;
    // both acquired — do work
    return true;
}

// Strategy 3: Hierarchical mutex — enforces lock order at runtime
class HierarchicalMutex {
    std::mutex mu_;
    const int level_;
    int prev_level_ = 0;
    inline static thread_local int current_level_ = INT_MAX;

public:
    explicit HierarchicalMutex(int level) : level_(level) {}

    void lock() {
        if (level_ >= current_level_)
            throw std::logic_error("Lock order violation");
        mu_.lock();
        prev_level_ = current_level_;
        current_level_ = level_;
    }

    void unlock() {
        current_level_ = prev_level_;
        mu_.unlock();
    }

    bool try_lock() {
        if (level_ >= current_level_) return false;
        if (!mu_.try_lock()) return false;
        prev_level_ = current_level_;
        current_level_ = level_;
        return true;
    }
};

HierarchicalMutex high_mu(100); // lower number = lower in hierarchy
HierarchicalMutex low_mu(200);

void correct_order() {
    std::lock_guard lk1(high_mu); // lock higher level first
    std::lock_guard lk2(low_mu);
    std::println("Correct order: ok");
}

void wrong_order() {
    std::lock_guard lk1(low_mu);
    // std::lock_guard lk2(high_mu); // throws at runtime!
}

int main() {
    correct_order();
    // HierarchicalMutex catches violations in debug/test builds
}
```

**Summary of strategies:**
1. **Consistent ordering** — simplest, works when you control all lock sites.
2. **std::scoped_lock** — best default for multi-mutex acquisition.
3. **try_lock + backoff** — for opportunistic locking, retry loops.
4. **Hierarchical mutex** — enforces ordering contracts at runtime, useful in large codebases.

```cpp
#include <atomic>
#include <print>

// compare_exchange_weak: may spuriously fail even if *this == expected
// compare_exchange_strong: only fails if *this != expected

// RULE: Use _weak inside retry loops (more efficient on some architectures)
// Use _strong when you can't retry or need one-shot semantics

std::atomic<int> val{0};

// Pattern 1: CAS loop — always use _weak
void atomic_max(std::atomic<int>& a, int newval) {
    int cur = a.load(std::memory_order_relaxed);
    // Loop handles both spurious failures (_weak) and lost races
    while (cur < newval &&
           !a.compare_exchange_weak(cur, newval,
               std::memory_order_release,
               std::memory_order_relaxed)) {
        // cur is updated to actual value on failure — don't reset it
    }
}

// Pattern 2: One-shot — use _strong
bool try_claim(std::atomic<bool>& flag) {
    bool expected = false;
    // Only one thread should succeed; no retry wanted
    return flag.compare_exchange_strong(expected, true,
        std::memory_order_acquire,
        std::memory_order_relaxed);
}

// Pattern 3: Fetch-then-modify pattern
void push_if_empty(std::atomic<int*>& ptr, int* newptr) {
    int* expected = nullptr;
    // _strong: retry here would be wrong — we only want to set if truly null
    ptr.compare_exchange_strong(expected, newptr,
        std::memory_order_release,
        std::memory_order_relaxed);
}

int main() {
    // atomic_max demo
    std::atomic<int> max_seen{0};
    for (int v : {3, 7, 2, 9, 4})
        atomic_max(max_seen, v);
    std::println("Max: {}", max_seen.load()); // 9

    // try_claim: only first call returns true
    std::atomic<bool> claimed{false};
    std::println("Claim 1: {}", try_claim(claimed)); // true
    std::println("Claim 2: {}", try_claim(claimed)); // false
}
```

**Why _weak can spuriously fail:** On LL/SC architectures (ARM, POWER), the hardware uses a "load-linked" reservation that can be cancelled by any interrupt or cache event, causing SC to fail even when the value matches. x86 CAS doesn't have this, but using _weak still lets the compiler optimize better.

**The second memory order argument** is for the failure case — must be no stronger than the success ordering. Use `relaxed` for failure when you're retrying anyway.

```cpp
#include <thread>
#include <queue>
#include <functional>
#include <mutex>
#include <condition_variable>
#include <future>
#include <vector>
#include <print>

class ThreadPool {
    std::vector<std::thread> workers_;
    std::queue<std::function<void()>> tasks_;
    std::mutex mu_;
    std::condition_variable cv_;
    bool stop_ = false;

public:
    explicit ThreadPool(std::size_t n) {
        workers_.reserve(n);
        for (std::size_t i = 0; i < n; ++i)
            workers_.emplace_back([this]{ run(); });
    }

    ~ThreadPool() {
        { std::lock_guard lock(mu_); stop_ = true; }
        cv_.notify_all();
        for (auto& w : workers_) w.join();
    }

    template<typename F, typename... Args>
    auto submit(F&& f, Args&&... args)
        -> std::future<std::invoke_result_t<F, Args...>>
    {
        using R = std::invoke_result_t<F, Args...>;
        auto task = std::make_shared<std::packaged_task<R()>>(
            std::bind(std::forward<F>(f), std::forward<Args>(args)...)
        );
        std::future<R> fut = task->get_future();
        {
            std::lock_guard lock(mu_);
            if (stop_) throw std::runtime_error("pool stopped");
            tasks_.emplace([task]{ (*task)(); });
        }
        cv_.notify_one();
        return fut;
    }

private:
    void run() {
        while (true) {
            std::function<void()> task;
            {
                std::unique_lock lock(mu_);
                cv_.wait(lock, [this]{ return stop_ || !tasks_.empty(); });
                if (stop_ && tasks_.empty()) return;
                task = std::move(tasks_.front());
                tasks_.pop();
            }
            task();
        }
    }
};

int main() {
    ThreadPool pool(4);

    std::vector<std::future<int>> futs;
    for (int i = 0; i < 20; ++i)
        futs.push_back(pool.submit([i]{
            std::this_thread::sleep_for(std::chrono::milliseconds(10));
            return i * i;
        }));

    for (auto& f : futs)
        std::println("{}", f.get());
}
```

**Design notes:**
- `packaged_task` wrapped in `shared_ptr` because `std::function` requires copyable callables.
- Drain the queue before stopping (process remaining tasks after `stop_=true`).
- `submit()` returns a typed future — callers can wait and get results or exceptions.
- For production: consider work-stealing, priority queues, and separate IO/CPU pools.

```cpp
#include <stop_token>
#include <thread>
#include <queue>
#include <mutex>
#include <condition_variable>
#include <optional>
#include <print>

template<typename T>
struct Channel {
    std::queue<T> buf;
    std::mutex mu;
    std::condition_variable_any cv; // _any supports stop_token
    bool closed = false;

    bool send(T val) {
        std::lock_guard lock(mu);
        if (closed) return false;
        buf.push(std::move(val));
        cv.notify_one();
        return true;
    }

    std::optional<T> recv(std::stop_token st) {
        std::unique_lock lock(mu);
        cv.wait(lock, st, [this]{ return !buf.empty() || closed; });
        if (buf.empty()) return std::nullopt;
        T v = std::move(buf.front());
        buf.pop();
        return v;
    }

    void close() {
        std::lock_guard lock(mu);
        closed = true;
        cv.notify_all();
    }
};

int main() {
    Channel<int> stage1, stage2;

    std::stop_source ss;

    // Stage 1: produce numbers
    std::jthread producer([&](std::stop_token st) {
        for (int i = 0; !st.stop_requested(); ++i) {
            stage1.send(i);
            std::this_thread::sleep_for(std::chrono::milliseconds(50));
        }
        stage1.close();
    }, ss.get_token()); // jthread auto-passes token if signature matches
    // Note: we pass ss.get_token() explicitly here for the lambda

    // Stage 2: transform
    std::jthread transformer([&](std::stop_token st) {
        while (auto v = stage1.recv(st))
            stage2.send(*v * 2);
        stage2.close();
    });

    // Stage 3: consume
    std::jthread consumer([&](std::stop_token st) {
        while (auto v = stage2.recv(st))
            std::println("Output: {}", *v);
    });

    std::this_thread::sleep_for(std::chrono::milliseconds(300));
    ss.request_stop(); // cascades through all stages via closed channels
}
```

**Key insight:** `condition_variable_any::wait` with a `stop_token` wakes up when either the predicate is true OR stop is requested — eliminating the need for manual stop checks in the wait loop. Cancellation propagates naturally when each stage closes its output channel on stop.

