#include <semaphore>
#include <thread>
#include <vector>
#include <print>
#include <chrono>

// Simulate a pool of 3 DB connections
constexpr int MAX_CONNECTIONS = 3;
std::counting_semaphore<MAX_CONNECTIONS> sem(MAX_CONNECTIONS);

void use_connection(int worker_id) {
    sem.acquire(); // blocks until a slot is available
    {
        std::println("Worker {} acquired connection", worker_id);
        std::this_thread::sleep_for(std::chrono::milliseconds(200));
        std::println("Worker {} releasing connection", worker_id);
    }
    sem.release(); // returns slot to pool
}

// RAII wrapper for semaphore
struct SemaphoreGuard {
    std::counting_semaphore<MAX_CONNECTIONS>& sem;
    explicit SemaphoreGuard(decltype(sem) s) : sem(s) { sem.acquire(); }
    ~SemaphoreGuard() { sem.release(); }
    SemaphoreGuard(const SemaphoreGuard&) = delete;
};

void use_connection_raii(int worker_id) {
    SemaphoreGuard guard(sem);
    std::println("Worker {} using connection", worker_id);
    std::this_thread::sleep_for(std::chrono::milliseconds(200));
}

// try_acquire_for: non-blocking with timeout
bool try_use_connection(int worker_id) {
    if (!sem.try_acquire_for(std::chrono::milliseconds(100))) {
        std::println("Worker {} timed out waiting for connection", worker_id);
        return false;
    }
    std::println("Worker {} got connection", worker_id);
    sem.release();
    return true;
}

int main() {
    std::vector<std::jthread> workers;
    for (int i = 0; i < 10; ++i)
        workers.emplace_back(use_connection_raii, i);
    // Max 3 threads inside the critical section at any time
}
```

**Semaphore vs mutex:**
- Mutex: binary (0 or 1), same thread must lock and unlock.
- `binary_semaphore` (`counting_semaphore<1>`): binary, but any thread can release.
- `counting_semaphore<N>`: N simultaneous holders — ideal for resource pools.

**std::binary_semaphore** is just `std::counting_semaphore<1>` and is more efficient than a mutex when the releaser differs from the acquirer (e.g., signal from interrupt handler to main thread).

```cpp
#include <vector>
#include <stdexcept>
#include <print>
#include <type_traits>

struct ExpensiveToCopy {
    std::vector<int> data;
    explicit ExpensiveToCopy(int n) : data(n) {}

    // WITHOUT noexcept: std::vector uses COPY during reallocation
    // because it can't safely move (an exception mid-move would corrupt the vector)
    ExpensiveToCopy(ExpensiveToCopy&&) = default; // NOT noexcept
};

struct CheapToMove {
    std::vector<int> data;
    explicit CheapToMove(int n) : data(n) {}

    // WITH noexcept: std::vector uses MOVE during reallocation — O(1) per element
    CheapToMove(CheapToMove&&) noexcept = default;
    CheapToMove& operator=(CheapToMove&&) noexcept = default;
};

static_assert(!std::is_nothrow_move_constructible_v<ExpensiveToCopy>);
static_assert( std::is_nothrow_move_constructible_v<CheapToMove>);

// noexcept as a contract: enables compiler optimizations
double fast_sqrt(double x) noexcept {
    // Compiler can omit exception-handling metadata for this function
    // Callers don't need landing pads here
    return __builtin_sqrt(x);
}

// noexcept(expr): conditional noexcept based on contained type
template<typename T>
void swap_safe(T& a, T& b) noexcept(std::is_nothrow_move_constructible_v<T> &&
                                     std::is_nothrow_move_assignable_v<T>) {
    T tmp = std::move(a);
    a = std::move(b);
    b = std::move(tmp);
}

int main() {
    // std::vector reallocation behavior demo
    std::vector<ExpensiveToCopy> v1;
    std::vector<CheapToMove>    v2;

    for (int i = 0; i < 10; ++i) {
        v1.emplace_back(1000); // copies during realloc — O(n) copies total
        v2.emplace_back(1000); // moves during realloc — O(n) moves, O(1) each
    }

    // Violating noexcept contract: calls std::terminate, not stack unwind
    // Never throw from a noexcept function!
}
```

**Rules of thumb:**
- Always mark move constructors/operators `noexcept` — critical for STL container efficiency.
- Mark destructors `noexcept` (they are implicitly, but be explicit in templates).
- Mark leaf functions that truly can't fail (simple getters, math ops) `noexcept`.
- If a noexcept function throws, `std::terminate()` is called — no recovery, no unwinding.

