    try {
        std::rethrow_if_nested(e);
    } catch (const std::exception& inner) {
        print_exception_chain(inner, depth + 1);
    }
}

int main() {
    try {
        middle_layer();
    } catch (const AppError& e) {
        std::println("Caught at {}:{}", e.where().file_name(), e.where().line());
