use tokio::net::UdpSocket;
use std::io;

/// Simple binary protocol:
/// Request:  [u8 op] [u32 a] [u32 b]  (9 bytes, big-endian)
/// Response: [u32 result]              (4 bytes, big-endian)
/// ops: 0=add, 1=sub, 2=mul

fn parse_request(buf: &[u8]) -> Option<(u8, u32, u32)> {
    if buf.len() < 9 { return None; }
    let op = buf[0];
    let a = u32::from_be_bytes(buf[1..5].try_into().ok()?);
    let b = u32::from_be_bytes(buf[5..9].try_into().ok()?);
    Some((op, a, b))
}

fn compute(op: u8, a: u32, b: u32) -> Option<u32> {
    match op {
        0 => a.checked_add(b),
        1 => a.checked_sub(b),
        2 => a.checked_mul(b),
        _ => None,
    }
}

#[tokio::main]
async fn main() -> io::Result<()> {
    // UdpSocket is wrapped by Tokio for non-blocking operation
    let socket = UdpSocket::bind("127.0.0.1:9000").await?;
    println!("UDP calc server on port 9000");

    let mut buf = [0u8; 1024];

    loop {
        // recv_from yields (bytes_read, sender_addr)
        let (n, peer) = socket.recv_from(&mut buf).await?;

        match parse_request(&buf[..n]) {
            Some((op, a, b)) => match compute(op, a, b) {
                Some(result) => {
                    let response = result.to_be_bytes();
                    socket.send_to(&response, peer).await?;
                }
                None => {
                    eprintln!("Overflow or unknown op from {peer}");
                }
            },
            None => {
                eprintln!("Malformed datagram from {peer} ({n} bytes)");
            }
        }
    }
}

// Client example (for testing):
// async fn send_request(socket: &UdpSocket, op: u8, a: u32, b: u32) -> u32 {
//     let mut req = [0u8; 9];
//     req[0] = op;
