use tokio::sync::{mpsc, Semaphore};
use tokio::time::{interval, Duration};
use std::sync::Arc;

/// Token-bucket rate limiter: allows `rate` permits per second.
/// Shared across any number of async tasks via Arc.
struct RateLimiter {
    semaphore: Arc<Semaphore>,
}

impl RateLimiter {
    fn new(rate: usize) -> Self {
        let semaphore = Arc::new(Semaphore::new(0));
        let sem_clone = semaphore.clone();

        // Background task: adds `rate` permits every second
        tokio::spawn(async move {
            let mut ticker = interval(Duration::from_secs(1));
            loop {
                ticker.tick().await;
                // add_permits won't exceed usize::MAX, safe to call repeatedly
                sem_clone.add_permits(rate);
            }
        });

        Self { semaphore }
    }

    async fn acquire(&self) {
        // Blocks until a permit is available
        self.semaphore
            .acquire()
            .await
            .expect("rate limiter semaphore closed")
            .forget(); // release ownership — permits are re-added by the ticker
    }
}

async fn producer(id: u64, limiter: Arc<RateLimiter>, tx: mpsc::Sender<String>) {
    for i in 0..5 {
        limiter.acquire().await;
        let msg = format!("producer-{id} item-{i}");
        println!("[{:.3?}] {msg}", std::time::Instant::now());
        tx.send(msg).await.unwrap();
    }
}

#[tokio::main]
async fn main() {
    let limiter = Arc::new(RateLimiter::new(3)); // 3 ops/sec globally
    let (tx, mut rx) = mpsc::channel(100);

    for id in 0..4 {
        tokio::spawn(producer(id, limiter.clone(), tx.clone()));
    }
    drop(tx);

    while let Some(msg) = rx.recv().await {
        let _ = msg;
    }
    println!("All done");
}
```

**Why `forget()`?** `SemaphorePermit` is an RAII guard that returns the permit on drop. We call `forget()` to suppress that — permits are budget tokens re-added by the ticker, not individual resources to return.

```rust
use tokio::sync::{Mutex, Semaphore};
use std::sync::Arc;
use std::collections::VecDeque;

/// A mock database connection
struct Connection {
    id: u64,
}

impl Connection {
    async fn new(id: u64) -> Self {
        // Simulate connection setup latency
        tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;
        println!("Created connection {id}");
        Self { id }
    }

    async fn query(&self, sql: &str) -> String {
        format!("[conn {}] result of `{}`", self.id, sql)
    }
}

struct Pool {
    connections: Mutex<VecDeque<Connection>>,
    semaphore: Semaphore,
    max_size: u64,
    next_id: Mutex<u64>,
}

impl Pool {
    fn new(max_size: u64) -> Arc<Self> {
        Arc::new(Self {
            connections: Mutex::new(VecDeque::new()),
            semaphore: Semaphore::new(max_size as usize),
            max_size,
            next_id: Mutex::new(0),
        })
    }

    async fn get(&self) -> PooledConn<'_> {
        // Acquire permit first — blocks if pool is exhausted
        let permit = self.semaphore.acquire().await.unwrap();

        let conn = {
            let mut queue = self.connections.lock().await;
            queue.pop_front()
        };

        let conn = match conn {
            Some(c) => c,
            None => {
                let mut id = self.next_id.lock().await;
                let c = Connection::new(*id).await;
                *id += 1;
                c
            }
        };

        PooledConn {
            conn: Some(conn),
            pool: self,
            _permit: permit,
        }
    }

    fn recycle(&self, conn: Connection) {
        if let Ok(mut queue) = self.connections.try_lock() {
            queue.push_back(conn);
        }
        // If lock fails, connection is simply dropped (acceptable)
    }
}

/// RAII guard that returns the connection when dropped
struct PooledConn<'a> {
    conn: Option<Connection>,
    pool: &'a Pool,
    _permit: tokio::sync::SemaphorePermit<'a>,
}

impl<'a> PooledConn<'a> {
    async fn query(&self, sql: &str) -> String {
        self.conn.as_ref().unwrap().query(sql).await
    }
}

impl<'a> Drop for PooledConn<'a> {
    fn drop(&mut self) {
        if let Some(conn) = self.conn.take() {
            self.pool.recycle(conn);
        }
        // _permit is dropped here, releasing the semaphore slot
    }
}

#[tokio::main]
async fn main() {
    let pool = Pool::new(3);

    let mut tasks = Vec::new();
    for i in 0..8 {
        let p = pool.clone();
        tasks.push(tokio::spawn(async move {
            let conn = p.get().await;
            let result = conn.query(&format!("SELECT {i}")).await;
            println!("{result}");
        }));
    }
    for t in tasks { t.await.unwrap(); }
}
```

