use std::alloc::{alloc, dealloc, Layout};
use std::cell::Cell;
use std::marker::PhantomData;

/// Bump allocator: allocates memory linearly, frees everything at once.
/// Lifetime 'a ties allocated values to the arena.
pub struct Arena {
    start: *mut u8,
    capacity: usize,
    offset: Cell<usize>,
}

impl Arena {
    pub fn new(capacity: usize) -> Self {
        // SAFETY: capacity > 0, Layout::array::<u8> never fails for sane sizes
        let layout = Layout::array::<u8>(capacity).unwrap();
        let start = unsafe { alloc(layout) };
        assert!(!start.is_null(), "allocation failed");
        Arena { start, capacity, offset: Cell::new(0) }
    }

    /// Allocate a value in the arena. Returns a reference with lifetime
    /// tied to the arena, so it cannot outlive the arena.
    pub fn alloc<T>(&self, value: T) -> &T {
        let layout = Layout::new::<T>();
        let current = self.offset.get();

        // Align upward
        let align = layout.align();
        let aligned = (current + align - 1) & !(align - 1);
        let next = aligned + layout.size();

        assert!(next <= self.capacity, "arena out of memory");
        self.offset.set(next);

        // SAFETY:
        // 1. `aligned` is within our allocated block (checked above).
        // 2. The pointer is properly aligned for T (we computed alignment).
        // 3. We write a valid T, then return an immutable reference.
        // 4. No other &T to this location exists (bump pointer never revisits).
        // 5. The reference lifetime 'a borrows from &self — it cannot outlive the Arena.
        unsafe {
            let ptr = self.start.add(aligned) as *mut T;
            ptr.write(value);
            &*ptr
        }
    }

    pub fn alloc_slice<T: Copy>(&self, items: &[T]) -> &[T] {
        let layout = Layout::array::<T>(items.len()).unwrap();
        let current = self.offset.get();
        let align = layout.align();
        let aligned = (current + align - 1) & !(align - 1);
        let next = aligned + layout.size();
        assert!(next <= self.capacity, "arena out of memory");
        self.offset.set(next);

        unsafe {
            let ptr = self.start.add(aligned) as *mut T;
            std::ptr::copy_nonoverlapping(items.as_ptr(), ptr, items.len());
            std::slice::from_raw_parts(ptr, items.len())
        }
    }
}

impl Drop for Arena {
    fn drop(&mut self) {
        // SAFETY: start was allocated with this exact layout in new()
        let layout = Layout::array::<u8>(self.capacity).unwrap();
        unsafe { dealloc(self.start, layout) };
    }
}

// Arena is NOT Send because the raw pointer isn't proven to be uniquely owned
// across threads. Mark explicitly:
unsafe impl Send for Arena {}
// NOT Sync — multiple threads calling alloc() would race on offset

fn main() {
    let arena = Arena::new(4096);

    let a: &u64 = arena.alloc(42u64);
    let b: &String = arena.alloc("hello".to_string());
    let c: &[u8] = arena.alloc_slice(&[1, 2, 3, 4]);

    println!("{a} {b} {c:?}");
    // All references valid here — arena still alive
    // After this scope, Arena::drop() frees the block
}
```

**Soundness invariants maintained:**
1. Bump pointer never revisits memory — no aliased `&mut`.
2. Returned `&T` lifetime tied to `&self` — cannot outlive the arena.
3. Proper alignment computed before every allocation.
4. Deallocated with the exact same `Layout` used for allocation.

```rust
// Suppose the C library exposes:
//   typedef void (*callback_t)(int event_code, void *user_data);
//   void register_callback(callback_t cb, void *user_data);
//   void trigger_event(int code);

use std::ffi::c_void;
use std::panic;

// --- Extern declarations ---
extern "C" {
    fn register_callback(
        cb: unsafe extern "C" fn(event_code: i32, user_data: *mut c_void),
        user_data: *mut c_void,
    );
    fn trigger_event(code: i32);
}

// --- Safe trampoline ---
// The trampoline converts the C ABI call into a Rust closure call.
// SAFETY requirements:
// 1. user_data must point to a valid Box<F> that outlives any calls.
// 2. The callback must not be called after Box<F> is freed.
// 3. F must not panic across the FFI boundary (panic = UB in extern "C").
unsafe extern "C" fn trampoline<F>(event_code: i32, user_data: *mut c_void)
where
    F: Fn(i32) + 'static,
{
    // Catch panics — never allow unwinding across FFI boundary
    let _ = panic::catch_unwind(|| {
        // Reconstruct reference to the closure WITHOUT taking ownership
        let cb = &*(user_data as *const F);
        cb(event_code);
    });
}

/// RAII guard: registers the callback and unregisters on drop.
/// Keeps the closure alive for as long as the guard exists.
struct EventGuard<F: Fn(i32) + 'static> {
    // Box keeps F at a stable heap address for the C library
    handler: Box<F>,
}

impl<F: Fn(i32) + 'static> EventGuard<F> {
    pub fn new(handler: F) -> Self {
        let mut guard = EventGuard { handler: Box::new(handler) };

        // SAFETY: handler is heap-allocated and will live as long as guard.
        // We pass a raw pointer to the Box's contents — stable address.
        let user_data = &*guard.handler as *const F as *mut c_void;
        unsafe {
            register_callback(trampoline::<F>, user_data);
        }
        guard
    }
}

impl<F: Fn(i32) + 'static> Drop for EventGuard<F> {
    fn drop(&mut self) {
        // In a real library you'd call unregister_callback here
        // to prevent the C side from calling a freed closure.
        println!("[EventGuard] unregistering callback");
    }
}

fn main() {
    let shared_count = std::sync::Arc::new(std::sync::atomic::AtomicU64::new(0));
    let count = shared_count.clone();

    let _guard = EventGuard::new(move |code| {
        count.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        println!("Event received: {code}");
    });

    unsafe { trigger_event(42); }
    println!("Total events: {}", shared_count.load(std::sync::atomic::Ordering::Relaxed));
    // _guard drops here, unregistering the callback
}
```

**Critical FFI safety rules:**
1. Never allow a Rust panic to cross `extern "C"` — wrap with `catch_unwind`.
2. Raw pointers passed to C must remain valid for the entire call duration.
3. The closure/object must live at a stable address (heap via `Box`, never stack).

```rust
// `unsafe trait` means: the compiler cannot verify the safety invariant.
// Only the human programmer can — and they must promise it holds
// by writing `unsafe impl`.

/// A marker trait: types that can safely be transferred to another thread.
/// Equivalent to std::marker::Send (but our own, for illustration).
///
/// # Safety
/// Implementing this trait asserts that moving a value of type T to a
/// different thread cannot cause data races or undefined behaviour.
/// Specifically:
/// - All internal data is either owned exclusively or protected by a
///   synchronisation primitive.
/// - No raw pointers alias mutable data reachable from another thread.
/// - Drop implementations do not access thread-local storage.
pub unsafe trait ThreadSafe {}

// Safe to implement — i32 has no shared mutable state
unsafe impl ThreadSafe for i32 {}
unsafe impl ThreadSafe for String {}
unsafe impl<T: ThreadSafe> ThreadSafe for Vec<T> {}

// NOT safe to implement for Rc<T> — Rc uses a non-atomic refcount
// that would race if two threads decremented it simultaneously.
use std::rc::Rc;
// unsafe impl<T> ThreadSafe for Rc<T> {}  // DON'T — data race on refcount

// --- A type that is safe to send but only because of internal synchronisation ---
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;

struct AtomicCounter(AtomicUsize);

// SAFETY: AtomicUsize uses CPU-level atomic ops — safe to access from multiple
// threads simultaneously. No non-atomic mutable state exists.
unsafe impl ThreadSafe for AtomicCounter {}

// --- Demonstrating the contract matters ---

// A deliberately unsafe type: raw pointer with no synchronisation
struct UnsafeShared(*mut u64);

// We COULD write this, but it would be UNSOUND:
// unsafe impl ThreadSafe for UnsafeShared {}
// Because: two threads could both dereference and mutate *mut u64 simultaneously.

// --- Using our trait in a generic bound ---
fn spawn_on_thread<T: ThreadSafe + 'static>(value: T, f: impl FnOnce(T) + Send + 'static) {
    std::thread::spawn(move || f(value)).join().unwrap();
}

fn main() {
    spawn_on_thread(42i32, |n| println!("Got {n} on another thread"));

    let counter = Arc::new(AtomicCounter(AtomicUsize::new(0)));
    // AtomicCounter is ThreadSafe, so Arc<AtomicCounter> is too
    // (Arc<T>: Send when T: Send + Sync, analog holds for our trait)
    println!("count: {}", counter.0.load(Ordering::Relaxed));
}
```

**Pattern:** `unsafe trait` shifts the proof burden from the compiler to the programmer. The `unsafe impl` is the programmer's written promise that the contract holds. This is how `std::marker::Send` and `Sync` work in the standard library.

```rust
use std::alloc::{alloc, dealloc, Layout};
use std::ptr;

/// Manually-managed array of T using raw pointers.
struct RawArray<T> {
    ptr: *mut T,
    len: usize,
    capacity: usize,
}

impl<T> RawArray<T> {
    fn new(capacity: usize) -> Self {
        assert!(capacity > 0 && std::mem::size_of::<T>() > 0);
        let layout = Layout::array::<T>(capacity).unwrap();
        // SAFETY: layout has non-zero size (capacity > 0, size_of::<T>() > 0)
        let ptr = unsafe { alloc(layout) as *mut T };
        assert!(!ptr.is_null(), "allocation failed");
        RawArray { ptr, len: 0, capacity }
    }

    fn push(&mut self, value: T) {
        assert!(self.len < self.capacity, "array is full");
        // SAFETY:
        // - ptr.add(len) is within the allocated block (checked above).
        // - The location is uninitialized — write() does NOT drop the old value.
        // - After write(), the slot is considered initialized.
        unsafe { ptr::write(self.ptr.add(self.len), value) };
        self.len += 1;
    }

    fn get(&self, idx: usize) -> Option<&T> {
        if idx >= self.len { return None; }
        // SAFETY: idx < len, so ptr.add(idx) points to an initialized T.
        // The returned reference borrows from self (&self lifetime).
        Some(unsafe { &*self.ptr.add(idx) })
    }

    fn pop(&mut self) -> Option<T> {
        if self.len == 0 { return None; }
        self.len -= 1;
        // SAFETY: ptr.add(len) was initialized by push().
        // read() copies the bytes out; the slot is now logically uninitialized.
        Some(unsafe { ptr::read(self.ptr.add(self.len)) })
    }
}

impl<T> Drop for RawArray<T> {
    fn drop(&mut self) {
        // Drop all initialized elements
        for i in 0..self.len {
            // SAFETY: each slot 0..len was initialized
            unsafe { ptr::drop_in_place(self.ptr.add(i)) };
        }
        let layout = Layout::array::<T>(self.capacity).unwrap();
        // SAFETY: ptr was allocated with this exact layout
        unsafe { dealloc(self.ptr as *mut u8, layout) };
    }
}

fn main() {
    let mut arr: RawArray<String> = RawArray::new(4);
    arr.push("alpha".to_string());
    arr.push("beta".to_string());
    arr.push("gamma".to_string());

    println!("{:?}", arr.get(1)); // Some("beta")
    let popped = arr.pop();
    println!("{:?}", popped);     // Some("gamma")
    println!("{:?}", arr.get(1)); // Some("beta")
    // Drop runs here: remaining Strings are freed, then block is deallocated
}
```

**Key rules:**
- `ptr::write(p, v)` — initializes without reading the old value (no drop).
- `ptr::read(p)` — bitwise copies out; the slot becomes logically uninit.
- `ptr::drop_in_place(p)` — runs the destructor without freeing memory.
- `ptr.add(n)` — pointer arithmetic in units of `T`, like C's `p + n`; requires `n * size_of::<T>()` bytes to be in-bounds.

