use serde::{Deserialize, Deserializer, Serialize, Serializer, de};
use std::fmt;
use std::str::FromStr;

#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
pub struct Version {
    pub major: u32,
    pub minor: u32,
    pub patch: u32,
}

impl fmt::Display for Version {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}.{}.{}", self.major, self.minor, self.patch)
    }
}

#[derive(Debug)]
pub struct ParseVersionError(String);

impl fmt::Display for ParseVersionError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "invalid version `{}`", self.0)
    }
}

impl FromStr for Version {
    type Err = ParseVersionError;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        let parts: Vec<&str> = s.split('.').collect();
        if parts.len() != 3 {
            return Err(ParseVersionError(s.to_string()));
        }
        let parse = |p: &str| p.parse::<u32>()
            .map_err(|_| ParseVersionError(s.to_string()));
        Ok(Version {
            major: parse(parts[0])?,
            minor: parse(parts[1])?,
            patch: parse(parts[2])?,
        })
    }
}

// Serialize as a string: {"version": "1.2.3"}
impl Serialize for Version {
    fn serialize<S: Serializer>(&self, s: S) -> Result<S::Ok, S::Error> {
        s.serialize_str(&self.to_string())
    }
}

// Deserialize from a string
struct VersionVisitor;

impl<'de> de::Visitor<'de> for VersionVisitor {
    type Value = Version;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("a semver string like \"1.2.3\"")
    }

    fn visit_str<E: de::Error>(self, v: &str) -> Result<Self::Value, E> {
        v.parse::<Version>().map_err(|e| E::custom(e.to_string()))
    }
}

impl<'de> Deserialize<'de> for Version {
    fn deserialize<D: Deserializer<'de>>(d: D) -> Result<Self, D::Error> {
        d.deserialize_str(VersionVisitor)
    }
}

// --- Usage ---
#[derive(Debug, Serialize, Deserialize)]
struct Package {
    name: String,
    version: Version,
}

fn main() {
    let pkg = Package {
        name: "mylib".to_string(),
        version: Version { major: 1, minor: 2, patch: 3 },
    };

    let json = serde_json::to_string_pretty(&pkg).unwrap();
    println!("{json}");
    // {
    //   "name": "mylib",
    //   "version": "1.2.3"
    // }

    let pkg2: Package = serde_json::from_str(&json).unwrap();
    assert_eq!(pkg.version, pkg2.version);
    println!("{:?}", pkg2);
}
```

**Visitor pattern:** `Visitor` is the idiom for custom deserialization. `expecting()` provides the error message; each `visit_*` method handles an input token type. Use `deserialize_str` to hint to the deserializer that you want a string.

