use serde::{Deserialize, Serialize};

#[derive(Debug, Serialize, Deserialize)]
pub struct ServerConfig {
    /// Renamed: JSON uses "host", Rust uses `address`
    #[serde(rename = "host")]
    pub address: String,

    pub port: u16,

    /// Skipped entirely in both serialize and deserialize
    #[serde(skip)]
    pub _internal_socket_fd: i32,

    /// Only skipped during serialization (still deserializable)
    #[serde(skip_serializing)]
    pub admin_password: String,

    /// Skip serializing if the value equals the default
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tls_cert_path: Option<String>,

    /// Use a default value when the field is absent in the input
    #[serde(default = "default_max_connections")]
    pub max_connections: u32,

    /// Use Default::default() when absent
    #[serde(default)]
    pub debug_mode: bool,

    /// Custom deserializer for a specific field only
    #[serde(deserialize_with = "deserialize_duration_secs")]
    #[serde(serialize_with = "serialize_duration_secs")]
    pub timeout_secs: std::time::Duration,
}

fn default_max_connections() -> u32 { 100 }

fn deserialize_duration_secs<'de, D>(
    d: D,
) -> Result<std::time::Duration, D::Error>
where D: serde::Deserializer<'de> {
    let secs = u64::deserialize(d)?;
    Ok(std::time::Duration::from_secs(secs))
}

fn serialize_duration_secs<S>(
    duration: &std::time::Duration,
    s: S,
) -> Result<S::Ok, S::Error>
where S: serde::Serializer {
    s.serialize_u64(duration.as_secs())
}

fn main() {
    let json = r#"
    {
        "host": "0.0.0.0",
        "port": 8080,
        "admin_password": "secret",
        "timeout_secs": 30
    }
    "#;

    let config: ServerConfig = serde_json::from_str(json).unwrap();
    println!("{:#?}", config);
    // max_connections = 100 (from default)
    // debug_mode = false (from Default)
    // _internal_socket_fd = 0 (from Default, since skip)
    // tls_cert_path = None

    let serialized = serde_json::to_string_pretty(&config).unwrap();
    println!("{serialized}");
    // "host" appears (renamed)
    // admin_password does NOT appear (skip_serializing)
    // tls_cert_path does NOT appear (skip_serializing_if = is_none)
    // _internal_socket_fd does NOT appear (skip)
    // timeout_secs appears as a number (custom serializer)
}
