use serde::Deserialize;

/// All string fields borrow from the input JSON bytes.
/// The lifetime 'de ties every &str to the deserializer's input buffer.
/// No allocation for strings — zero copies.
#[derive(Debug, Deserialize)]
struct LogEntry<'de> {
    /// &str borrows directly from the JSON input
    level: &'de str,
    message: &'de str,
    /// Option<&str> works too — None if the field is absent or null
    #[serde(borrow)]
    request_id: Option<&'de str>,
    /// Numeric fields are always copied (no allocation needed anyway)
    timestamp: u64,
    /// Nested struct also borrows
    context: Context<'de>,
}

#[derive(Debug, Deserialize)]
struct Context<'de> {
    #[serde(borrow)]
    service: &'de str,
    #[serde(borrow)]
    host: &'de str,
}

fn parse_log_entry(json: &str) -> LogEntry<'_> {
    // serde_json::from_str deserializes with lifetime tied to the &str input
    serde_json::from_str(json).expect("invalid log entry")
}

fn main() {
    let json = r#"{
        "level": "ERROR",
        "message": "connection refused",
        "request_id": "abc-123",
        "timestamp": 1700000000,
        "context": {
            "service": "api-gateway",
            "host": "prod-1"
        }
    }"#;

    let entry = parse_log_entry(json);
    println!("{:#?}", entry);

    // entry.level is a slice into `json` — no String allocated
    assert!(std::ptr::eq(
        entry.level.as_ptr(),
        json.find("ERROR").map(|i| json[i..].as_ptr()).unwrap()
    ));
    println!("Zero copies confirmed: entry.level points into original buffer");

    // Useful for high-throughput log parsers where you process millions
    // of entries per second — avoiding allocations is critical.
}
```

**When zero-copy works:**
- Input must be a `&str` or `&[u8]` slice — not a stream or `Read` impl.
- The output struct cannot outlive the input buffer.
- Escaped strings in JSON (e.g., `\n`, `\u0041`) require an owned `String` — serde will return an error or fall back to allocation.

**The `#[serde(borrow)]` attribute** tells the derive macro to use `deserialize_with` that explicitly requests borrowing from the input, required for `Option<&str>` and other wrapper types.

```rust
use serde::{Deserialize, Deserializer, de};
use std::fmt;

/// Deserializes a string like "1 2 3 4" into a Vec<i64>.
fn deserialize_space_separated<'de, D>(deserializer: D) -> Result<Vec<i64>, D::Error>
where
    D: Deserializer<'de>,
{
    struct SpaceSepVisitor;

    impl<'de> de::Visitor<'de> for SpaceSepVisitor {
        type Value = Vec<i64>;

        fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
            f.write_str("a space-separated list of integers")
        }

        fn visit_str<E: de::Error>(self, v: &str) -> Result<Vec<i64>, E> {
            if v.trim().is_empty() {
                return Ok(Vec::new());
            }
            v.split_whitespace()
                .map(|s| s.parse::<i64>().map_err(|e| {
                    E::invalid_value(
                        de::Unexpected::Str(s),
                        &"an integer",
                    )
                }))
                .collect()
        }

        // Also handle JSON arrays natively (format flexibility)
        fn visit_seq<A: de::SeqAccess<'de>>(self, mut seq: A) -> Result<Vec<i64>, A::Error> {
            let mut out = Vec::new();
            while let Some(n) = seq.next_element::<i64>()? {
                out.push(n);
            }
            Ok(out)
        }
    }

    // deserialize_any lets the deserializer decide whether to call visit_str or visit_seq
    deserializer.deserialize_any(SpaceSepVisitor)
}

#[derive(Debug, Deserialize)]
struct Query {
    name: String,
    #[serde(deserialize_with = "deserialize_space_separated")]
    ids: Vec<i64>,
    #[serde(deserialize_with = "deserialize_space_separated", default)]
    tags: Vec<i64>,
}

fn main() {
    // String form
    let json1 = r#"{"name": "search", "ids": "10 20 30 40"  }"#;
    let q1: Query = serde_json::from_str(json1).unwrap();
    println!("{q1:#?}");

    // Array form (same deserializer handles it)
    let json2 = r#"{"name": "search", "ids": [10, 20, 30], "tags": "1 2"}"#;
    let q2: Query = serde_json::from_str(json2).unwrap();
    println!("{q2:#?}");

    // Missing optional field
    let json3 = r#"{"name": "empty", "ids": ""}"#;
    let q3: Query = serde_json::from_str(json3).unwrap();
    println!("{q3:#?}"); // ids: []
}
```

**Design choices:**
- `visit_str` handles the string format; `visit_seq` handles native JSON arrays.
- `deserialize_any` lets the format choose which `visit_*` to call, making the deserializer format-agnostic.
- `E::invalid_value` with `Unexpected::Str` gives precise error messages pointing to the bad token.

```rust
use serde::{
    Serialize, Serializer,
    ser::SerializeMap,
    Deserialize,
};
use serde_json::Value;
use std::collections::HashMap;

/// A HashMap that serializes with alphabetically sorted keys.
/// Useful for deterministic JSON output (test snapshots, hashes, etc.)
#[derive(Debug, Clone, Deserialize)]
#[serde(transparent)]
pub struct SortedMap(pub HashMap<String, Value>);

impl Serialize for SortedMap {
    fn serialize<S: Serializer>(&self, serializer: S) -> Result<S::Ok, S::Error> {
        // Collect and sort keys
        let mut pairs: Vec<(&String, &Value)> = self.0.iter().collect();
        pairs.sort_by_key(|(k, _)| k.as_str());

        let mut map = serializer.serialize_map(Some(pairs.len()))?;
        for (k, v) in pairs {
            map.serialize_entry(k, v)?;
        }
        map.end()
    }
}

impl SortedMap {
    pub fn new() -> Self { Self(HashMap::new()) }
    pub fn insert(&mut self, k: impl Into<String>, v: impl Into<Value>) {
        self.0.insert(k.into(), v.into());
    }
}

/// Recursively sort all object keys in a serde_json Value
pub fn sort_value_keys(v: Value) -> Value {
    match v {
        Value::Object(map) => {
            let mut pairs: Vec<(String, Value)> = map.into_iter()
                .map(|(k, v)| (k, sort_value_keys(v)))
                .collect();
            pairs.sort_by(|a, b| a.0.cmp(&b.0));
            Value::Object(pairs.into_iter().collect())
        }
        Value::Array(arr) => {
            Value::Array(arr.into_iter().map(sort_value_keys).collect())
        }
        other => other,
    }
}

fn main() {
    let mut map = SortedMap::new();
    map.insert("zebra", Value::Bool(true));
    map.insert("alpha", Value::Number(42.into()));
    map.insert("middle", Value::String("hello".to_string()));

    let json = serde_json::to_string_pretty(&map).unwrap();
    println!("{json}");
    // Keys always appear: alpha, middle, zebra

    // Round-trip preserves the map
    let decoded: SortedMap = serde_json::from_str(&json).unwrap();
    let json2 = serde_json::to_string_pretty(&decoded).unwrap();
    assert_eq!(json, json2, "output must be identical on re-serialization");
    println!("Round-trip OK");
}
```

**`SerializeMap` protocol:**
1. Call `serialize_map(Some(len))` — length hint optimises some formats (e.g., MessagePack).
2. Call `serialize_entry(k, v)` for each pair (or `serialize_key` + `serialize_value` separately).
3. Call `end()` — required or the output will be malformed.

`#[serde(transparent)]` on the struct makes deserialization see through the newtype wrapper automatically.

