#[derive(Debug)]
struct Node<T> {
    value: T,
    left: Option<Box<Node<T>>>,
    right: Option<Box<Node<T>>>,
}

impl<T> Node<T> {
    fn new(value: T) -> Box<Self> {
        Box::new(Node { value, left: None, right: None })
    }
}

// ---- In-order iterator (left -> root -> right) ----
// Uses an explicit stack to simulate recursion without stack overflow risk.
struct InOrder<'a, T> {
    stack: Vec<&'a Node<T>>,
    current: Option<&'a Node<T>>,
}

impl<'a, T> InOrder<'a, T> {
    fn new(root: Option<&'a Box<Node<T>>>) -> Self {
        InOrder {
            stack: Vec::new(),
            current: root.map(|n| n.as_ref()),
        }
    }
}

impl<'a, T> Iterator for InOrder<'a, T> {
    type Item = &'a T;

    fn next(&mut self) -> Option<Self::Item> {
        loop {
            if let Some(node) = self.current.take() {
                // Go left as far as possible, pushing nodes
                self.stack.push(node);
                self.current = node.left.as_ref().map(|n| n.as_ref());
            } else {
                // Backtrack to last pushed node
                let node = self.stack.pop()?;
                self.current = node.right.as_ref().map(|n| n.as_ref());
                return Some(&node.value);
            }
        }
    }
}

// ---- Pre-order DFS iterator (root -> left -> right) ----
struct PreOrder<'a, T> {
    stack: Vec<&'a Node<T>>,
}

impl<'a, T> PreOrder<'a, T> {
    fn new(root: Option<&'a Box<Node<T>>>) -> Self {
        PreOrder {
            stack: root.map(|n| vec![n.as_ref()]).unwrap_or_default(),
        }
    }
}

impl<'a, T> Iterator for PreOrder<'a, T> {
    type Item = &'a T;

    fn next(&mut self) -> Option<Self::Item> {
        let node = self.stack.pop()?;
        // Push right first so left is processed first
        if let Some(right) = &node.right { self.stack.push(right); }
        if let Some(left) = &node.left  { self.stack.push(left); }
        Some(&node.value)
    }
}

fn main() {
    //       4
    //      / \
    //     2   6
    //    / \ / \
    //   1  3 5  7
    let mut root = Node::new(4);
    root.left = Some(Node::new(2));
    root.right = Some(Node::new(6));
    root.left.as_mut().unwrap().left = Some(Node::new(1));
    root.left.as_mut().unwrap().right = Some(Node::new(3));
    root.right.as_mut().unwrap().left = Some(Node::new(5));
    root.right.as_mut().unwrap().right = Some(Node::new(7));

    let in_order: Vec<_> = InOrder::new(Some(&root)).collect();
    println!("In-order:  {:?}", in_order); // [1, 2, 3, 4, 5, 6, 7]

    let pre_order: Vec<_> = PreOrder::new(Some(&root)).collect();
    println!("Pre-order: {:?}", pre_order); // [4, 2, 1, 3, 6, 5, 7]
}
