/// Generates a builder struct and setter methods for a given struct.
/// Usage: builder!(StructName, field1: Type1, field2: Type2, ...)
macro_rules! builder {
    (
        $name:ident,
        $( $field:ident : $ty:ty ),+ $(,)?
    ) => {
        // The actual struct (all fields required after building)
        #[derive(Debug)]
        struct $name {
            $( pub $field: $ty, )+
        }

        // The builder struct (all fields optional)
        paste::paste! {
            #[derive(Default, Debug)]
            struct [< $name Builder >] {
                $( $field: Option<$ty>, )+
            }

            impl [< $name Builder >] {
                pub fn new() -> Self {
                    Self::default()
                }

                // Generate one setter per field
                $(
                pub fn $field(mut self, value: $ty) -> Self {
                    self.$field = Some(value);
                    self
                }
                )+

                pub fn build(self) -> Result<$name, String> {
                    Ok($name {
                        $(
                        $field: self.$field.ok_or_else(|| {
                            format!("field `{}` was not set", stringify!($field))
                        })?,
                        )+
                    })
                }
            }

            impl $name {
                pub fn builder() -> [< $name Builder >] {
                    [< $name Builder >]::new()
                }
            }
        }
    };
}

// Without paste crate, use a simpler naming convention:
macro_rules! simple_builder {
    ( $name:ident { $( $field:ident : $ty:ty ),+ $(,)? } ) => {
        #[derive(Debug)]
        pub struct $name { $( pub $field: $ty, )+ }

        #[derive(Debug, Default)]
        pub struct Builder { $( $field: Option<$ty>, )+ }

        impl Builder {
            $( pub fn $field(mut self, v: $ty) -> Self {
                self.$field = Some(v); self
            } )+

            pub fn build(self) -> $name {
                $name {
                    $( $field: self.$field.unwrap_or_else(||
                        panic!("field {} missing", stringify!($field))
                    ), )+
                }
            }
        }
    };
}

// Practical demo without the paste crate dependency:
macro_rules! make_builder {
    ($name:ident, $builder:ident { $($f:ident : $t:ty = $default:expr),+ $(,)? }) => {
        #[derive(Debug)] pub struct $name { $(pub $f: $t,)+ }

        #[derive(Debug)] pub struct $builder { $($f: $t,)+ }

        impl $builder {
            pub fn new() -> Self { $builder { $($f: $default,)+ } }
            $(pub fn $f(mut self, v: $t) -> Self { self.$f = v; self })+
            pub fn build(self) -> $name { $name { $($f: self.$f,)+ } }
        }
    };
}

make_builder!(HttpRequest, HttpRequestBuilder {
    url: String = String::new(),
    method: String = "GET".to_string(),
    timeout_ms: u64 = 5000,
    follow_redirects: bool = true
});

fn main() {
    let req = HttpRequestBuilder::new()
        .url("https://example.com".to_string())
        .method("POST".to_string())
        .timeout_ms(10_000)
        .follow_redirects(false)
        .build();

    println!("{req:#?}");
}
```

**`macro_rules!` meta-variables used:** `$name:ident` (identifier), `$ty:ty` (type expression), `$f:expr` (expression). The `$(...)+` repetition generates one instance per field.

