use std::collections::HashMap;
use std::hash::{Hash, Hasher};

/// An interned string ID — cheap to copy, compare, and hash.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct Sym(u32);

/// String interner: stores each unique string once.
/// All allocated strings live for the lifetime of the Interner.
pub struct Interner {
    // Maps string content to its symbol ID
    // The key borrows from the `strings` storage below
    map: HashMap<&'static str, Sym>,
    // Owns all string data; never reallocates existing strings
    strings: Vec<Box<str>>,
}

impl Interner {
    pub fn new() -> Self {
        Interner {
            map: HashMap::new(),
            strings: Vec::new(),
        }
    }

    /// Intern a string, returning its stable Sym ID.
    /// Subsequent calls with equal content return the same Sym.
    pub fn intern(&mut self, s: &str) -> Sym {
        if let Some(&sym) = self.map.get(s) {
            return sym;
        }

        let id = Sym(self.strings.len() as u32);
        let owned: Box<str> = s.into();

        // SAFETY: We extend the lifetime of the reference to 'static.
        // This is sound because:
        // 1. The Box<str> lives in `self.strings` for the lifetime of the Interner.
        // 2. We never remove entries from `strings`.
        // 3. Box<str> is heap-allocated — it never moves.
        // 4. The reference is only used as a HashMap key while the Interner lives.
        let static_ref: &'static str = unsafe {
            &*(owned.as_ref() as *const str)
        };

        self.strings.push(owned);
        self.map.insert(static_ref, id);
        id
    }

    /// Resolve a Sym back to its string content.
    pub fn resolve(&self, sym: Sym) -> &str {
        &self.strings[sym.0 as usize]
    }

    pub fn len(&self) -> usize { self.strings.len() }
}

fn main() {
    let mut intern = Interner::new();

    let a = intern.intern("hello");
    let b = intern.intern("world");
    let c = intern.intern("hello"); // Same as `a`

    assert_eq!(a, c); // Identical Syms
    assert_ne!(a, b);

    println!("Sym({}): {}", a.0, intern.resolve(a));
    println!("Sym({}): {}", b.0, intern.resolve(b));
    println!("Total unique strings: {}", intern.len()); // 2

    // Syms are 4 bytes — cheaper to pass around than &str (16 bytes)
    let words = vec!["foo", "bar", "foo", "baz", "bar", "foo"];
    let syms: Vec<Sym> = words.iter().map(|w| intern.intern(w)).collect();
    println!("Syms: {:?}", syms);
    // foo, bar, foo, baz, bar, foo -> [2, 3, 2, 4, 3, 2]
}
```

**Unsafety justification:** The `'static` lifetime lie is a common interner pattern. It's safe because the backing `Box<str>` values are pinned to the heap and their lifetime is bounded by the `Interner`. Never store the `&'static str` keys outside the `map`, and never drop the `Interner` while references exist.

