#![feature(allocator_api)] // for completeness; GlobalAlloc is stable

use std::alloc::{GlobalAlloc, Layout, System};
use std::sync::atomic::{AtomicI64, AtomicU64, Ordering};

pub struct TrackingAllocator {
    alloc_count: AtomicI64,  // signed: decrements on dealloc
    total_bytes: AtomicU64,
    live_bytes: AtomicI64,
}

impl TrackingAllocator {
    pub const fn new() -> Self {
        TrackingAllocator {
            alloc_count: AtomicI64::new(0),
            total_bytes: AtomicU64::new(0),
            live_bytes: AtomicI64::new(0),
        }
    }

    pub fn stats(&self) -> AllocStats {
        AllocStats {
            live_allocs: self.alloc_count.load(Ordering::Relaxed),
            total_bytes: self.total_bytes.load(Ordering::Relaxed),
            live_bytes: self.live_bytes.load(Ordering::Relaxed),
        }
    }
}

#[derive(Debug)]
pub struct AllocStats {
    pub live_allocs: i64,
    pub total_bytes: u64,
    pub live_bytes: i64,
}

unsafe impl GlobalAlloc for TrackingAllocator {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        let ptr = System.alloc(layout);
        if !ptr.is_null() {
            self.alloc_count.fetch_add(1, Ordering::Relaxed);
            self.total_bytes.fetch_add(layout.size() as u64, Ordering::Relaxed);
            self.live_bytes.fetch_add(layout.size() as i64, Ordering::Relaxed);
        }
        ptr
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        System.dealloc(ptr, layout);
        self.alloc_count.fetch_sub(1, Ordering::Relaxed);
        self.live_bytes.fetch_sub(layout.size() as i64, Ordering::Relaxed);
    }

    unsafe fn realloc(&self, ptr: *mut u8, layout: Layout, new_size: usize) -> *mut u8 {
        let new_ptr = System.realloc(ptr, layout, new_size);
        if !new_ptr.is_null() {
            let delta = new_size as i64 - layout.size() as i64;
            self.live_bytes.fetch_add(delta, Ordering::Relaxed);
            if delta > 0 {
                self.total_bytes.fetch_add(delta as u64, Ordering::Relaxed);
            }
        }
        new_ptr
    }
}

#[global_allocator]
static ALLOCATOR: TrackingAllocator = TrackingAllocator::new();

fn main() {
    let before = ALLOCATOR.stats();
    println!("Before: {before:?}");

    let v: Vec<u64> = (0..1024).collect();
    let s = String::from("Hello, allocator!");

    let during = ALLOCATOR.stats();
    println!("During: {during:?}");

    drop(v);
    drop(s);

    let after = ALLOCATOR.stats();
    println!("After:  {after:?}");
    // live_allocs and live_bytes should be back near 0
    // (some bookkeeping allocs from the runtime may remain)
}
```

**Notes:**
- `#[global_allocator]` replaces the default system allocator for the entire program.
- `Relaxed` ordering is sufficient for statistics (we don't need cross-thread synchronisation of the counts).
- Intercepting every allocation has a performance cost — use only for profiling builds.

```rust
use tokio::sync::watch;
use tokio::time::{Duration, sleep};
use std::sync::Arc;

#[derive(Clone, Debug, PartialEq)]
struct Config {
    max_requests_per_sec: u32,
    log_level: String,
    feature_flags: Vec<String>,
}

impl Default for Config {
    fn default() -> Self {
        Config {
            max_requests_per_sec: 100,
            log_level: "info".to_string(),
            feature_flags: vec![],
        }
    }
}

/// Worker that reconfigures itself whenever the config changes
async fn worker(id: u64, mut config_rx: watch::Receiver<Config>) {
    // borrow() gives the current value without cloning
    println!("Worker {id} starting with rate_limit={}",
        config_rx.borrow().max_requests_per_sec);

    loop {
        // changed() waits until the sender sends a NEW value
        // Returns Err if all senders are dropped (shutdown)
        match config_rx.changed().await {
            Ok(()) => {
                // borrow_and_update() marks as "seen" and returns current value
                let cfg = config_rx.borrow_and_update();
                println!(
                    "Worker {id} reconfigured: rate={} log={} flags={:?}",
                    cfg.max_requests_per_sec,
                    cfg.log_level,
                    cfg.feature_flags,
                );
                // Drop cfg before .await to avoid holding the read lock
            }
            Err(_) => {
                println!("Worker {id}: config channel closed, shutting down");
                break;
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let (config_tx, config_rx) = watch::channel(Config::default());

    // Spawn 5 workers — all share the same receiver (cheap clone)
    let mut handles = Vec::new();
    for id in 0..5 {
        handles.push(tokio::spawn(worker(id, config_rx.clone())));
    }

    sleep(Duration::from_millis(100)).await;

    // Update 1: rate limit change
    config_tx.send(Config {
        max_requests_per_sec: 500,
        log_level: "warn".to_string(),
        feature_flags: vec!["new-ui".to_string()],
    }).unwrap();

    sleep(Duration::from_millis(100)).await;

    // Update 2: enable another flag
    config_tx.send_modify(|cfg| {
        cfg.feature_flags.push("dark-mode".to_string());
    });

    sleep(Duration::from_millis(100)).await;

    // Dropping tx closes the channel — all workers exit
    drop(config_tx);

    for h in handles { h.await.unwrap(); }
}
```

**watch vs broadcast:**
- `watch`: stores only the **latest** value; late subscribers see current state. 1 sender, N receivers.
- `broadcast`: delivers **every** message; slow subscribers get `Lagged` errors. N senders, N receivers.

Use `watch` for configuration, feature flags, health state — anything where only the latest value matters.

