use std::marker::PhantomData;
use std::ops::{Add, Mul, Div};
use std::fmt;

// Unit markers — zero-size types, never instantiated
#[derive(Debug, Clone, Copy)] pub struct Meters;
#[derive(Debug, Clone, Copy)] pub struct Seconds;
#[derive(Debug, Clone, Copy)] pub struct MetersPerSecond;
#[derive(Debug, Clone, Copy)] pub struct SquareMeters;

/// A dimensioned value: the unit is part of the type.
#[derive(Clone, Copy)]
pub struct Quantity<U> {
    value: f64,
    _unit: PhantomData<U>,
}

impl<U: Copy> Quantity<U> {
    pub fn new(value: f64) -> Self {
        Quantity { value, _unit: PhantomData }
    }
    pub fn value(self) -> f64 { self.value }
}

impl<U: Copy + fmt::Debug> fmt::Display for Quantity<U> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{:.3} {:?}", self.value, std::any::type_name::<U>())
    }
}

// Adding same units is allowed
impl<U: Copy> Add for Quantity<U> {
    type Output = Quantity<U>;
    fn add(self, rhs: Self) -> Self::Output {
        Quantity::new(self.value + rhs.value)
    }
}

// Dividing Meters by Seconds yields MetersPerSecond
impl Div<Quantity<Seconds>> for Quantity<Meters> {
    type Output = Quantity<MetersPerSecond>;
    fn div(self, rhs: Quantity<Seconds>) -> Self::Output {
        Quantity::new(self.value / rhs.value)
    }
}

// Multiplying Meters by Meters yields SquareMeters
impl Mul for Quantity<Meters> {
    type Output = Quantity<SquareMeters>;
    fn mul(self, rhs: Quantity<Meters>) -> Self::Output {
        Quantity::new(self.value * rhs.value)
    }
}

// Convenience constructors
fn meters(v: f64) -> Quantity<Meters> { Quantity::new(v) }
fn seconds(v: f64) -> Quantity<Seconds> { Quantity::new(v) }

fn main() {
    let dist = meters(100.0);
    let time = seconds(9.58); // Usain Bolt's 100m record
    let speed: Quantity<MetersPerSecond> = dist / time;
    println!("Speed: {:.3} m/s", speed.value()); // 10.438 m/s

    let area: Quantity<SquareMeters> = meters(5.0) * meters(3.0);
    println!("Area: {:.1} m²", area.value()); // 15.0 m²

    let total_dist = meters(50.0) + meters(30.0);
    println!("Total: {:.0} m", total_dist.value()); // 80 m

    // These FAIL to compile:
    // let bad = dist + time;       // Add<Quantity<Seconds>> not impl for Quantity<Meters>
    // let bad2 = speed + dist;     // Add<Quantity<Meters>> not impl for Quantity<MetersPerSecond>
    // let bad3 = dist / dist;      // Div<Quantity<Meters>> for Quantity<Meters> not defined
}
```

**Cost:** `PhantomData<U>` is zero-size — no runtime overhead. The entire unit system lives in the type checker and is erased at compilation.

