// A heterogeneous list: each element can have a different type.
// The type encodes the full sequence: HCons<i32, HCons<String, HCons<f64, HNil>>>

/// The empty list
#[derive(Debug, Clone, Copy)]
struct HNil;

/// A cons cell: head of type H, tail of type T (another HList)
#[derive(Debug, Clone)]
struct HCons<H, T> {
    head: H,
    tail: T,
}

// Convenience constructor
fn hcons<H, T>(head: H, tail: T) -> HCons<H, T> {
    HCons { head, tail }
}

// Macro for ergonomic construction: hlist![1, "hello", 3.14]
macro_rules! hlist {
    () => { HNil };
    ($h:expr $(, $t:expr)*) => {
        HCons { head: $h, tail: hlist![$($t),*] }
    };
}

// ---- Type-level indexing using traits ----

/// Get the element at index N from the HList
trait HGet<Index> {
    type Output;
    fn get(self) -> Self::Output;
}

// Zero: get the head
struct Zero;
struct Succ<N>(N);

impl<H, T> HGet<Zero> for HCons<H, T> {
    type Output = H;
    fn get(self) -> H { self.head }
}

// Succ<N>: recurse into the tail
impl<H, T, N> HGet<Succ<N>> for HCons<H, T>
where
    T: HGet<N>,
{
    type Output = T::Output;
    fn get(self) -> T::Output { self.tail.get() }
}

// ---- Length as a type-level computation ----
trait HLen {
    const LEN: usize;
}

impl HLen for HNil {
    const LEN: usize = 0;
}

impl<H, T: HLen> HLen for HCons<H, T> {
    const LEN: usize = 1 + T::LEN;
}

// ---- Prepend ----
trait HPrepend<H> {
    type Output;
    fn prepend(self, head: H) -> Self::Output;
}

impl<H, T> HPrepend<H> for T {
    type Output = HCons<H, T>;
    fn prepend(self, head: H) -> HCons<H, T> {
        HCons { head, tail: self }
    }
}

fn main() {
    let list = hlist![42i32, "hello", 3.14f64, true];

    // Get by position at compile time
    let first: i32 = list.clone().get::<Zero, _>(); // 42
    // Type alias for readability:
    type First = Zero;
    type Second = Succ<Zero>;
    type Third = Succ<Succ<Zero>>;

    // These type-check — wrong types would fail to compile
    println!("Length: {}", <_ as HLen>::LEN); // Actually need a concrete type

    // Demonstrate manual access
    let l = hlist![1u8, "world", 99.9f64];
    println!("{}", l.head);         // 1
    println!("{}", l.tail.head);    // "world"
    println!("{}", l.tail.tail.head); // 99.9

    // Prepend
    let extended = HNil.prepend(42i32).prepend("hi");
    println!("{:?}", extended);
}
```

**Real-world use:** The `frunk` crate provides a production-grade HList implementation used for generic programming, record types, and type-safe serialization. This pattern is the foundation of Diesel's query builder and Axum's handler extraction.

