use std::cell::RefCell;
use std::collections::HashMap;

/// Per-thread LRU-lite cache: each thread has its own independent cache.
/// No synchronisation needed — thread-locals are inherently per-thread.
struct ThreadCache {
    data: HashMap<String, String>,
    max_size: usize,
    access_order: Vec<String>, // tracks insertion order for eviction
}

impl ThreadCache {
    fn new(max_size: usize) -> Self {
        ThreadCache {
            data: HashMap::new(),
            max_size,
            access_order: Vec::new(),
        }
    }

    fn get(&self, key: &str) -> Option<&String> {
        self.data.get(key)
    }

    fn insert(&mut self, key: String, value: String) {
        if self.data.len() >= self.max_size && !self.data.contains_key(&key) {
            // Evict oldest entry
            if let Some(oldest) = self.access_order.first().cloned() {
                self.data.remove(&oldest);
                self.access_order.retain(|k| k != &oldest);
            }
        }
        self.access_order.retain(|k| k != &key);
        self.access_order.push(key.clone());
        self.data.insert(key, value);
    }

    fn stats(&self) -> (usize, usize) {
        (self.data.len(), self.max_size)
    }
}

// thread_local! creates a per-thread instance, initialized lazily on first access
thread_local! {
    static CACHE: RefCell<ThreadCache> = RefCell::new(ThreadCache::new(64));
}

/// Public API — hides the thread_local/RefCell machinery
pub fn cache_get(key: &str) -> Option<String> {
    CACHE.with(|cache| {
        cache.borrow().get(key).cloned()
    })
}

pub fn cache_insert(key: impl Into<String>, value: impl Into<String>) {
    CACHE.with(|cache| {
        cache.borrow_mut().insert(key.into(), value.into());
    });
}

pub fn cache_stats() -> (usize, usize) {
    CACHE.with(|cache| cache.borrow().stats())
}

fn main() {
    cache_insert("user:1", "Alice");
    cache_insert("user:2", "Bob");

    println!("{:?}", cache_get("user:1")); // Some("Alice")
    println!("{:?}", cache_get("user:3")); // None
    println!("Stats: {:?}", cache_stats()); // (2, 64)

    // Each thread has an independent cache
    std::thread::spawn(|| {
        cache_insert("user:3", "Charlie"); // Only in this thread's cache
        println!("Thread2 user:1: {:?}", cache_get("user:1")); // None — different thread
        println!("Thread2 user:3: {:?}", cache_get("user:3")); // Some("Charlie")
    }).join().unwrap();

    // Main thread still has user:1, not user:3
    println!("Main user:3: {:?}", cache_get("user:3")); // None
}
```

**When to use `thread_local!`:**
- Per-thread caches, random number generators, or connection pools.
- Avoiding mutex contention on hot paths.
- Storing non-`Send` types like `Rc<T>` that can't cross thread boundaries.

**Caution:** Avoid holding `borrow_mut()` across async `.await` points — thread-locals are not `Sync` and async tasks may migrate between threads.

```rust
// ---- FnOnce: can only be called once (consumes captured values) ----
fn make_greeting(name: String) -> impl FnOnce() -> String {
    // `name` is moved into the closure
    move || format!("Hello, {name}!") // name consumed on call
}

// ---- FnMut: can be called multiple times, mutates captured state ----
fn make_counter(start: i64, step: i64) -> impl FnMut() -> i64 {
    let mut current = start;
    move || {
        let val = current;
        current += step;
        val
    }
}

// ---- Fn: can be called many times, no mutation ----
fn make_multiplier(factor: f64) -> impl Fn(f64) -> f64 {
    move |x| x * factor
}

// ---- Composing closures ----
fn compose<A, B, C>(
    f: impl Fn(A) -> B,
    g: impl Fn(B) -> C,
) -> impl Fn(A) -> C {
    move |x| g(f(x))
}

// ---- Higher-order function accepting any callable ----
fn apply_twice<T: Clone>(f: impl Fn(T) -> T, x: T) -> T {
    f(f(x.clone()))
}

// ---- Box<dyn Fn> for runtime polymorphism ----
fn build_pipeline(ops: Vec<Box<dyn Fn(f64) -> f64>>) -> impl Fn(f64) -> f64 {
    move |mut x| {
        for op in &ops {
            x = op(x);
        }
        x
    }
}

// ---- Demonstrating trait bounds precisely ----
fn call_once_only<F: FnOnce() -> String>(f: F) -> String {
    f() // f is consumed here — can't call again
}

fn call_repeatedly<F: Fn(usize) -> String>(f: F, times: usize) -> Vec<String> {
    (0..times).map(|i| f(i)).collect()
}

fn main() {
    // FnOnce
    let greet = make_greeting("Alice".to_string());
    println!("{}", call_once_only(greet));
    // greet();  // error: use of moved value

    // FnMut
    let mut counter = make_counter(0, 2);
    println!("{} {} {}", counter(), counter(), counter()); // 0 2 4

    // Fn
    let triple = make_multiplier(3.0);
    println!("{} {}", triple(4.0), triple(7.0)); // 12.0 21.0

    // Compose: add 1 then double
    let transform = compose(|x: f64| x + 1.0, |x| x * 2.0);
    println!("{}", transform(3.0)); // 8.0

    // apply_twice
    println!("{}", apply_twice(|x: i32| x * 3, 2)); // 18

    // Pipeline
    let pipeline = build_pipeline(vec![
        Box::new(|x| x + 10.0),
        Box::new(|x| x * 2.0),
        Box::new(|x: f64| x.sqrt()),
    ]);
    println!("{:.3}", pipeline(6.0)); // sqrt((6+10)*2) = sqrt(32) = 5.657

    // FnMut in iterator
    let mut total = 0;
    let sums: Vec<_> = (1..=5).map(|x| { total += x; total }).collect();
    println!("{:?}", sums); // [1, 3, 6, 10, 15]
}
```

**Closure trait hierarchy:** `FnOnce ⊇ FnMut ⊇ Fn`. A `Fn` can be used wherever `FnMut` or `FnOnce` is required, but not vice versa. When in doubt, accept `impl Fn(...)` — it's the most restrictive and most reusable.

