// Const generic parameters enforce valid ranges at compile time.
// Invalid configs are type errors — no runtime panics.

/// A buffer size that must be between MIN and MAX, and a power of two.
/// The validity is checked via const assertions.
#[derive(Debug, Clone, Copy)]
struct BoundedBuffer<const N: usize>;

impl<const N: usize> BoundedBuffer<N> {
    const ASSERT_POWER_OF_TWO: () = assert!(
        N.is_power_of_two(),
        "Buffer size must be a power of two"
    );

    const ASSERT_MIN: () = assert!(N >= 64, "Buffer size must be at least 64 bytes");
    const ASSERT_MAX: () = assert!(N <= 65536, "Buffer size must be at most 64KB");

    pub fn new() -> Self {
        // Force evaluation of the const assertions
        let _ = Self::ASSERT_POWER_OF_TWO;
        let _ = Self::ASSERT_MIN;
        let _ = Self::ASSERT_MAX;
        BoundedBuffer
    }

    pub const fn capacity() -> usize { N }
}

/// Thread pool with compile-time validated thread count
#[derive(Debug)]
struct ThreadPool<const THREADS: usize> {
    name: &'static str,
}

impl<const THREADS: usize> ThreadPool<THREADS> {
    const CHECK: () = {
        assert!(THREADS >= 1, "Must have at least 1 thread");
        assert!(THREADS <= 256, "Too many threads");
    };

    pub fn new(name: &'static str) -> Self {
        let _ = Self::CHECK;
        ThreadPool { name }
    }

    pub const fn thread_count() -> usize { THREADS }
}

/// Port number must be in valid range
struct Port<const P: u16>;

impl<const P: u16> Port<P> {
    const VALID: () = assert!(P >= 1024, "Ports below 1024 require privileges");

    pub fn new() -> Self {
        let _ = Self::VALID;
        Port
    }

    pub const fn value() -> u16 { P }
}

// --- Generic function requiring a validated config ---
fn create_server<const PORT: u16, const THREADS: usize, const BUF: usize>(
    _port: Port<PORT>,
    _pool: &ThreadPool<THREADS>,
    _buf: &BoundedBuffer<BUF>,
) {
    println!(
        "Server on port {PORT} with {THREADS} threads and {BUF}-byte buffers"
    );
}

fn main() {
    let port = Port::<8080>::new();
    let pool = ThreadPool::<4>::new("workers");
    let buf = BoundedBuffer::<4096>::new();

    create_server(port, &pool, &buf);

    // These FAIL at compile time:
    // let bad_port = Port::<80>::new();
    //   error: evaluation of `Port::<80>::VALID` failed: Ports below 1024 require privileges

    // let bad_buf = BoundedBuffer::<100>::new();
    //   error: Buffer size must be a power of two

    // let bad_pool = ThreadPool::<0>::new("empty");
    //   error: Must have at least 1 thread

    println!("Buffer capacity: {} bytes", BoundedBuffer::<4096>::capacity());
    println!("Thread count: {}", ThreadPool::<4>::thread_count());
}
```

**Why const assertions?** Unlike `debug_assert!` (runtime, debug only) or regular `assert!` (runtime always), `const { assert!(...) }` or const-eval `assert!` in a `const` context is checked at **compile time** — the program simply won't compile with invalid parameters.

