use std::fmt;

// Newtypes: zero-cost wrappers that create distinct types
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct UserId(u64);

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct OrderId(u64);

// Dollars stored as cents to avoid floating-point issues
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub struct Dollars(i64); // cents internally

impl UserId {
    pub fn new(id: u64) -> Self { UserId(id) }
    pub fn as_u64(self) -> u64 { self.0 }
}

impl OrderId {
    pub fn new(id: u64) -> Self { OrderId(id) }
    pub fn as_u64(self) -> u64 { self.0 }
}

impl Dollars {
    pub fn from_cents(cents: i64) -> Self { Dollars(cents) }
    pub fn from_dollars(dollars: i64) -> Self { Dollars(dollars * 100) }
    pub fn cents(self) -> i64 { self.0 }
    pub fn dollars(self) -> i64 { self.0 / 100 }

    pub fn checked_add(self, other: Dollars) -> Option<Dollars> {
        self.0.checked_add(other.0).map(Dollars)
    }
}

impl fmt::Display for Dollars {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "${}.{:02}", self.0 / 100, (self.0 % 100).unsigned_abs())
    }
}

impl fmt::Display for UserId {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "user:{}", self.0)
    }
}

impl fmt::Display for OrderId {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "order:{}", self.0)
    }
}

// Without newtypes, this function signature is ambiguous:
// fn process_order(user_id: u64, order_id: u64, amount: f64)
//
// With newtypes, the compiler catches argument transposition:
fn process_order(user: UserId, order: OrderId, amount: Dollars) {
    println!("Processing {order} for {user}: {amount}");
}

fn main() {
    let user = UserId::new(42);
    let order = OrderId::new(1001);
    let amount = Dollars::from_dollars(99);

    process_order(user, order, amount);

    // Compile error — types are distinct even though underlying repr is u64:
    // process_order(order, user, amount); // ERROR: mismatched types

    // Arithmetic goes through the newtype, not raw integers
    let tax = Dollars::from_cents(891);
    let total = amount.checked_add(tax).expect("overflow");
    println!("Total with tax: {total}");

    // HashMap keys work because we derived Hash + Eq
    use std::collections::HashMap;
    let mut cache: HashMap<UserId, String> = HashMap::new();
    cache.insert(user, "Alice".to_string());
    println!("{:?}", cache.get(&user));
}
```

Why newtypes beat type aliases:
- `type UserId = u64` is transparent — the compiler allows mixing `UserId` and `OrderId` freely.
- `struct UserId(u64)` is nominal — mismatching them is a hard compile error.
- The wrapper is zero-cost: `UserId` has the same size, alignment, and representation as `u64`.
- Implement only the traits you explicitly want — `Dollars` does not implement `Add` directly, forcing you to use `checked_add` and handle overflow.

```rust
// The Command trait — each operation implements this
pub trait Command {
    fn execute(&mut self, doc: &mut Document);
    fn undo(&mut self, doc: &mut Document);
    fn description(&self) -> &str;
}

#[derive(Debug, Default)]
pub struct Document {
    pub text: String,
}

// --- Concrete Commands ---

pub struct InsertText {
    position: usize,
    text: String,
}

impl InsertText {
    pub fn new(position: usize, text: impl Into<String>) -> Self {
        InsertText { position, text: text.into() }
    }
}

impl Command for InsertText {
    fn execute(&mut self, doc: &mut Document) {
        doc.text.insert_str(self.position, &self.text);
    }

    fn undo(&mut self, doc: &mut Document) {
        let end = self.position + self.text.len();
        doc.text.drain(self.position..end);
    }

    fn description(&self) -> &str { "InsertText" }
}

pub struct DeleteText {
    position: usize,
    length: usize,
    deleted: String, // stored on execute for undo
}

impl DeleteText {
    pub fn new(position: usize, length: usize) -> Self {
        DeleteText { position, length, deleted: String::new() }
    }
}

impl Command for DeleteText {
    fn execute(&mut self, doc: &mut Document) {
        let end = (self.position + self.length).min(doc.text.len());
        self.deleted = doc.text[self.position..end].to_string();
        doc.text.drain(self.position..end);
    }

    fn undo(&mut self, doc: &mut Document) {
        doc.text.insert_str(self.position, &self.deleted);
    }

    fn description(&self) -> &str { "DeleteText" }
}

pub struct ReplaceAll {
    from: String,
    to: String,
    previous: String,
}

impl ReplaceAll {
    pub fn new(from: impl Into<String>, to: impl Into<String>) -> Self {
        ReplaceAll { from: from.into(), to: to.into(), previous: String::new() }
    }
}

impl Command for ReplaceAll {
    fn execute(&mut self, doc: &mut Document) {
        self.previous = doc.text.clone();
        doc.text = doc.text.replace(&*self.from, &self.to);
    }

    fn undo(&mut self, doc: &mut Document) {
        doc.text = self.previous.clone();
    }

    fn description(&self) -> &str { "ReplaceAll" }
}

// --- Editor: holds document + undo/redo stacks ---

pub struct Editor {
    document: Document,
    undo_stack: Vec<Box<dyn Command>>,
    redo_stack: Vec<Box<dyn Command>>,
}

impl Editor {
    pub fn new() -> Self {
        Editor {
            document: Document::default(),
            undo_stack: Vec::new(),
            redo_stack: Vec::new(),
        }
    }

    pub fn execute(&mut self, mut cmd: Box<dyn Command>) {
        cmd.execute(&mut self.document);
        self.undo_stack.push(cmd);
        // Any new action clears the redo stack
        self.redo_stack.clear();
    }

    pub fn undo(&mut self) -> bool {
        if let Some(mut cmd) = self.undo_stack.pop() {
            cmd.undo(&mut self.document);
            self.redo_stack.push(cmd);
            true
        } else {
            false
        }
    }

    pub fn redo(&mut self) -> bool {
        if let Some(mut cmd) = self.redo_stack.pop() {
            cmd.execute(&mut self.document);
            self.undo_stack.push(cmd);
            true
        } else {
            false
        }
    }

    pub fn text(&self) -> &str { &self.document.text }

    pub fn history(&self) -> Vec<&str> {
        self.undo_stack.iter().map(|c| c.description()).collect()
    }
}

fn main() {
    let mut editor = Editor::new();

    editor.execute(Box::new(InsertText::new(0, "Hello, world!")));
    println!("After insert: '{}'", editor.text());

    editor.execute(Box::new(ReplaceAll::new("world", "Rust")));
    println!("After replace: '{}'", editor.text());

    editor.execute(Box::new(DeleteText::new(5, 1)));
    println!("After delete: '{}'", editor.text());

    println!("History: {:?}", editor.history());

    editor.undo();
    println!("After undo: '{}'", editor.text());

    editor.undo();
    println!("After undo: '{}'", editor.text());

    editor.redo();
    println!("After redo: '{}'", editor.text());
}
```

The `deleted` field in `DeleteText` demonstrates the common pattern of capturing state during `execute()` that is needed for `undo()`. `Box<dyn Command>` allows heterogeneous command types on the same stack. Clearing `redo_stack` on new execute matches standard editor semantics.

```rust
use std::collections::HashMap;

// --- 1. Frequency map (the canonical entry API example) ---
fn word_frequency(text: &str) -> HashMap<&str, usize> {
    let mut freq: HashMap<&str, usize> = HashMap::new();
    for word in text.split_whitespace() {
        // entry() does ONE hash lookup, not two
        *freq.entry(word).or_insert(0) += 1;
    }
    freq
}

// --- 2. Group-by: collect items into a Vec per key ---
fn group_by_first_char(words: &[&str]) -> HashMap<char, Vec<&str>> {
    let mut groups: HashMap<char, Vec<&str>> = HashMap::new();
    for &word in words {
        if let Some(c) = word.chars().next() {
            groups.entry(c).or_default().push(word);
            // or_default() uses Default::default() — Vec::new() here
        }
    }
    groups
}

// --- 3. or_insert_with: lazy initialization (only runs closure if key absent) ---
fn lazy_expensive_init() {
    let mut cache: HashMap<u32, Vec<u32>> = HashMap::new();
    let key = 42u32;

    // The closure only runs if key is not present — avoids computing sieve unnecessarily
    cache.entry(key).or_insert_with(|| {
        println!("Computing factors for {key} (expensive!)");
        (1..=key).filter(|&d| key % d == 0).collect()
    });

    // Second call: closure not called, existing value returned
    cache.entry(key).or_insert_with(|| {
        println!("This never prints");
        vec![]
    });

    println!("Factors of {key}: {:?}", cache[&key]);
}

// --- 4. and_modify + or_insert: update existing or set default ---
fn running_stats(data: &[(String, f64)]) -> HashMap<String, (f64, usize)> {
    let mut stats: HashMap<String, (f64, usize)> = HashMap::new();
    for (category, value) in data {
        stats.entry(category.clone())
            .and_modify(|(sum, count)| {
                *sum += value;
                *count += 1;
            })
            .or_insert((*value, 1));
    }
    stats
}

// --- 5. Occupied/Vacant: full control via match ---
fn upsert_max(map: &mut HashMap<String, i32>, key: String, value: i32) {
    use std::collections::hash_map::Entry;
    match map.entry(key) {
        Entry::Occupied(mut e) => {
            if value > *e.get() {
                e.insert(value);
            }
        }
        Entry::Vacant(e) => {
            e.insert(value);
        }
    }
}

// --- 6. Remove-if-condition (entry + occupied remove) ---
fn decrement_or_remove(counts: &mut HashMap<String, u32>, key: &str) {
    use std::collections::hash_map::Entry;
    if let Entry::Occupied(mut e) = counts.entry(key.to_string()) {
        *e.get_mut() -= 1;
        if *e.get() == 0 {
            e.remove();
        }
    }
}

fn main() {
    let text = "the quick brown fox jumps over the lazy dog the fox";
    let freq = word_frequency(text);
    let mut sorted: Vec<_> = freq.iter().collect();
    sorted.sort_by(|a, b| b.1.cmp(a.1).then(a.0.cmp(b.0)));
    println!("Top words: {:?}", &sorted[..3]);

    let words = ["apple", "avocado", "banana", "blueberry", "cherry", "apricot"];
    let groups = group_by_first_char(&words);
    let mut g_keys: Vec<_> = groups.keys().collect();
    g_keys.sort();
    for k in g_keys { println!("'{k}': {:?}", groups[k]); }

    lazy_expensive_init();

    let data = vec![
        ("A".to_string(), 1.0), ("B".to_string(), 2.0),
        ("A".to_string(), 3.0), ("B".to_string(), 4.0),
    ];
    let stats = running_stats(&data);
    for (k, (sum, count)) in &stats {
        println!("{k}: avg={:.2}", sum / *count as f64);
    }

    let mut maxmap = HashMap::new();
    upsert_max(&mut maxmap, "score".into(), 10);
    upsert_max(&mut maxmap, "score".into(), 7);  // ignored
    upsert_max(&mut maxmap, "score".into(), 15); // wins
    println!("Max score: {}", maxmap["score"]); // 15
}
```

The entry API rule: **never write `if map.contains_key(k) { map.get_mut(k) } else { map.insert(k, ...) }`** — that's two hash lookups. `entry()` computes the hash once and returns a handle to the bucket, which either variant (`Occupied`/`Vacant`) resolves without rehashing.

