// --- 2. Finding nearest keys ---
fn nearest_key_demo() {
    let mut map: BTreeMap<i64, &str> = BTreeMap::new();
    for (ts, ev) in [(100, "start"), (250, "checkpoint"), (400, "end"), (600, "cleanup")] {
        map.insert(ts, ev);
    }

    let query = 300i64;

    // Floor: largest key <= query
    let floor = map.range(..=query).next_back();
    println!("Floor of {query}: {floor:?}"); // Some((250, "checkpoint"))

    // Ceiling: smallest key >= query
    let ceil = map.range(query..).next();
    println!("Ceil of {query}: {ceil:?}"); // Some((400, "end"))

    // Nearest overall
    let nearest = match (floor, ceil) {
        (Some((fk, fv)), Some((ck, cv))) => {
            if (query - fk).abs() <= (ck - query).abs() { (fk, fv) } else { (ck, cv) }
        }
        (Some(f), None) => f,
        (None, Some(c)) => c,
        (None, None) => panic!("empty map"),
    };
    println!("Nearest to {query}: {nearest:?}"); // (250, "checkpoint")
}

// --- 3. Sorted event timeline ---

#[derive(Debug, Clone)]
pub struct Event {
    pub name: String,
    pub payload: String,
}

/// A timeline where events are sorted by timestamp.
/// Multiple events can share a timestamp — stored as Vec.
pub struct Timeline {
    events: BTreeMap<u64, Vec<Event>>,
}

impl Timeline {
    pub fn new() -> Self { Timeline { events: BTreeMap::new() } }

    pub fn insert(&mut self, timestamp_ms: u64, event: Event) {
        self.events.entry(timestamp_ms).or_default().push(event);
    }

    /// All events in [start, end] ms, in chronological order
    pub fn range(&self, start: u64, end: u64) -> impl Iterator<Item = (u64, &Event)> {
        self.events
            .range(start..=end)
            .flat_map(|(&ts, evs)| evs.iter().map(move |e| (ts, e)))
    }

    /// Most recent event at or before `now`
    pub fn latest_at(&self, now: u64) -> Option<(u64, &Event)> {
        self.events
            .range(..=now)
            .next_back()
            .and_then(|(&ts, evs)| evs.last().map(|e| (ts, e)))
    }

    /// Drain all events before `cutoff` (for log rotation)
    pub fn drain_before(&mut self, cutoff: u64) -> Vec<(u64, Vec<Event>)> {
        // split_off returns the [cutoff..] portion, self becomes [..cutoff)
        let keep = self.events.split_off(&cutoff);
        let old = std::mem::replace(&mut self.events, keep);
        old.into_iter().collect()
    }
}

fn main() {
    range_query_demo();
    println!();
    nearest_key_demo();
    println!();

    let mut timeline = Timeline::new();
    timeline.insert(1000, Event { name: "login".into(), payload: "user=42".into() });
    timeline.insert(1500, Event { name: "page_view".into(), payload: "/home".into() });
    timeline.insert(1500, Event { name: "page_view".into(), payload: "/about".into() }); // same ts
    timeline.insert(2000, Event { name: "purchase".into(), payload: "item=99".into() });
    timeline.insert(3000, Event { name: "logout".into(), payload: "".into() });

    println!("Events 1000..=2000:");
    for (ts, ev) in timeline.range(1000, 2000) {
        println!("  [{ts}] {}: {}", ev.name, ev.payload);
    }

    println!("Latest at t=1800: {:?}", timeline.latest_at(1800).map(|(ts, e)| (ts, &e.name)));

    let old = timeline.drain_before(2000);
    println!("Drained {} timestamp buckets", old.len());
    println!("Remaining events: {}", timeline.events.len());
}
```

BTreeMap guarantees: keys are always sorted, `range()` is O(log n) to find the start, then O(1) per element. `split_off()` is O(k log n) where k is keys being split — use it for efficient time-based log rotation instead of repeatedly calling `remove`.

```rust
use std::{
    sync::{Arc, Mutex, mpsc},
    thread,
};

type Job = Box<dyn FnOnce() + Send + 'static>;

enum Message {
    Job(Job),
    Shutdown,
}

pub struct ThreadPool {
    workers: Vec<Worker>,
    sender: mpsc::Sender<Message>,
}

impl ThreadPool {
    /// Panics if `size` == 0.
    pub fn new(size: usize) -> Self {
        assert!(size > 0, "pool size must be > 0");
        let (sender, receiver) = mpsc::channel::<Message>();
        // Share one receiver across all workers
        let receiver = Arc::new(Mutex::new(receiver));

        let workers = (0..size)
            .map(|id| Worker::new(id, Arc::clone(&receiver)))
            .collect();

        ThreadPool { workers, sender }
    }

    /// Submit a job. Panics if the pool has been shut down.
    pub fn execute<F>(&self, f: F)
    where
        F: FnOnce() + Send + 'static,
    {
        self.sender.send(Message::Job(Box::new(f))).unwrap();
    }

    /// Graceful shutdown: wait for all in-flight jobs to complete.
    pub fn shutdown(self) {
        // One Shutdown message per worker
        for _ in &self.workers {
            self.sender.send(Message::Shutdown).unwrap();
        }
        // Drop sender so workers see the channel closed after Shutdown
        drop(self.sender);
        for w in self.workers {
            if let Some(handle) = w.thread {
                handle.join().unwrap();
            }
        }
    }
}

// Drop impl for implicit shutdown (if caller doesn't call .shutdown())
impl Drop for ThreadPool {
    fn drop(&mut self) {
        for _ in &self.workers {
            let _ = self.sender.send(Message::Shutdown);
        }
        for worker in &mut self.workers {
            if let Some(handle) = worker.thread.take() {
                let _ = handle.join();
            }
        }
    }
}

struct Worker {
    #[allow(dead_code)]
    id: usize,
    thread: Option<thread::JoinHandle<()>>,
}

impl Worker {
    fn new(id: usize, receiver: Arc<Mutex<mpsc::Receiver<Message>>>) -> Self {
        let thread = thread::Builder::new()
            .name(format!("worker-{id}"))
            .spawn(move || loop {
                let message = receiver.lock().unwrap().recv();
                match message {
                    Ok(Message::Job(job)) => {
                        job();
                    }
                    Ok(Message::Shutdown) | Err(_) => {
                        break;
                    }
                }
            })
            .expect("failed to spawn worker thread");

        Worker { id, thread: Some(thread) }
    }
}

fn main() {
    use std::sync::atomic::{AtomicUsize, Ordering};
    use std::time::Instant;

    let pool = ThreadPool::new(4);
    let counter = Arc::new(AtomicUsize::new(0));
    let start = Instant::now();

    for i in 0..20 {
        let c = Arc::clone(&counter);
        pool.execute(move || {
            // Simulate work
            thread::sleep(std::time::Duration::from_millis(10));
            c.fetch_add(1, Ordering::Relaxed);
            println!("Job {i} done on {:?}", thread::current().name());
        });
    }

    pool.shutdown(); // Waits for all 20 jobs to complete
    println!("Completed {} jobs in {:?}", counter.load(Ordering::Relaxed), start.elapsed());
    // ~50ms for 20 x 10ms jobs on 4 threads, vs 200ms sequential
}
```

Design notes:
- The `Arc<Mutex<Receiver>>` pattern lets multiple workers compete for jobs without external coordination — whichever worker can lock first takes the next job (work-stealing by mutex contention).
- Named threads (`Builder::name`) make debugging easier — thread names appear in panic backtraces and profilers.
- `Message::Shutdown` is cleaner than closing the channel because it lets in-flight jobs finish before the worker exits.
- `thread` stored as `Option<JoinHandle>` so `Drop` can call `.take()` to avoid double-join.

```rust
// Cargo.toml: crossbeam = "0.8"
use crossbeam::channel::{self, Receiver, Sender, Select, bounded, unbounded, after, tick};
use std::thread;
use std::time::Duration;

// --- 1. MPMC vs MPSC: crossbeam channels are multi-producer multi-consumer ---

fn mpmc_demo() {
    let (tx, rx) = unbounded::<i32>();

    // Multiple producers
    let tx2 = tx.clone();
    thread::spawn(move || { for i in 0..5 { tx.send(i).unwrap(); } });
    thread::spawn(move || { for i in 5..10 { tx2.send(i).unwrap(); } });

    // Multiple consumers — impossible with std::sync::mpsc
    let rx2 = rx.clone();
    let h1 = thread::spawn(move || {
        let mut sum = 0;
        while let Ok(v) = rx.recv() { sum += v; }
        sum
    });
    let h2 = thread::spawn(move || {
        let mut sum = 0;
        while let Ok(v) = rx2.recv() { sum += v; }
        sum
    });

    let s1 = h1.join().unwrap();
    let s2 = h2.join().unwrap();
    println!("Total: {} (expected 45)", s1 + s2);
}

// --- 2. Bounded channels: backpressure ---

fn backpressure_demo() {
    // Capacity 4: producer blocks when consumer is slow
    let (tx, rx) = bounded::<String>(4);

    let producer = thread::spawn(move || {
        for i in 0..10 {
            println!("Sending item {i}");
            tx.send(format!("item-{i}")).unwrap(); // blocks when buffer full
        }
        // tx dropped here — receiver will see disconnected after last item
    });

    let consumer = thread::spawn(move || {
        for item in rx.iter() {
            thread::sleep(Duration::from_millis(10)); // slow consumer
            println!("Received: {item}");
        }
    });

    producer.join().unwrap();
    consumer.join().unwrap();
}

// --- 3. select!: receive from multiple channels without blocking on any one ---

fn select_demo() {
    let (work_tx, work_rx) = unbounded::<String>();
    let (done_tx, done_rx) = bounded::<()>(1);

    let worker = thread::spawn(move || {
        // Deadline channel fires after 100ms
        let timeout = after(Duration::from_millis(100));

        loop {
            let mut sel = Select::new();
            let oper_work = sel.recv(&work_rx);
            let oper_done = sel.recv(&done_rx);
            let oper_timeout = sel.recv(&timeout);

            let oper = sel.select();
            match oper.index() {
                i if i == oper_work => match oper.recv(&work_rx) {
                    Ok(job) => println!("Working on: {job}"),
                    Err(_) => { println!("Work channel closed"); break; }
                },
                i if i == oper_done => {
                    let _ = oper.recv(&done_rx);
                    println!("Shutdown signal received");
                    break;
                }
                i if i == oper_timeout => {
                    let _ = oper.recv(&timeout);
                    println!("Timeout — no work for 100ms, shutting down");
                    break;
                }
                _ => unreachable!()
            }
        }
    });

    work_tx.send("task-1".into()).unwrap();
    work_tx.send("task-2".into()).unwrap();
    thread::sleep(Duration::from_millis(5));
    done_tx.send(()).unwrap();

    worker.join().unwrap();
}

// --- 4. Tick: periodic heartbeat / rate limiter ---

fn tick_demo() {
    let ticker = tick(Duration::from_millis(20));
    let (cancel_tx, cancel_rx) = bounded::<()>(1);

    thread::spawn(move || {
        thread::sleep(Duration::from_millis(75));
        cancel_tx.send(()).unwrap();
    });

    let mut ticks = 0;
    loop {
        let mut sel = Select::new();
        let t = sel.recv(&ticker);
        let c = sel.recv(&cancel_rx);
        let oper = sel.select();
        match oper.index() {
            i if i == t => { oper.recv(&ticker).unwrap(); ticks += 1; println!("tick {ticks}"); }
            i if i == c => { oper.recv(&cancel_rx).unwrap(); break; }
            _ => unreachable!()
        }
    }
    println!("Stopped after {ticks} ticks");
}

// --- 5. Disconnected pattern: detect when all senders are gone ---

fn disconnected_pattern() {
    use crossbeam::channel::RecvError;
    let (tx, rx) = unbounded::<i32>();

    thread::spawn(move || {
        for i in 0..3 { tx.send(i).unwrap(); }
        // tx dropped here
    });

    loop {
        match rx.recv() {
            Ok(v) => println!("Got: {v}"),
            Err(RecvError) => { println!("All senders gone — clean exit"); break; }
        }
    }
}

fn main() {
    println!("=== MPMC ==="); mpmc_demo();
    println!("=== Backpressure ==="); backpressure_demo();
    println!("=== Select ==="); select_demo();
    println!("=== Tick ==="); tick_demo();
    println!("=== Disconnected ==="); disconnected_pattern();
}
```

Crossbeam vs std::sync::mpsc:
- `mpsc` is single-consumer only; crossbeam channels are MPMC — any thread can recv.
- `bounded(0)` is a rendezvous channel: send blocks until a receiver is ready (synchronous handoff).
- `Select` is the Rust equivalent of Go's `select` — it blocks until any one of N channels is ready, with no spurious wakeups.
- `after()` and `tick()` return `Receiver<Instant>` — they compose naturally with `Select`.

```rust
// Cargo.toml:
// rayon = "1.10"

use rayon::prelude::*;
use rayon::ThreadPoolBuilder;
use std::time::Instant;

// --- Simulate CPU-heavy work ---
fn is_prime(n: u64) -> bool {
    if n < 2 { return false; }
    if n == 2 { return true; }
    if n % 2 == 0 { return false; }
    let limit = (n as f64).sqrt() as u64 + 1;
    (3..=limit).step_by(2).all(|i| n % i != 0)
}

fn heavy_transform(x: u64) -> (u64, bool, u64) {
    let prime = is_prime(x);
    let sum_digits: u64 = x.to_string().bytes().map(|b| (b - b'0') as u64).sum();
    (x, prime, sum_digits)
}

fn main() {
    let data: Vec<u64> = (2..=100_000).collect();

    // --- 1. Sequential baseline ---
    let t0 = Instant::now();
    let seq_primes = data.iter().filter(|&&x| is_prime(x)).count();
    println!("Sequential: {seq_primes} primes in {:?}", t0.elapsed());

    // --- 2. par_iter: drop-in parallel replacement ---
    let t1 = Instant::now();
    let par_primes = data.par_iter().filter(|&&x| is_prime(x)).count();
    println!("Parallel:   {par_primes} primes in {:?}", t1.elapsed());
    assert_eq!(seq_primes, par_primes);

    // --- 3. Parallel map → collect ---
    let t2 = Instant::now();
    let transformed: Vec<_> = data
        .par_iter()
        .copied()
        .map(heavy_transform)
        .filter(|(_, prime, _)| *prime)
        .collect();
    println!("Parallel map+filter: {} primes in {:?}", transformed.len(), t2.elapsed());

    // --- 4. Parallel map-reduce (sum of prime digit-sums) ---
    let t3 = Instant::now();
    let digit_sum_total: u64 = data
        .par_iter()
        .copied()
        .filter(|&x| is_prime(x))
        .map(|x| x.to_string().bytes().map(|b| (b - b'0') as u64).sum::<u64>())
        .sum(); // rayon's parallel sum (reduce under the hood)
    println!("Parallel digit sum: {digit_sum_total} in {:?}", t3.elapsed());

    // --- 5. par_chunks: manual chunking for uneven workloads ---
    let t4 = Instant::now();
    let chunk_results: Vec<usize> = data
        .par_chunks(1000)
        .map(|chunk| chunk.iter().filter(|&&x| is_prime(x)).count())
        .collect();
    let total: usize = chunk_results.iter().sum();
    println!("par_chunks: {total} primes in {:?}", t4.elapsed());

    // --- 6. Custom thread pool ---
    let pool = ThreadPoolBuilder::new()
        .num_threads(2) // limit parallelism
        .thread_name(|i| format!("worker-{i}"))
        .stack_size(4 * 1024 * 1024) // 4MB stack per thread
        .build()
        .unwrap();

    let t5 = Instant::now();
    let limited_count = pool.install(|| {
        data.par_iter().filter(|&&x| is_prime(x)).count()
    });
    println!("2-thread pool: {limited_count} primes in {:?}", t5.elapsed());

    // --- 7. Parallel sort ---
    let mut values: Vec<u64> = (0..50_000).rev().collect();
    let t6 = Instant::now();
    values.par_sort_unstable();
    println!("par_sort_unstable 50K items: {:?}", t6.elapsed());
    assert!(values.windows(2).all(|w| w[0] <= w[1]));

    // --- 8. par_iter on HashMap entries (sort by value) ---
    use std::collections::HashMap;
    let freq: HashMap<char, usize> = "hello world rust programming"
        .chars()
        .fold(HashMap::new(), |mut m, c| { *m.entry(c).or_insert(0) += 1; m });

    let mut pairs: Vec<_> = freq.par_iter().collect();
    pairs.par_sort_by(|a, b| b.1.cmp(a.1).then(a.0.cmp(b.0)));
    println!("Top chars: {:?}", &pairs[..3]);
}
```

Rayon rules:
- `par_iter()` vs `par_iter_mut()` vs `into_par_iter()` mirror the sequential counterparts.
- Rayon uses a **work-stealing** scheduler — no manual load balancing needed.
- The global thread pool has `N_CPUS` threads by default. `ThreadPoolBuilder` lets you create isolated pools for background tasks or latency-sensitive code.
- `pool.install(|| ...)` runs the closure's rayon operations in that pool, not the global one.
- Avoid: holding mutexes inside parallel closures (causes deadlock), I/O-heavy tasks (rayon is for CPU work — use async for I/O).

