// === Demonstration: what #[log_call] generates ===
// The macro transforms the function by wrapping its body in a closure,
// printing args before and the return value after.

// Original:
//   #[log_call]
//   fn add(a: i32, b: i32) -> i32 { a + b }
//
// Becomes (approximately):
//   fn add(a: i32, b: i32) -> i32 {
//       print!("[CALL] add(");
//       print!("a = {:?}, ", a);
//       print!("b = {:?}, ", b);
//       println!(")");
//       let __result = (|| { a + b })();
//       println!("[RET]  add -> {:?}", __result);
//       __result
//   }

// Simulated output of the macro:
fn add(a: i32, b: i32) -> i32 {
    print!("[CALL] add(");
    print!("a = {:?}, ", a);
    print!("b = {:?}, ", b);
    println!(")");
    let result = (|| { a + b })();
    println!("[RET]  add -> {:?}", result);
    result
}

fn find_first<T: std::fmt::Debug + PartialEq>(haystack: &[T], needle: &T) -> Option<usize> {
    print!("[CALL] find_first(");
    print!("haystack = {:?}, ", haystack);
    print!("needle = {:?}, ", needle);
    println!(")");
    let result = (|| {
        haystack.iter().position(|x| x == needle)
    })();
    println!("[RET]  find_first -> {:?}", result);
    result
}

struct Calculator { value: f64 }

impl Calculator {
    fn multiply(&self, x: f64, factor: f64) -> f64 {
        // #[log_call] on methods works too — captures self
        print!("[CALL] multiply(");
        print!("self.value = {:?}, ", self.value);
        print!("x = {:?}, ", x);
        print!("factor = {:?}, ", factor);
        println!(")");
        let result = (|| { self.value + x * factor })();
        println!("[RET]  multiply -> {:?}", result);
        result
    }
}

fn main() {
    let sum = add(3, 7);
    println!("Result: {sum}\n");

    let items = vec!["apple", "banana", "cherry"];
    let pos = find_first(&items, &"banana");
    println!("Position: {pos:?}\n");

    let calc = Calculator { value: 10.0 };
    let r = calc.multiply(3.0, 2.5);
    println!("Calc: {r}");
}

// Output:
// [CALL] add(a = 3, b = 7, )
// [RET]  add -> 10
// Result: 10
//
// [CALL] find_first(haystack = ["apple", "banana", "cherry"], needle = "banana", )
// [RET]  find_first -> Some(1)
// Position: Some(1)
```

Attribute macro mechanics:
- `#[proc_macro_attribute]` receives two `TokenStream`s: the attribute's arguments (e.g., `#[log_call(level=debug)]`) and the annotated item.
- `ItemFn` from `syn` gives structured access to visibility, signature, body, and existing attributes.
- Wrapping the body in `(|| #block )()` preserves early returns (`?`, `return`) — without this, `return` inside the original body would return from the wrapper, not the outer function. The closure makes `return` behave as expected within the original scope.
- The generated `__result` binding uses a double-underscore prefix to minimize collision risk (though hygiene handles this in practice).

```rust
// --- What hygiene prevents ---

// This macro introduces a variable named `temp` internally.
// The caller's `temp` variable is completely unaffected.
macro_rules! swap_via_temp {
    ($a:expr, $b:expr) => {{
        let temp = $a; // this `temp` is in a fresh hygiene context
        $a = $b;
        $b = temp;
    }};
}

// This macro has a loop with a `break` — it does NOT interfere
// with any outer loop the caller has
macro_rules! find_in_slice {
    ($slice:expr, $target:expr) => {{
        let mut _found = None;
        for (i, item) in $slice.iter().enumerate() {
            if *item == $target {
                _found = Some(i);
                break; // breaks the inner loop ONLY
            }
        }
        _found
    }};
}

fn hygiene_demo() {
    let mut x = 1;
    let mut temp = 999; // caller's `temp` — NOT touched by macro

    // This would be a bug WITHOUT hygiene:
    // swap_via_temp would overwrite caller's `temp`
    swap_via_temp!(x, temp);
    // temp is now 1 (was x), x is now 999
    // Caller's intent: temp==999 used by name, but macro's temp is separate
    println!("x={x}, temp={temp}"); // x=999, temp=1 — swap worked correctly

    // The `break` inside find_in_slice! only exits the macro's inner loop
    let data = [10, 20, 30, 40];
    let mut outer_count = 0;
     'outer: for _ in 0..3 {
        outer_count += 1;
        let idx = find_in_slice!(data, 30); // break inside doesn't affect 'outer
        if idx.is_some() { break 'outer; }
    }
    println!("outer_count={outer_count}"); // 1, not 3
}

// --- Where hygiene breaks down: $crate and cross-crate items ---

// Problem: if this macro is exported and used from another crate,
// `Vec` might be shadowed or in a different path.
// Solution: use $crate:: or ::std:: for fully qualified paths.
macro_rules! make_vec_bad {
    ($($x:expr),*) => {{
        // BAD: `Vec` resolves in the caller's scope
        let v: Vec<_> = vec![$($x),*];
        v
    }};
}

macro_rules! make_vec_good {
    ($($x:expr),*) => {{
        // GOOD: always resolves to std's Vec regardless of caller's imports
        let mut v: ::std::vec::Vec<_> = ::std::vec::Vec::new();
        $( v.push($x); )*
        v
    }};
}

// --- Intentionally escaping hygiene: tt muncher with identifier injection ---
// Sometimes you WANT a macro to inject a name into the caller's scope.
// Example: a macro that declares a named variable.

// `ident` fragment specifier captures an identifier without hygiene wrapping
macro_rules! declare_counter {
    ($name:ident) => {
        // Using $name as an ident injects it into the CALLER's scope
        let mut $name: usize = 0;
        // This is intentional: the caller will use `$name` directly
    };
}

macro_rules! declare_and_init {
    ($name:ident = $val:expr) => {
        let $name = $val;
    };
}

fn escaped_hygiene_demo() {
    declare_counter!(hits); // injects `hits` into this scope
    hits += 1;
    hits += 1;
    println!("hits={hits}"); // 2 — the ident IS in caller scope

    declare_and_init!(result = 42 * 2);
    println!("result={result}"); // 84
}

// --- Hygiene and $crate ---

// In a library macro, use $crate to refer to items in YOUR crate
// so callers don't need to import them.
// (This is a demo — $crate only works in exported macros)

/*
// In my_lib/src/lib.rs:
pub struct MyError(pub String);

#[macro_export]
macro_rules! my_bail {
    ($msg:expr) => {
        return Err($crate::MyError($msg.to_string()));
        // $crate resolves to `my_lib`, even when used in another crate
    };
}
*/

// --- Macro that deliberately injects multiple names ---
macro_rules! timing_block {
    ($label:expr, $name:ident, $body:block) => {
        let __start = ::std::time::Instant::now();
        let $name = { $body }; // $name is in caller scope
        println!("{}: {:?}", $label, __start.elapsed());
        // __start uses double-underscore — convention for "internal, don't shadow me"
    };
}

fn timing_demo() {
    timing_block!("computation", answer, {
        (1u64..=1000).sum::<u64>()
    });
    println!("answer={answer}"); // answer is in scope here
}

fn main() {
    hygiene_demo();
    escaped_hygiene_demo();
    timing_demo();

    let v = make_vec_good!(1, 2, 3);
    println!("{v:?}");
}
```

Hygiene summary:
- **Default behavior**: identifiers introduced by a macro live in a fresh context — they cannot shadow or be shadowed by caller-scope variables with the same name.
- **`$ident` fragments**: when a macro captures an identifier via `$name:ident` and binds it with `let $name = ...`, that binding IS in the caller's scope — this is intentional escape.
- **Paths**: macros can refer to items from other crates safely using `$crate::` (own crate) or `::std::` (absolute). This prevents breakage when callers have conflicting imports.
- **Convention**: prefix macro-internal variables with `__` (double underscore) to signal "implementation detail" and minimize practical collision risk, even though hygiene formally handles it.

