use std::marker::PhantomData;
use std::io::{self, Write, Read};

// --- State marker types (uninhabited — cannot be constructed) ---
pub enum Disconnected {}
pub enum Connected {}
pub enum TlsHandshaking {}
pub enum Authenticated {}

// --- The connection type, parameterized on state ---
pub struct TcpConn<S> {
    // In a real impl: TcpStream, buffers, etc.
    addr: String,
    _state: PhantomData<S>,
}

// --- Methods available in ALL states ---
impl<S> TcpConn<S> {
    pub fn remote_addr(&self) -> &str { &self.addr }
}

// --- Disconnected: the initial state ---
impl TcpConn<Disconnected> {
    pub fn new(addr: impl Into<String>) -> Self {
        TcpConn { addr: addr.into(), _state: PhantomData }
    }

    /// Consumes the Disconnected connection, returns a Connected one.
    /// Transition: Disconnected -> Connected
    pub fn connect(self) -> Result<TcpConn<Connected>, io::Error> {
        println!("[tcp] Connecting to {}...", self.addr);
        // Real impl: TcpStream::connect(&self.addr)
        Ok(TcpConn { addr: self.addr, _state: PhantomData })
    }
}

// --- Connected: can send/receive or start TLS ---
impl TcpConn<Connected> {
    pub fn send(&mut self, data: &[u8]) -> Result<usize, io::Error> {
        println!("[tcp] Sending {} bytes", data.len());
        Ok(data.len())
    }

    pub fn recv(&mut self, buf: &mut [u8]) -> Result<usize, io::Error> {
        println!("[tcp] Receiving into {} byte buffer", buf.len());
        Ok(0)
    }

    /// Start TLS handshake — transitions to TlsHandshaking.
    /// The Connected state is consumed — you can't send plaintext after starting TLS.
    pub fn start_tls(self) -> TcpConn<TlsHandshaking> {
        println!("[tls] Starting TLS handshake");
        TcpConn { addr: self.addr, _state: PhantomData }
    }

    /// Close the connection cleanly.
    /// Transition: Connected -> Disconnected
    pub fn close(self) -> TcpConn<Disconnected> {
        println!("[tcp] Closing connection to {}", self.addr);
        TcpConn { addr: self.addr, _state: PhantomData }
    }
}

// --- TlsHandshaking: complete handshake to get an Authenticated connection ---
impl TcpConn<TlsHandshaking> {
    /// Complete the TLS handshake.
    /// Transition: TlsHandshaking -> Authenticated
    pub fn finish_handshake(self) -> Result<TcpConn<Authenticated>, io::Error> {
        println!("[tls] Handshake complete");
        Ok(TcpConn { addr: self.addr, _state: PhantomData })
    }

    /// Abort the TLS handshake and fall back to a closed state.
    pub fn abort(self) -> TcpConn<Disconnected> {
        println!("[tls] Handshake aborted");
        TcpConn { addr: self.addr, _state: PhantomData }
    }
}

// --- Authenticated: TLS-encrypted send/receive ---
impl TcpConn<Authenticated> {
    pub fn send_encrypted(&mut self, data: &[u8]) -> Result<usize, io::Error> {
        println!("[tls] Sending {} bytes (encrypted)", data.len());
        Ok(data.len())
    }

    pub fn recv_encrypted(&mut self, buf: &mut [u8]) -> Result<usize, io::Error> {
        println!("[tls] Receiving (encrypted) into {} byte buffer", buf.len());
        Ok(0)
    }

    pub fn close(self) -> TcpConn<Disconnected> {
        println!("[tls] Closing TLS connection to {}", self.addr);
        TcpConn { addr: self.addr, _state: PhantomData }
    }
}

// --- Usage: valid state transitions ---
fn https_request(host: &str, path: &str) -> Result<(), io::Error> {
    // Must connect before sending:
    let disconnected = TcpConn::<Disconnected>::new(format!("{host}:443"));
    let connected = disconnected.connect()?;

    // Must complete TLS before sending encrypted data:
    let handshaking = connected.start_tls();
    let mut authenticated = handshaking.finish_handshake()?;

    // Now we can send/receive:
    let request = format!("GET {path} HTTP/1.1\r\nHost: {host}\r\n\r\n");
    authenticated.send_encrypted(request.as_bytes())?;

    let mut buf = vec![0u8; 4096];
    authenticated.recv_encrypted(&mut buf)?;

    // Clean close:
    let _disconnected = authenticated.close();
    // `authenticated` is moved — cannot use it after close()
    Ok(())
}

fn main() {
    https_request("example.com", "/").unwrap();

    // The following would be COMPILE ERRORS:

    // Cannot send on a disconnected connection:
    // let d = TcpConn::<Disconnected>::new("host:80");
    // d.send(b"hello"); // ERROR: no method `send` on TcpConn<Disconnected>

    // Cannot skip TLS and call send_encrypted on a plain Connected:
    // let conn = TcpConn::<Disconnected>::new("host:443").connect().unwrap();
    // conn.send_encrypted(b"data"); // ERROR: no method on TcpConn<Connected>

    // Cannot use connection after closing:
    // let closed_conn = conn.close();
    // closed_conn.send(b"ghost"); // ERROR: no `send` on TcpConn<Disconnected>

    // Cannot close a connection that's already Disconnected:
    // let d = TcpConn::<Disconnected>::new("host:80");
    // d.close(); // ERROR: no method `close` on TcpConn<Disconnected>
}
```

The typestate pattern in summary:
- State is encoded in the type parameter `S` — there is exactly one valid type for each protocol state.
- Transition methods consume `self` (by value) and return a connection in the new state. The old state ceases to exist at the type level.
- Methods that are invalid in a given state simply don't exist on that `impl` block — the error is "method not found", not a runtime panic.
- `PhantomData<S>` carries the state in the type system with zero runtime cost — the struct has the same layout regardless of `S`.

```rust
// Cargo.toml: rayon = "1.10"

use rayon::prelude::*;
use std::fs::File;
use std::io::{BufWriter, Write};

// --- Mandelbrot computation ---

/// Returns the escape iteration count, or `max_iter` if the point is in the set.
#[inline]
fn mandelbrot(cx: f64, cy: f64, max_iter: u32) -> u32 {
    let (mut x, mut y) = (0.0f64, 0.0f64);
    for i in 0..max_iter {
        let (x2, y2) = (x * x, y * y);
        if x2 + y2 > 4.0 { return i; }
        y = 2.0 * x * y + cy;
        x = x2 - y2 + cx;
    }
    max_iter
}

/// Map iteration count to an RGB color (smooth coloring).
fn iteration_to_color(iter: u32, max_iter: u32) -> [u8; 3] {
    if iter == max_iter { return [0, 0, 0]; } // in set = black
    // Smooth gradient cycling through hues
    let t = iter as f64 / max_iter as f64;
    let r = (9.0 * (1.0 - t) * t * t * t * 255.0) as u8;
    let g = (15.0 * (1.0 - t) * (1.0 - t) * t * t * 255.0) as u8;
    let b = (8.5 * (1.0 - t) * (1.0 - t) * (1.0 - t) * t * 255.0) as u8;
    [r, g, b]
}

struct Viewport {
    width: usize,
    height: usize,
    x_min: f64,
    x_max: f64,
    y_min: f64,
    y_max: f64,
    max_iter: u32,
}

impl Viewport {
    fn pixel_to_complex(&self, px: usize, py: usize) -> (f64, f64) {
        let cx = self.x_min + (px as f64 / self.width as f64) * (self.x_max - self.x_min);
        let cy = self.y_min + (py as f64 / self.height as f64) * (self.y_max - self.y_min);
        (cx, cy)
    }
}

/// Render the Mandelbrot set into an RGB pixel buffer.
/// Uses rayon's par_chunks_mut to parallelize row computation.
fn render(vp: &Viewport) -> Vec<u8> {
    let total_pixels = vp.width * vp.height;
    let mut pixels = vec![0u8; total_pixels * 3]; // RGB

    // Split the pixel buffer into row-sized chunks and process in parallel.
    // Each chunk is exactly one row: width * 3 bytes.
    pixels
        .par_chunks_mut(vp.width * 3)
        .enumerate() // enumerate gives (row_index, &mut [u8])
        .for_each(|(py, row)| {
            for px in 0..vp.width {
                let (cx, cy) = vp.pixel_to_complex(px, py);
                let iter = mandelbrot(cx, cy, vp.max_iter);
                let color = iteration_to_color(iter, vp.max_iter);
                let offset = px * 3;
                row[offset..offset + 3].copy_from_slice(&color);
            }
        });

    pixels
}

/// Write raw RGB data as a PPM P6 file.
fn write_ppm(path: &str, pixels: &[u8], width: usize, height: usize) -> std::io::Result<()> {
    let file = File::create(path)?;
    let mut out = BufWriter::new(file);
    // PPM header
    writeln!(out, "P6")?;
    writeln!(out, "{width} {height}")?;
    writeln!(out, "255")?;
    // Pixel data (raw binary)
    out.write_all(pixels)?;
    Ok(())
}

fn main() {
    use std::time::Instant;

    let vp = Viewport {
        width: 1920,
        height: 1080,
        x_min: -2.5,
        x_max: 1.0,
        y_min: -1.1,
        y_max: 1.1,
        max_iter: 256,
    };

    println!("Rendering {}x{} Mandelbrot set...", vp.width, vp.height);
    let t0 = Instant::now();
    let pixels = render(&vp);
    let elapsed = t0.elapsed();
    println!("Rendered in {elapsed:.2?} using {} threads",
        rayon::current_num_threads());

    write_ppm("mandelbrot.ppm", &pixels, vp.width, vp.height)
        .expect("failed to write PPM");
    println!("Written to mandelbrot.ppm");
    println!("View with: eog mandelbrot.ppm  (or convert to PNG with ImageMagick)");

    // --- Zoomed view: the Seahorse Valley ---
    let zoomed = Viewport {
        width: 1920,
        height: 1080,
        x_min: -0.756,
        x_max: -0.734,
        y_min: 0.099,
        y_max: 0.113,
        max_iter: 1024,
    };

    let t1 = Instant::now();
    let zoomed_pixels = render(&zoomed);
    println!("Zoomed render in {:.2?}", t1.elapsed());
    write_ppm("seahorse.ppm", &zoomed_pixels, zoomed.width, zoomed.height).unwrap();
}
```

Key design decisions:
- `par_chunks_mut(width * 3)` divides the output buffer into row-sized slices and gives each rayon worker thread exclusive mutable access to its row — no locks needed, the disjoint slices are `Send + 'static` within rayon's work-stealing scheduler.
- `.enumerate()` on a parallel iterator works the same as sequential — rayon handles index assignment correctly.
- `BufWriter` wraps the `File` to batch small writes into large ones — critical for PPM output performance since we call `write_all` once for the full pixel array.
- The PPM format is the simplest possible — a plain text header followed by raw RGB bytes. Useful for benchmarking because there's no encode overhead.

