// === A custom mini URL parser to fuzz (self-contained for the example) ===

#[derive(Debug, PartialEq)]
pub struct ParsedUrl {
    pub scheme: String,
    pub host: String,
    pub port: Option<u16>,
    pub path: String,
}

#[derive(Debug)]
pub enum UrlError {
    NoScheme,
    InvalidPort(std::num::ParseIntError),
    Empty,
}

pub fn parse_url(input: &str) -> Result<ParsedUrl, UrlError> {
    if input.is_empty() { return Err(UrlError::Empty); }

    let (scheme, rest) = input.split_once("://").ok_or(UrlError::NoScheme)?;
    let (authority, path) = rest.split_once('/').unwrap_or((rest, ""));

    let (host, port) = if let Some((h, p)) = authority.split_once(':') {
        let port = p.parse::<u16>().map_err(UrlError::InvalidPort)?;
        (h, Some(port))
    } else {
        (authority, None)
    };

    Ok(ParsedUrl {
        scheme: scheme.to_string(),
        host: host.to_string(),
        port,
        path: path.to_string(),
    })
}

// === Properties to check in fuzz tests ===

/// Fuzz-testable harness — structure your real fuzz target similarly
#[cfg(test)]
fn fuzz_harness(data: &[u8]) {
    let Ok(s) = std::str::from_utf8(data) else { return; };

    // Property 1: must never panic
    let result = parse_url(s);

    // Property 2: if parsing succeeds, serialization must work
    if let Ok(ref parsed) = result {
        let reconstructed = format!(
            "{}://{}{}{}",
            parsed.scheme,
            parsed.host,
            parsed.port.map(|p| format!(":{p}")).unwrap_or_default(),
            if parsed.path.is_empty() { String::new() } else { format!("/{}" , parsed.path) }
        );

        // Property 3: re-parsing must give the same result
        let reparsed = parse_url(&reconstructed);
        assert!(reparsed.is_ok(),
            "Round-trip failed\nInput: {s:?}\nReconstructed: {reconstructed:?}");
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // Seed corpus: start with known-valid inputs to guide libFuzzer
    const SEED_CORPUS: &[&[u8]] = &[
        b"http://example.com",
        b"https://host:8080/path",
        b"ftp://user@host/",
        b"://no-scheme",
        b"",
        b"http://host:99999/overflow", // port out of u16 range
        b"http://[::1]:80/ipv6",
    ];

    #[test]
    fn run_seed_corpus() {
        for input in SEED_CORPUS {
            fuzz_harness(input); // must not panic
        }
    }

    #[test]
    fn known_good_cases() {
        let r = parse_url("http://example.com/path").unwrap();
        assert_eq!(r.scheme, "http");
        assert_eq!(r.host, "example.com");
        assert_eq!(r.path, "path");
        assert_eq!(r.port, None);

        let r = parse_url("https://api.example.com:443/v1").unwrap();
        assert_eq!(r.port, Some(443));
    }
}

fn main() {
    // Run the corpus manually for demonstration
    let inputs = [
        "http://example.com",
