// The Orphan Rule:
// You can only implement a trait for a type if EITHER
// (a) the trait is defined in your crate, OR
// (b) the type is defined in your crate.
// You cannot implement a foreign trait for a foreign type.

// --- Scenario 1: Display for Vec<String> ---

// This is ILLEGAL — both Display (std) and Vec (std) are foreign:
// impl std::fmt::Display for Vec<String> { ... }
// ERROR: only traits defined in the current crate can be implemented for
//        types defined outside of the crate

// SOLUTION: newtype wrapper
use std::fmt;

pub struct CommaSeparated(pub Vec<String>);

impl fmt::Display for CommaSeparated {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let mut iter = self.0.iter();
        if let Some(first) = iter.next() {
            write!(f, "{first}")?;
            for item in iter {
                write!(f, ", {item}")?;
            }
        }
        f.write_str("")
    }
}

// Make the newtype transparent: delegate all Vec operations
impl std::ops::Deref for CommaSeparated {
    type Target = Vec<String>;
    fn deref(&self) -> &Self::Target { &self.0 }
}

impl std::ops::DerefMut for CommaSeparated {
    fn deref_mut(&mut self) -> &mut Self::Target { &mut self.0 }
}

impl From<Vec<String>> for CommaSeparated {
    fn from(v: Vec<String>) -> Self { CommaSeparated(v) }
}

// --- Scenario 2: Adding serde::Serialize to an external type ---
// Imagine `ThirdPartyPoint` comes from an external crate:
pub struct ThirdPartyPoint { pub x: f64, pub y: f64 }

// This is ILLEGAL:
// impl serde::Serialize for ThirdPartyPoint { ... } // both are foreign

// SOLUTION: newtype with manual delegation
// (Using a custom Serialize trait for the demo since serde isn't in scope)

pub trait Serialize {
    fn to_json(&self) -> String;
}

pub struct SerializablePoint(pub ThirdPartyPoint);

impl Serialize for SerializablePoint {
    fn to_json(&self) -> String {
        format!("{{\"x\": {}, \"y\": {}}}", self.0.x, self.0.y)
    }
}

impl From<ThirdPartyPoint> for SerializablePoint {
    fn from(p: ThirdPartyPoint) -> Self { SerializablePoint(p) }
}

// --- Scenario 3: Implementing Add between external types ---
// Suppose we want to add nalgebra::Vector3 + cgmath::Vector3
// Both types are foreign — direct Add impl is illegal.
// Newtype one of them:

// Simulated external vector types:
#[derive(Debug, Clone, Copy)]
pub struct LibAVec3 { pub x: f32, pub y: f32, pub z: f32 }

#[derive(Debug, Clone, Copy)]
pub struct LibBVec3 { pub x: f32, pub y: f32, pub z: f32 }

// Wrap LibAVec3 in our newtype, then implement Add<LibBVec3> for it:
pub struct MyVec3(pub LibAVec3);

impl std::ops::Add<LibBVec3> for MyVec3 {
    type Output = LibAVec3;
    fn add(self, rhs: LibBVec3) -> LibAVec3 {
        LibAVec3 {
            x: self.0.x + rhs.x,
            y: self.0.y + rhs.y,
            z: self.0.z + rhs.z,
        }
    }
}

// --- Scenario 4: Blanket impl workaround ---
// You want: for all T: ExternalTrait, implement YourTrait
// This WOULD violate orphan rules in some configurations.
// The fix: add a sealed trait or use a local marker type.

pub trait Printable {
    fn print(&self);
}

// Cannot: impl<T: fmt::Display> Printable for T {} if T is foreign
// Because a downstream crate could add Display to a type and cause conflict.

// SOLUTION: require explicit opt-in via newtype or local wrapper
pub struct Printed<T: fmt::Display>(pub T);

impl<T: fmt::Display> Printable for Printed<T> {
    fn print(&self) { println!("{}", self.0); }
}

// --- The #[repr(transparent)] bonus ---
// When your newtype is repr(transparent), it has the same layout as T.
// This enables safe transmutation between T and Newtype(T) in some cases.

#[repr(transparent)]
pub struct Meters(pub f64);

#[repr(transparent)]
pub struct Kilograms(pub f64);

impl fmt::Display for Meters {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}m", self.0)
    }
}

// Now you can implement any trait you want for Meters/Kilograms,
// including foreign traits, because THESE types are defined in YOUR crate.
use std::ops::{Add, Sub, Mul};

impl Add for Meters {
    type Output = Meters;
    fn add(self, rhs: Meters) -> Meters { Meters(self.0 + rhs.0) }
}

impl Sub for Meters {
    type Output = Meters;
    fn sub(self, rhs: Meters) -> Meters { Meters(self.0 - rhs.0) }
}

impl Mul<f64> for Meters {
    type Output = Meters;
    fn mul(self, rhs: f64) -> Meters { Meters(self.0 * rhs) }
}

fn main() {
    // CommaSeparated Display
    let words: CommaSeparated = vec![
        "rust".to_string(), "python".to_string(), "go".to_string(),
    ].into();
    println!("Languages: {words}"); // rust, python, go
    println!("Count: {}", words.len()); // Deref gives Vec methods

    // Serialize via newtype
    let p = ThirdPartyPoint { x: 1.5, y: 2.5 };
    let sp: SerializablePoint = p.into();
    println!("{}", sp.to_json());

    // Cross-library Add
    let a = MyVec3(LibAVec3 { x: 1.0, y: 2.0, z: 3.0 });
    let b = LibBVec3 { x: 4.0, y: 5.0, z: 6.0 };
    let sum = a + b;
    println!("{sum:?}");

    // Printable via Printed wrapper
    let p = Printed(42);
    p.print();
    let p = Printed("hello");
    p.print();

    // Meters arithmetic
    let d1 = Meters(100.0);
    let d2 = Meters(50.0);
    println!("Sum: {}", d1 + d2);   // 150m
    println!("Diff: {}", d1 - d2);  // 50m
    println!("3x: {}", d1 * 3.0);   // 300m
}
```

Orphan rule summary:
- **Rule**: `impl<T> ForeignTrait for ForeignType` is always illegal.
- **Allowed**: `impl ForeignTrait for LocalType` — your type, their trait.
- **Allowed**: `impl LocalTrait for ForeignType` — your trait, their type.
- **Workaround**: wrap the foreign type in a local newtype. The newtype is yours, so you can implement any trait on it.
- **Cost**: you must re-expose the inner type's API (`Deref`, `From`, `Into`, delegate methods).
- **`#[repr(transparent)]`**: ensures the newtype has identical layout to the inner type — safe casting between them in FFI or unsafe code.

