use anyhow::{Context, Result as AnyResult};

fn main_anyhow() -> AnyResult<()> {
    let p = std::path::Path::new("/etc/app/config.toml");
    let content = std::fs::read_to_string(p)
        .with_context(|| format!("reading config at {}", p.display()))?;
    println!("Config: {}", content.len());
    Ok(())
}

fn main() {
    let p = std::path::Path::new("/nonexistent");
    match run(p) {
        Ok(()) => println!("ok"),
        Err(AppError::Config(ConfigError::ReadFailed { path, source })) =>
            eprintln!("read failed {}: {source}", path.display()),
        Err(e) => eprintln!("{e}"),
    }

    if let Err(e) = main_anyhow() {
        eprintln!("{e:#}"); // {:#} prints full cause chain
    }
}
