Guidelines: use `thiserror` for library error types (explicit, matchable). Use `anyhow` in binaries/applications (rich context, easy `?`). `#[from]` generates `From<SourceError>` automatically. `#[source]` exposes the inner error via `std::error::Error::source()`. `.with_context()` stacks human-readable messages while preserving the cause chain.

```rust
#[derive(Debug, Clone, PartialEq)]
enum Token { Num(f64), Plus, Minus, Star, Slash, LParen, RParen }

#[derive(Debug)]
enum ParseError {
    UnexpectedChar(char),
    UnexpectedToken { expected: &'static str, got: Option<Token> },
    DivisionByZero,
}

impl std::fmt::Display for ParseError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::UnexpectedChar(c)              => write!(f, "bad char: {c:?}"),
            Self::UnexpectedToken { expected, got } => write!(f, "expected {expected}, got {got:?}"),
            Self::DivisionByZero                 => write!(f, "division by zero"),
        }
    }
}

fn tokenize(input: &str) -> Result<Vec<Token>, ParseError> {
    let mut tokens = Vec::new();
    let mut chars = input.chars().peekable();
    while let Some(&ch) = chars.peek() {
        match ch {
            ' ' | '\t' => { chars.next(); }
            '0'..='9' | '.' => {
                let mut s = String::new();
                while matches!(chars.peek(), Some('0'..='9' | '.')) { s.push(chars.next().unwrap()); }
                tokens.push(Token::Num(s.parse().map_err(|_| ParseError::UnexpectedChar(ch))?));
            }
            '+' => { tokens.push(Token::Plus);   chars.next(); }
            '-' => { tokens.push(Token::Minus);  chars.next(); }
            '*' => { tokens.push(Token::Star);   chars.next(); }
            '/' => { tokens.push(Token::Slash);  chars.next(); }
            '(' => { tokens.push(Token::LParen); chars.next(); }
            ')' => { tokens.push(Token::RParen); chars.next(); }
            c   => return Err(ParseError::UnexpectedChar(c)),
        }
    }
    Ok(tokens)
}

struct Parser { tokens: Vec<Token>, pos: usize }

impl Parser {
    fn new(t: Vec<Token>) -> Self { Parser { tokens: t, pos: 0 } }
    fn peek(&self) -> Option<&Token> { self.tokens.get(self.pos) }
    fn advance(&mut self) -> Option<Token> {
        if self.pos < self.tokens.len() {
            let t = self.tokens[self.pos].clone();
            self.pos += 1;
            Some(t)
        } else { None }
    }

    // expr := term (('+' | '-') term)*
    fn expr(&mut self) -> Result<f64, ParseError> {
        let mut v = self.term()?;
        loop {
            match self.peek() {
                Some(Token::Plus)  => { self.advance(); v += self.term()?; }
                Some(Token::Minus) => { self.advance(); v -= self.term()?; }
                _ => break,
            }
        }
        Ok(v)
    }

    // term := factor (('*' | '/') factor)*
    fn term(&mut self) -> Result<f64, ParseError> {
        let mut v = self.factor()?;
        loop {
            match self.peek() {
                Some(Token::Star)  => { self.advance(); v *= self.factor()?; }
                Some(Token::Slash) => {
                    self.advance();
                    let r = self.factor()?;
                    if r == 0.0 { return Err(ParseError::DivisionByZero); }
                    v /= r;
                }
                _ => break,
            }
        }
        Ok(v)
    }

    // factor := NUM | '(' expr ')' | '-' factor
    fn factor(&mut self) -> Result<f64, ParseError> {
        match self.peek().cloned() {
            Some(Token::Num(n)) => { self.advance(); Ok(n) }
            Some(Token::LParen) => {
                self.advance();
                let v = self.expr()?;
                match self.advance() {
                    Some(Token::RParen) => Ok(v),
                    got => Err(ParseError::UnexpectedToken { expected: ")", got }),
                }
            }
            Some(Token::Minus) => { self.advance(); Ok(-self.factor()?) }
            got => Err(ParseError::UnexpectedToken { expected: "number or '('", got }),
        }
    }
}

pub fn evaluate(input: &str) -> Result<f64, ParseError> {
    let mut parser = Parser::new(tokenize(input)?);
    let result = parser.expr()?;
    if parser.peek().is_some() {
        return Err(ParseError::UnexpectedToken { expected: "end of input", got: parser.peek().cloned() });
    }
    Ok(result)
}

fn main() {
    let cases = [
        ("2 + 3",          5.0),
        ("10 - 3 * 2",     4.0),
        ("(10 - 3) * 2",  14.0),
        ("100 / (2 + 3)", 20.0),
        ("-5 + 3",         -2.0),
    ];
    for (expr, expected) in cases {
        let r = evaluate(expr).unwrap();
        println!("{expr} = {r} {}", if (r - expected).abs() < 1e-10 { "OK" } else { "FAIL" });
    }
    for bad in ["2/0", "abc", "(1+2"] {
        println!("{bad:?} => {:?}", evaluate(bad));
    }
}
```

Each grammar rule maps to one method. `peek()` reads without consuming; `advance()` consumes. Operator precedence falls out from the call hierarchy: `expr` calls `term` calls `factor`. The `while` loop in `expr`/`term` gives left-associativity.

