use std::time::SystemTime;

#[derive(Debug, Clone)]
pub enum Download {
    Pending { url: String },
    Downloading { url: String, started: SystemTime, bytes_done: u64, total: u64 },
    Paused { url: String, bytes_done: u64, total: u64, reason: String },
    Completed { url: String, total: u64, path: String, secs: f64 },
    Failed { url: String, bytes_done: u64, error: String },
}

#[derive(Debug)] pub struct BadTransition(&'static str);

impl Download {
    pub fn start(self, total: u64) -> Result<Self, BadTransition> {
        match self {
            Download::Pending { url } => Ok(Download::Downloading {
                url, started: SystemTime::now(), bytes_done: 0, total,
            }),
            _ => Err(BadTransition("only Pending can start")),
        }
    }

    pub fn progress(self, new_bytes: u64) -> Result<Self, BadTransition> {
        match self {
            Download::Downloading { url, started, bytes_done, total } =>
                Ok(Download::Downloading { url, started, bytes_done: (bytes_done + new_bytes).min(total), total }),
            _ => Err(BadTransition("only Downloading can progress")),
        }
    }

    pub fn pause(self, reason: impl Into<String>) -> Result<Self, BadTransition> {
        match self {
            Download::Downloading { url, bytes_done, total, .. } =>
                Ok(Download::Paused { url, bytes_done, total, reason: reason.into() }),
            _ => Err(BadTransition("only Downloading can be paused")),
        }
    }

    pub fn resume(self) -> Result<Self, BadTransition> {
        match self {
            Download::Paused { url, bytes_done, total, .. } =>
                Ok(Download::Downloading { url, started: SystemTime::now(), bytes_done, total }),
            _ => Err(BadTransition("only Paused can resume")),
        }
    }

    pub fn complete(self, path: impl Into<String>) -> Result<Self, BadTransition> {
        match self {
            Download::Downloading { url, started, total, .. } =>
                Ok(Download::Completed {
                    url, total, path: path.into(),
                    secs: started.elapsed().unwrap_or_default().as_secs_f64(),
                }),
            _ => Err(BadTransition("only Downloading can complete")),
        }
    }

    pub fn fail(self, error: impl Into<String>) -> Result<Self, BadTransition> {
        let (url, bytes_done) = match &self {
            Download::Pending { url }                        => (url.clone(), 0),
            Download::Downloading { url, bytes_done, .. }   => (url.clone(), *bytes_done),
            Download::Paused { url, bytes_done, .. }         => (url.clone(), *bytes_done),
            _ => return Err(BadTransition("terminal state cannot fail")),
        };
        Ok(Download::Failed { url, bytes_done, error: error.into() })
    }

    pub fn progress_pct(&self) -> Option<f64> {
        match self {
            Download::Downloading { bytes_done, total, .. } |
            Download::Paused { bytes_done, total, .. } if *total > 0 =>
                Some(*bytes_done as f64 / *total as f64 * 100.0),
            _ => None,
        }
    }

    pub fn is_terminal(&self) -> bool {
        matches!(self, Download::Completed { .. } | Download::Failed { .. })
    }
}

fn main() {
    let dl = Download::Pending { url: "https://example.com/file.zip".into() };
    let dl = dl.start(1_000_000).unwrap();
    let dl = dl.progress(250_000).unwrap();
    println!("Progress: {:.1}%", dl.progress_pct().unwrap());
    let dl = dl.pause("user paused").unwrap();
    let dl = dl.resume().unwrap();
    let dl = dl.progress(750_000).unwrap();
    let dl = dl.complete("/tmp/file.zip").unwrap();
    println!("{dl:?}");
    assert!(dl.is_terminal());

    // Invalid transition produces a descriptive error
    let bad = Download::Pending { url: "x".into() }.complete("/tmp/x");
    println!("Invalid: {:?}", bad.unwrap_err());
}
```

Each transition method consumes `self` (by value) and returns `Result<Self, BadTransition>`. The old state ceases to exist at the call site -- no dangling handle. Pattern matching on enum variants with data extracts progress counters, start times, etc. without extra `Option` fields.

```rust
// --- 1. Elision rules ---

// Rule 1: each input &T gets its own implicit lifetime
// fn first<'a>(s: &'a str) -> &'a str  (one input -> output inherits it)
fn first_word(s: &str) -> &str {
    s.split_whitespace().next().unwrap_or("")
}

// Rule 2 (method): if first param is &self, output borrows from self
struct Buf(String);
impl Buf {
    fn contents(&self) -> &str { &self.0 }
    // Multiple &inputs: compiler cannot elide; must be explicit:
    fn longest<'a>(&'a self, other: &'a str) -> &'a str {
        if self.0.len() >= other.len() { &self.0 } else { other }
    }
}

// --- 2. Lifetimes in structs: two independent lifetimes ---

pub struct StrSplit<'hay, 'delim> {
    haystack: &'hay str,
    delimiter: &'delim str,
    pos: usize,
}

impl<'hay, 'delim> StrSplit<'hay, 'delim> {
    pub fn new(haystack: &'hay str, delimiter: &'delim str) -> Self {
        StrSplit { haystack, delimiter, pos: 0 }
    }
}

impl<'hay, 'delim> Iterator for StrSplit<'hay, 'delim> {
    type Item = &'hay str; // yields slices from haystack, not delimiter

    fn next(&mut self) -> Option<Self::Item> {
        let rest = &self.haystack[self.pos..];
        if rest.is_empty() { return None; }
        if let Some(i) = rest.find(self.delimiter) {
            let part = &rest[..i];
            self.pos += i + self.delimiter.len();
            Some(part)
        } else {
            self.pos = self.haystack.len();
            Some(rest)
        }
    }
}

// --- 3. Lifetime bounds on generics: T: 'a ---
// T: 'a means T does not contain references shorter than 'a.
struct Cache<'a, T: 'a> { key: &'a str, value: T }

impl<'a, T: std::fmt::Debug + 'a> Cache<'a, T> {
    fn new(key: &'a str, value: T) -> Self { Cache { key, value } }
    fn show(&self) { println!("{}={:?}", self.key, self.value); }
}

// 'long: 'short means 'long outlives 'short (covariant lifetime subtyping)
fn shorten<'long, 'short>(s: &'long str) -> &'short str where 'long: 'short {
    &s[..s.len().min(3)]
}

// --- 4. Higher-Ranked Trait Bounds (HRTBs) ---
// for<'a> Fn(&'a T): "this function works for ANY lifetime 'a chosen by the caller"

// Without HRTB: lifetime is fixed at definition site (too restrictive)
fn apply_specific<'a, T, R>(data: &'a T, f: impl Fn(&'a T) -> R) -> R { f(data) }

// With HRTB: lifetime is chosen fresh at each call site
fn apply_any<T, R>(data: &T, f: impl for<'a> Fn(&'a T) -> R) -> R { f(data) }

// Practical: storing a parser that works on any borrow of a string
pub struct Parser<F: for<'i> Fn(&'i str) -> Option<(&'i str, i64)>> {
    parse_fn: F,
}

impl<F: for<'i> Fn(&'i str) -> Option<(&'i str, i64)>> Parser<F> {
    pub fn new(f: F) -> Self { Parser { parse_fn: f } }
    pub fn parse<'i>(&self, input: &'i str) -> Option<(&'i str, i64)> {
        (self.parse_fn)(input)
    }
}

fn parse_int(input: &str) -> Option<(&str, i64)> {
    let end = input.find(|c: char| !c.is_ascii_digit() && c != '-').unwrap_or(input.len());
    let n = input[..end].parse::<i64>().ok()?;
    Some((&input[end..], n))
}

fn main() {
    println!("{}", first_word("hello world"));

    let parts: Vec<_> = StrSplit::new("a,b,c", ",").collect();
    println!("{parts:?}");

    // Delimiter shorter-lived than haystack -- compiles because lifetimes are separate
    let result: Vec<_> = {
        let delim = String::from("-");
        StrSplit::new("x-y-z", &delim).collect()
    };
    println!("{result:?}");

    Cache::new("x", vec![1, 2, 3]).show();

    let parser = Parser::new(parse_int);
    if let Some((rest, n)) = parser.parse("42 remaining") {
        println!("parsed {n}, rest={rest:?}");
    }

    let s = String::from("hello");
    let len = apply_any(&s, |r: &String| r.len());
    println!("len={len}");
}
```

Lifetime cheat sheet: `T: 'a` means T's references all outlive `'a`. `'long: 'short` means `'long` outlives `'short`. `for<'a> Fn(&'a T)` is a HRTB -- the lifetime is quantified universally, chosen fresh by the caller rather than fixed at the closure definition site.

```rust
// Cargo.toml: nom = "7"
use nom::{
    bytes::complete::{tag, take},
    number::complete::{be_u8, be_u16, be_u32},
    combinator::{verify, map_res},
    IResult,
    error::{Error, ErrorKind},
};

// Packet layout (big-endian):
//   [0..2]   magic:   0xCAFE
//   [2]      version: u8  (must be 1)
//   [3]      type:    u8  (0=Ping 1=Data 2=Ack)
//   [4..6]   length:  u16 (payload bytes)
//   [6..6+L] payload: [u8; length]
//   [N..N+4] crc32:   u32

const MAGIC: &[u8] = &[0xCA, 0xFE];

#[derive(Debug, PartialEq, Clone, Copy)]
pub enum PktType { Ping, Data, Ack }

#[derive(Debug, PartialEq)]
pub struct Packet<'a> {
    pub version: u8,
    pub pkt_type: PktType,
    pub payload: &'a [u8],  // zero-copy slice into input buffer
    pub crc: u32,
}

fn checksum(data: &[u8]) -> u32 {
    data.iter().fold(0u32, |a, &b| a.wrapping_add(b as u32))
}

fn parse_pkt_type(input: &[u8]) -> IResult<&[u8], PktType> {
    map_res(be_u8, |b| match b {
        0 => Ok(PktType::Ping),
        1 => Ok(PktType::Data),
        2 => Ok(PktType::Ack),
        _ => Err(()),
    })(input)
}

pub fn parse_packet(orig: &[u8]) -> IResult<&[u8], Packet<'_>> {
    let (input, _)        = tag(MAGIC)(orig)?;
    let (input, version)  = verify(be_u8, |&v| v == 1)(input)?;
    let (input, pkt_type) = parse_pkt_type(input)?;
    let (input, length)   = be_u16(input)?;
    let (input, payload)  = take(length as usize)(input)?;
    let (input, crc)      = be_u32(input)?;

    // Validate checksum over magic+version+type+length+payload (first 6 + length bytes)
    let covered_len = 6 + length as usize;
    if checksum(&orig[..covered_len]) != crc {
        return Err(nom::Err::Error(Error::new(input, ErrorKind::Verify)));
    }

    Ok((input, Packet { version, pkt_type, payload, crc }))
}

fn build_packet(ptype: u8, payload: &[u8]) -> Vec<u8> {
    let mut p = vec![0xCA, 0xFE, 1, ptype,
                     (payload.len() >> 8) as u8, (payload.len() & 0xFF) as u8];
    p.extend_from_slice(payload);
    let crc = checksum(&p);
    p.extend_from_slice(&crc.to_be_bytes());
    p
}

fn main() {
    let raw = build_packet(1, b"hello, zero-copy!");
    match parse_packet(&raw) {
        Ok((rest, pkt)) => {
            println!("{pkt:?}");
            println!("payload: {:?}", std::str::from_utf8(pkt.payload).unwrap());
            println!("remaining: {} bytes", rest.len());
            // pkt.payload is a slice INTO raw -- no allocation
            assert!(std::ptr::eq(pkt.payload.as_ptr(), raw[6..].as_ptr()));
        }
        Err(e) => eprintln!("parse error: {e:?}"),
    }

    // Bad checksum
    let mut corrupt = build_packet(2, b"ack");
    *corrupt.last_mut().unwrap() ^= 0xFF;
    assert!(parse_packet(&corrupt).is_err());
    println!("corrupted packet correctly rejected");
}
```

Zero-copy mechanics: `take(n)` returns a `&[u8]` slice into the original buffer -- no copy. The `Packet<'a>` lifetime ties `payload` to the input buffer. `IResult<&[u8], T>` threads remaining bytes through each parser step. Use `nom::streaming::` variants instead of `nom::complete::` when parsing data arriving in chunks (they return `Err::Incomplete` instead of `Err::Error` when more bytes are needed).

```rust
use std::panic::{catch_unwind, AssertUnwindSafe};
use std::sync::{Arc, Mutex};

// --- 1. Basic catch_unwind ---

fn might_panic(x: i32) -> i32 {
    if x == 0 { panic!("division by zero!"); }
    100 / x
}

fn safe_call(x: i32) -> Result<i32, String> {
    catch_unwind(|| might_panic(x)).map_err(|e| {
        if let Some(s) = e.downcast_ref::<&str>() { s.to_string() }
        else if let Some(s) = e.downcast_ref::<String>() { s.clone() }
        else { "unknown panic".into() }
    })
}

// --- 2. FFI boundary: panicking into C is UB ---
#[no_mangle]
pub extern "C" fn safe_compute(x: i32) -> i32 {
    catch_unwind(|| might_panic(x)).unwrap_or(-1)
}

// --- 3. Thread pool: catch to avoid killing the worker ---
fn worker(rx: std::sync::mpsc::Receiver<Box<dyn FnOnce() + Send>>) {
    for job in rx {
        if let Err(e) = catch_unwind(AssertUnwindSafe(job)) {
            eprintln!("job panicked: {:?}", e.downcast_ref::<&str>());
            // worker continues
        }
    }
}

// --- 4. AssertUnwindSafe for non-UnwindSafe types ---
fn with_mut_ref() {
    let mut data = vec![1, 2, 3];
    // &mut T is not UnwindSafe; wrap it to tell the compiler we handle invariants
    let result = catch_unwind(AssertUnwindSafe(|| {
        data.push(4);
        // if we panic here, caller is responsible for auditing the state
    }));
    println!("result: {result:?}, data: {data:?}");
}

// --- 5. Mutex poisoning ---
fn poison_demo() {
    let data = Arc::new(Mutex::new(vec![1, 2, 3]));
    let d2 = Arc::clone(&data);

    let handle = std::thread::spawn(move || {
        let _guard = d2.lock().unwrap();
        panic!("panic while holding the lock");
    });
    let _ = handle.join();

    match data.lock() {
        Ok(v) => println!("ok: {v:?}"),
        Err(poison) => {
            println!("poisoned -- recovering");
            let v = poison.into_inner(); // recover the data
            println!("recovered: {v:?}");
            data.clear_poison(); // future lock() calls return Ok
        }
    }
    println!("after clear: {:?}", data.lock().unwrap());
}

fn main() {
    println!("{:?}", safe_call(5));  // Ok(20)
    println!("{:?}", safe_call(0));  // Err("division by zero!")
    with_mut_ref();
    poison_demo();
}
```

Rules: never use `catch_unwind` for control flow (use `Result`). Always wrap `extern "C"` functions in `catch_unwind` -- panicking across FFI is undefined behavior. `AssertUnwindSafe` is a promise that your invariants survive partial writes. A poisoned `Mutex` is recovered via `PoisonError::into_inner()`; call `clear_poison()` to restore normal `lock()` semantics.

```rust
const A: usize = 26; // lowercase ASCII only

#[derive(Clone)]
struct Node {
    children: [u32; A], // u32::MAX = absent (saves vs Option<usize>)
    is_word: bool,
    freq: u32,
}

impl Node {
    fn new() -> Self { Node { children: [u32::MAX; A], is_word: false, freq: 0 } }
}

pub struct Trie { nodes: Vec<Node> }

impl Trie {
    pub fn new() -> Self { Trie { nodes: vec![Node::new()] } }

    fn idx(c: char) -> Option<usize> {
        if c.is_ascii_lowercase() { Some((c as u8 - b'a') as usize) } else { None }
    }

    fn alloc(&mut self) -> u32 {
        let i = self.nodes.len() as u32;
        self.nodes.push(Node::new());
        i
    }

    pub fn insert(&mut self, word: &str) {
        let mut cur = 0usize;
        for c in word.chars() {
            let i = Self::idx(c).expect("non-lowercase char");
            if self.nodes[cur].children[i] == u32::MAX {
                let n = self.alloc();
                self.nodes[cur].children[i] = n;
            }
            cur = self.nodes[cur].children[i] as usize;
        }
        self.nodes[cur].is_word = true;
        self.nodes[cur].freq += 1;
    }

    fn traverse(&self, prefix: &str) -> Option<usize> {
        let mut cur = 0usize;
        for c in prefix.chars() {
            let next = self.nodes[cur].children[Self::idx(c)?];
            if next == u32::MAX { return None; }
            cur = next as usize;
        }
        Some(cur)
    }

    pub fn contains(&self, word: &str) -> bool {
        self.traverse(word).map(|n| self.nodes[n].is_word).unwrap_or(false)
    }

    pub fn starts_with(&self, prefix: &str) -> bool {
        self.traverse(prefix).is_some()
    }

    /// Return up to `limit` completions for `prefix`, sorted by freq desc.
    pub fn autocomplete(&self, prefix: &str, limit: usize) -> Vec<(String, u32)> {
        let Some(start) = self.traverse(prefix) else { return vec![]; };
        let mut results = Vec::new();
        let mut stack = vec![(start, prefix.to_string())];
        while let Some((idx, pfx)) = stack.pop() {
            let node = &self.nodes[idx];
            if node.is_word { results.push((pfx.clone(), node.freq)); }
            for ci in (0..A).rev() {
                let child = node.children[ci];
                if child != u32::MAX {
                    let mut next = pfx.clone();
                    next.push((b'a' + ci as u8) as char);
                    stack.push((child as usize, next));
                }
            }
        }
        results.sort_by(|a, b| b.1.cmp(&a.1).then(a.0.cmp(&b.0)));
        results.truncate(limit);
        results
    }

    pub fn node_count(&self) -> usize { self.nodes.len() }
    pub fn memory_bytes(&self) -> usize { self.nodes.len() * std::mem::size_of::<Node>() }
}

fn main() {
    let mut t = Trie::new();
    for w in ["rust", "rusty", "rusted", "rustacean", "run", "runner", "ruby"] {
        t.insert(w);
    }
    for _ in 0..5 { t.insert("rust"); }
    for _ in 0..3 { t.insert("runner"); }

    println!("nodes={}, memory={} bytes", t.node_count(), t.memory_bytes());
    println!("contains 'rust': {}", t.contains("rust"));
    println!("contains 'rus': {}", t.contains("rus"));
    println!("starts_with 'rus': {}", t.starts_with("rus"));

    println!("autocomplete 'ru':");
    for (w, f) in t.autocomplete("ru", 5) { println!("  {w} (freq={f})"); }
}
```

Memory layout: `[u32; 26]` children use 104 bytes/node with `u32::MAX` as sentinel (saves vs `Option<u32>` which adds a discriminant byte). Arena allocation (all nodes in `Vec<Node>`) avoids per-node `Box` overhead and is cache-friendly for DFS traversal. For Unicode keys use `HashMap<char, u32>` children instead.

```rust
use std::ops::{Add, Sub, Mul, Div};
use std::marker::PhantomData;

// A physical quantity parameterized on dimension exponents (M, S, KG).
// Quantity<1,0,0> = meters, Quantity<0,1,0> = seconds, etc.
#[derive(Clone, Copy)]
pub struct Q<const M: i8, const S: i8, const KG: i8>(pub f64);

impl<const M: i8, const S: i8, const KG: i8> std::fmt::Debug for Q<M,S,KG> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{} [m^{M} s^{S} kg^{KG}]", self.0)
    }
}

// Type aliases
pub type Length       = Q<1, 0, 0>;
pub type Time         = Q<0, 1, 0>;
pub type Mass         = Q<0, 0, 1>;
pub type Velocity     = Q<1,-1, 0>;
pub type Acceleration = Q<1,-2, 0>;
pub type Force        = Q<1,-2, 1>;
pub type Energy       = Q<2,-2, 1>;

// Constructors
pub fn meters(v: f64) -> Length { Q(v) }
pub fn seconds(v: f64) -> Time  { Q(v) }
pub fn kg(v: f64) -> Mass       { Q(v) }

// Add/Sub: only same dimensions compile
impl<const M: i8, const S: i8, const KG: i8> Add for Q<M,S,KG> {
    type Output = Self; fn add(self, r: Self) -> Self { Q(self.0 + r.0) }
}
impl<const M: i8, const S: i8, const KG: i8> Sub for Q<M,S,KG> {
    type Output = Self; fn sub(self, r: Self) -> Self { Q(self.0 - r.0) }
}

// Scalar scaling
impl<const M: i8, const S: i8, const KG: i8> Mul<f64> for Q<M,S,KG> {
    type Output = Self; fn mul(self, r: f64) -> Self { Q(self.0 * r) }
}

// Specific cross-dimension ops (stable Rust -- no generic_const_exprs needed)
impl Div<Time> for Length {
    type Output = Velocity; fn div(self, r: Time) -> Velocity { Q(self.0 / r.0) }
}
impl Div<Time> for Velocity {
    type Output = Acceleration; fn div(self, r: Time) -> Acceleration { Q(self.0 / r.0) }
}
impl Mul<Acceleration> for Mass {
    type Output = Force; fn mul(self, r: Acceleration) -> Force { Q(self.0 * r.0) }
}
impl Mul<Length> for Force {
    type Output = Energy; fn mul(self, r: Length) -> Energy { Q(self.0 * r.0) }
}

fn main() {
    let d = meters(100.0);
    let t = seconds(10.0);
    let v = d / t;                     // Length/Time = Velocity (compile-time)
    let a = v / seconds(5.0);          // Velocity/Time = Acceleration
    let f = kg(70.0) * a;             // Mass*Acceleration = Force
    let e = f * meters(2.0);           // Force*Length = Energy

    println!("{:?}", v); // [m^1 s^-1 kg^0]
    println!("{:?}", f); // [m^1 s^-2 kg^1]
    println!("{:?}", e); // [m^2 s^-2 kg^1]

    // Adding same dimensions works
    let total = meters(50.0) + meters(30.0);
    println!("{:?}", total);

    // COMPILE ERROR (uncomment to verify):
    // let _ = meters(1.0) + seconds(1.0); // Q<1,0,0> != Q<0,1,0>
    // let _ = kg(5.0) + meters(3.0);

    // Extract raw value for dimensionless ops
    let ratio = meters(200.0).0 / meters(100.0).0;
    println!("ratio={ratio}");
}
```

Zero runtime cost: `Q<M,S,KG>` is `#[repr(transparent)]` over `f64` implicitly (single field). The type parameters are erased after monomorphization. Dimension checking happens entirely at compile time -- a type mismatch is "mismatched types" not a runtime panic. On nightly with `#![feature(generic_const_exprs)]` you can implement fully generic `Mul<Q<M2,S2,KG2>>` that adds exponents.

