// Cargo.toml: crossbeam = "0.8"
use crossbeam::channel::{self, Receiver, Sender, bounded};
use std::thread;
use std::time::Duration;

type Job = Box<dyn FnOnce() -> Result<String, String> + Send + 'static>;

struct WorkQueue {
    sender: Sender<Job>,
    result_rx: Receiver<Result<String, String>>,
    workers: Vec<thread::JoinHandle<()>>,
}

impl WorkQueue {
    fn new(n_workers: usize, queue_cap: usize) -> Self {
        let (job_tx, job_rx) = bounded::<Job>(queue_cap);
        let (res_tx, res_rx) = bounded::<Result<String, String>>(queue_cap * 2);

        let workers = (0..n_workers).map(|id| {
            let job_rx = job_rx.clone();
            let res_tx = res_tx.clone();
            thread::Builder::new()
                .name(format!("worker-{id}"))
                .spawn(move || {
                    for job in &job_rx {
                        let outcome = std::panic::catch_unwind(
                            std::panic::AssertUnwindSafe(job)
                        );
                        let result = match outcome {
                            Ok(r) => r,
                            Err(e) => Err(format!("worker panicked: {:?}",
                                e.downcast_ref::<&str>())),
                        };
                        if res_tx.send(result).is_err() { break; }
                    }
                })
                .expect("spawn failed")
        }).collect();

        WorkQueue { sender: job_tx, result_rx: res_rx, workers }
    }

    fn submit<F>(&self, f: F) -> Result<(), ()>
    where F: FnOnce() -> Result<String, String> + Send + 'static
    {
        self.sender.send(Box::new(f)).map_err(|_| ())
    }

    fn collect(&self, n: usize) -> Vec<Result<String, String>> {
        (0..n).map(|_| self.result_rx.recv().unwrap()).collect()
    }

    fn shutdown(self) {
        drop(self.sender); // signals workers: channel closed
        for w in self.workers { let _ = w.join(); }
    }
}

fn main() {
    let queue = WorkQueue::new(4, 16);

    // Submit 10 jobs, some panicking
    let n_jobs = 10;
    for i in 0..n_jobs {
        queue.submit(move || {
            thread::sleep(Duration::from_millis(10));
            if i == 3 {
                panic!("simulated panic in job {i}");
            }
            if i == 7 {
                return Err(format!("job {i} failed: bad data"));
            }
            Ok(format!("job {i} done on {:?}", thread::current().name()))
        }).expect("queue full");
    }

    let results = queue.collect(n_jobs);
    for (i, r) in results.iter().enumerate() {
        match r {
            Ok(s)  => println!("[{i}] OK: {s}"),
            Err(e) => println!("[{i}] ERR: {e}"),
        }
    }

    let successes = results.iter().filter(|r| r.is_ok()).count();
    println!("\n{successes}/{n_jobs} jobs succeeded");

    queue.shutdown();
}
```

Design: bounded `job_tx` applies backpressure -- `submit()` blocks when the queue is full, preventing unbounded memory growth. `catch_unwind` in each worker converts panics to `Err` so the worker stays alive. Dropping `sender` closes the channel, signalling workers to exit their `for job in &job_rx` loop cleanly. The result channel is also bounded to prevent result accumulation from starving the job channel.

```rust
use std::time::{Duration, Instant};
use std::thread;

/// Configuration for retry behavior.
pub struct RetryConfig {
    pub max_attempts: u32,
    pub base_delay: Duration,
    pub max_delay: Duration,
    pub jitter: bool,
}

impl Default for RetryConfig {
    fn default() -> Self {
        RetryConfig {
            max_attempts: 3,
            base_delay: Duration::from_millis(100),
            max_delay: Duration::from_secs(30),
            jitter: true,
        }
    }
}

fn jitter_factor(seed: u64) -> f64 {
    // Simple LCG for deterministic-ish jitter without external crates
    let x = seed.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
    (x >> 33) as f64 / u32::MAX as f64 // in [0, 1)
}

/// Retry `f` up to `config.max_attempts` times with exponential backoff.
/// Returns Ok on first success, Err of the last failure otherwise.
pub fn retry<T, E, F>(config: &RetryConfig, mut f: F) -> Result<T, E>
where
    F: FnMut(u32) -> Result<T, E>,
    E: std::fmt::Debug,
{
    let mut last_err = None;
    for attempt in 0..config.max_attempts {
        match f(attempt) {
            Ok(v) => return Ok(v),
            Err(e) => {
                if attempt + 1 == config.max_attempts { last_err = Some(e); break; }

                // Exponential backoff: base * 2^attempt
                let delay_ms = config.base_delay.as_millis() as u64 * (1u64 << attempt);
                let delay_ms = delay_ms.min(config.max_delay.as_millis() as u64);

                let actual_ms = if config.jitter {
                    let seed = Instant::now().elapsed().subsec_nanos() as u64 + attempt as u64;
                    let factor = 0.5 + jitter_factor(seed) * 0.5; // in [0.5, 1.0)
                    (delay_ms as f64 * factor) as u64
                } else {
                    delay_ms
                };

                eprintln!("[retry] attempt {} failed: {e:?}; waiting {}ms", attempt + 1, actual_ms);
                thread::sleep(Duration::from_millis(actual_ms));
                last_err = Some(e);
            }
        }
    }
    Err(last_err.unwrap())
}

/// Run `f` with a wall-clock timeout.
/// Returns Err("timeout") if the deadline is exceeded.
pub fn with_timeout<T, E: From<&'static str>>(
    timeout: Duration,
    f: impl FnOnce() -> Result<T, E> + Send + 'static,
) -> Result<T, E>
where
    T: Send + 'static,
    E: Send + 'static,
{
    let (tx, rx) = std::sync::mpsc::channel();
    thread::spawn(move || { let _ = tx.send(f()); });
    rx.recv_timeout(timeout).unwrap_or(Err("timeout".into()))
}

// --- Demo: flaky operation ---

fn flaky_connect(attempt: u32) -> Result<String, String> {
    // Succeeds on attempt >= 2
    if attempt < 2 {
        Err(format!("connection refused (attempt {})", attempt + 1))
    } else {
        Ok(format!("connected on attempt {}", attempt + 1))
    }
}

fn always_slow() -> Result<i32, &'static str> {
    thread::sleep(Duration::from_secs(10));
    Ok(42)
}

fn main() {
    // Basic retry
    let config = RetryConfig {
        max_attempts: 4,
        base_delay: Duration::from_millis(50),
        max_delay: Duration::from_secs(5),
        jitter: false,
    };
    match retry(&config, flaky_connect) {
        Ok(msg) => println!("Success: {msg}"),
        Err(e)  => println!("Failed: {e}"),
    }

    // Retry with timeout: give up after 500ms total
    let start = Instant::now();
    let result: Result<String, String> = with_timeout(
        Duration::from_millis(500),
        || {
            let cfg = RetryConfig { max_attempts: 10, base_delay: Duration::from_millis(200), ..Default::default() };
            retry(&cfg, |a| {
                if a < 5 { Err(format!("fail {a}")) } else { Ok("done".into()) }
            })
        },
    );
    println!("timeout result: {:?} in {:?}", result, start.elapsed());

    // Always-slow operation times out
    let r: Result<i32, &'static str> = with_timeout(Duration::from_millis(50), always_slow);
    println!("slow result: {r:?}");
}
```

Exponential backoff formula: `delay = base * 2^attempt`, capped at `max_delay`. Full jitter (`delay * random[0.5, 1.0)`) reduces thundering-herd problems when many clients retry simultaneously. The `with_timeout` function uses `mpsc::recv_timeout` to impose a deadline; the spawned thread may continue running (no cancel mechanism in std -- for true cancellation use a `AtomicBool` flag or async).

