use std::marker::PhantomData;

// Phantom state markers (zero-sized, uninhabited)
pub enum Open {}
pub enum Closed {}
pub enum ReadMode {}
pub enum WriteMode {}

/// A file handle parameterized on open/closed state and access mode.
/// Invalid operations (reading a closed handle, writing to a read-mode handle)
/// are compile errors, not runtime panics.
pub struct Handle<State, Mode> {
    fd: i32, // simulated file descriptor
    _state: PhantomData<State>,
    _mode: PhantomData<Mode>,
}

// Opening -- produce an Open handle in the requested mode
pub fn open_read(path: &str) -> Handle<Open, ReadMode> {
    println!("[open-r] {path}");
    Handle { fd: 3, _state: PhantomData, _mode: PhantomData }
}

pub fn open_write(path: &str) -> Handle<Open, WriteMode> {
    println!("[open-w] {path}");
    Handle { fd: 4, _state: PhantomData, _mode: PhantomData }
}

// Operations on Open handles only
impl<Mode> Handle<Open, Mode> {
    /// Consumes the open handle and returns a closed one.
    pub fn close(self) -> Handle<Closed, Mode> {
        println!("[close] fd={}", self.fd);
        Handle { fd: self.fd, _state: PhantomData, _mode: PhantomData }
    }

    pub fn fd(&self) -> i32 { self.fd }
}

// Read operation -- only on Open + ReadMode
impl Handle<Open, ReadMode> {
    pub fn read(&self, buf: &mut [u8]) -> usize {
        println!("[read] {} bytes from fd={}", buf.len(), self.fd);
        0 // simulated
    }
}

// Write operation -- only on Open + WriteMode
impl Handle<Open, WriteMode> {
    pub fn write(&self, data: &[u8]) -> usize {
        println!("[write] {} bytes to fd={}", data.len(), self.fd);
        data.len() // simulated
    }
}

// Upgrade: convert a read handle to a writable one (new fd)
impl Handle<Open, ReadMode> {
    pub fn try_reopen_write(self, path: &str) -> Handle<Open, WriteMode> {
        println!("[reopen-w] {path}");
        self.close(); // close the read handle (consumed)
        open_write(path)
    }
}

// Drop for any state: cleans up if still open
impl<Mode> Drop for Handle<Open, Mode> {
    fn drop(&mut self) {
        println!("[auto-close] fd={}", self.fd);
    }
}

// Closed handles have no operations -- only Drop (which is a no-op)
impl<Mode> Drop for Handle<Closed, Mode> {
    fn drop(&mut self) {} // nothing to clean up
}

fn main() {
    // Read path
    let mut buf = [0u8; 64];
    let r = open_read("/etc/hosts");
    r.read(&mut buf);
    let _closed_r = r.close();
    // _closed_r.read(&mut buf); // COMPILE ERROR: no `read` on Handle<Closed, ReadMode>

    // Write path
    let w = open_write("/tmp/out.txt");
    w.write(b"hello");
    let _closed_w = w.close();
    // _closed_w.write(b"x"); // COMPILE ERROR: no `write` on Handle<Closed, WriteMode>

    // Cannot write to a read handle
    let r2 = open_read("/tmp/in.txt");
    // r2.write(b"x"); // COMPILE ERROR: no `write` on Handle<Open, ReadMode>
    drop(r2); // triggers auto-close

    // Reopen for write
    let r3 = open_read("/tmp/data.bin");
    let w3 = r3.try_reopen_write("/tmp/data.bin");
    w3.write(b"overwritten");
    // r3 is gone (consumed by try_reopen_write) -- cannot use it
}
```

Phantom types encode state in the type system with zero runtime overhead -- `PhantomData<State>` contributes no bytes to the struct layout. Each transition method (`close`, `try_reopen_write`) consumes `self` and returns a handle with the new state, making the old state inaccessible. `impl Handle<Open, ReadMode>` adds methods only when both type parameters match -- precision unavailable with runtime flags.

