use std::sync::atomic::{AtomicUsize, Ordering};
use std::cell::UnsafeCell;

/// Fixed-capacity SPSC ring buffer.
/// Only safe when used with exactly ONE producer thread and ONE consumer thread.
pub struct SpscQueue<T, const N: usize> {
    buf: [UnsafeCell<std::mem::MaybeUninit<T>>; N],
    head: AtomicUsize, // consumer reads from here
    tail: AtomicUsize, // producer writes here
}

unsafe impl<T: Send, const N: usize> Send for SpscQueue<T, N> {}
unsafe impl<T: Send, const N: usize> Sync for SpscQueue<T, N> {}

impl<T, const N: usize> SpscQueue<T, N> {
    pub fn new() -> Self {
        SpscQueue {
            buf: std::array::from_fn(|_| UnsafeCell::new(std::mem::MaybeUninit::uninit())),
            head: AtomicUsize::new(0),
            tail: AtomicUsize::new(0),
        }
    }

    /// Push an item. Returns Err(item) if the queue is full.
    /// Only call from the PRODUCER thread.
    pub fn push(&self, item: T) -> Result<(), T> {
        let tail = self.tail.load(Ordering::Relaxed);
        let next_tail = (tail + 1) % N;
        // Acquire: ensure we see the most recent head update from the consumer
        if next_tail == self.head.load(Ordering::Acquire) {
            return Err(item); // full
        }
        unsafe { (*self.buf[tail].get()).write(item); }
        // Release: make the write visible to the consumer before updating tail
        self.tail.store(next_tail, Ordering::Release);
        Ok(())
    }

    /// Pop an item. Returns None if the queue is empty.
    /// Only call from the CONSUMER thread.
    pub fn pop(&self) -> Option<T> {
        let head = self.head.load(Ordering::Relaxed);
        // Acquire: ensure we see the item written by the producer's Release
        if head == self.tail.load(Ordering::Acquire) {
            return None; // empty
        }
        let item = unsafe { (*self.buf[head].get()).assume_init_read() };
        // Release: make the slot available to the producer
        self.head.store((head + 1) % N, Ordering::Release);
        Some(item)
    }

    pub fn is_empty(&self) -> bool {
        self.head.load(Ordering::Relaxed) == self.tail.load(Ordering::Relaxed)
    }

    pub fn capacity(&self) -> usize { N - 1 } // one slot wasted to distinguish full from empty
}

impl<T, const N: usize> Drop for SpscQueue<T, N> {
    fn drop(&mut self) {
        while self.pop().is_some() {} // drop remaining items
    }
}

use std::sync::{Arc, Mutex};
use std::collections::VecDeque;
use std::time::Instant;

fn bench_spsc(n: usize) -> std::time::Duration {
    let queue = Arc::new(SpscQueue::<u64, 1024>::new());
    let q_prod = Arc::clone(&queue);
    let q_cons = Arc::clone(&queue);

    let t = Instant::now();
    let producer = std::thread::spawn(move || {
        let mut sent = 0;
        while sent < n {
            if q_prod.push(sent as u64).is_ok() { sent += 1; }
        }
    });
    let consumer = std::thread::spawn(move || {
        let mut received = 0;
        while received < n {
            if q_cons.pop().is_some() { received += 1; }
        }
    });
    producer.join().unwrap();
    consumer.join().unwrap();
    t.elapsed()
}

fn bench_mutex(n: usize) -> std::time::Duration {
    let queue = Arc::new(Mutex::new(VecDeque::<u64>::with_capacity(1024)));
    let q_prod = Arc::clone(&queue);
    let q_cons = Arc::clone(&queue);

    let t = Instant::now();
    let producer = std::thread::spawn(move || {
        for i in 0..n as u64 { q_prod.lock().unwrap().push_back(i); }
    });
    let consumer = std::thread::spawn(move || {
        let mut received = 0;
        while received < n {
            if q_cons.lock().unwrap().pop_front().is_some() { received += 1; }
        }
    });
    producer.join().unwrap();
    consumer.join().unwrap();
    t.elapsed()
}

fn main() {
    // Basic correctness
    let q = SpscQueue::<i32, 8>::new();
    for i in 0..7 { assert!(q.push(i).is_ok()); }
    assert!(q.push(99).is_err()); // full
    for i in 0..7 { assert_eq!(q.pop(), Some(i)); }
    assert_eq!(q.pop(), None);
    println!("Correctness: OK");

    // Benchmark
    let n = 100_000;
    let spsc_time = bench_spsc(n);
    let mutex_time = bench_mutex(n);
    println!("SPSC:  {} items in {:?}", n, spsc_time);
    println!("Mutex: {} items in {:?}", n, mutex_time);
    println!("Speedup: {:.1}x", mutex_time.as_secs_f64() / spsc_time.as_secs_f64());
}
```

Ordering rationale: `push` uses `Acquire` when loading `head` (to see consumer's latest release) and `Release` when storing `tail` (to publish the new item to the consumer). `pop` mirrors this. `Relaxed` is used for self-reads (`tail` in `push`, `head` in `pop`) because only one thread touches each pointer. This is the minimal ordering needed -- `SeqCst` would be correct but wastes a full memory fence (`MFENCE` on x86).

