use std::marker::PhantomData;

// Step marker types -- uninhabited (cannot be constructed)
pub enum Uninitialized {}
pub enum Validated {}
pub enum Approved {}
pub enum Executed {}

/// A loan application that must go through Validate -> Approve -> Execute in order.
/// Any attempt to skip a step is a compile error.
pub struct LoanApplication<S> {
    id: u64,
    amount: f64,
    applicant: String,
    score: Option<u32>,   // set by validate
    approved_by: Option<String>, // set by approve
    _step: PhantomData<S>,
}

impl LoanApplication<Uninitialized> {
    pub fn new(id: u64, applicant: impl Into<String>, amount: f64) -> Self {
        LoanApplication {
            id, amount, applicant: applicant.into(),
            score: None, approved_by: None, _step: PhantomData,
        }
    }
}

// Validate: Uninitialized -> Validated
impl LoanApplication<Uninitialized> {
    pub fn validate(self) -> Result<LoanApplication<Validated>, String> {
        if self.amount <= 0.0 { return Err("amount must be positive".into()); }
        if self.applicant.is_empty() { return Err("applicant required".into()); }
        let score = (self.amount as u32 % 300) + 500; // simulated
        println!("[validate] app={} score={score}", self.id);
        Ok(LoanApplication { score: Some(score), ..self.into_validated() })
    }

    fn into_validated(self) -> LoanApplication<Validated> {
        LoanApplication { id: self.id, amount: self.amount, applicant: self.applicant,
                          score: self.score, approved_by: self.approved_by, _step: PhantomData }
    }
}

// Approve: Validated -> Approved
impl LoanApplication<Validated> {
    pub fn approve(self, approver: impl Into<String>) -> Result<LoanApplication<Approved>, String> {
        let score = self.score.unwrap();
        if score < 600 { return Err(format!("score {score} too low")); }
        let approver = approver.into();
        println!("[approve] app={} by={approver}", self.id);
        Ok(LoanApplication {
            approved_by: Some(approver),
            id: self.id, amount: self.amount, applicant: self.applicant,
            score: self.score, _step: PhantomData,
        })
    }

    pub fn score(&self) -> u32 { self.score.unwrap() }
}

// Execute: Approved -> Executed
impl LoanApplication<Approved> {
    pub fn execute(self) -> LoanApplication<Executed> {
        println!("[execute] app={} amount={:.2} approved_by={:?}",
            self.id, self.amount, self.approved_by);
        LoanApplication { id: self.id, amount: self.amount, applicant: self.applicant,
                          score: self.score, approved_by: self.approved_by, _step: PhantomData }
    }

    pub fn approved_by(&self) -> &str { self.approved_by.as_deref().unwrap() }
}

// Completed application info
impl LoanApplication<Executed> {
    pub fn receipt(&self) -> String {
        format!("Loan #{}: ${:.2} for '{}' (score={}, approver={})",
            self.id, self.amount, self.applicant,
            self.score.unwrap(), self.approved_by.as_deref().unwrap())
    }
}

// Available at any step
impl<S> LoanApplication<S> {
    pub fn id(&self) -> u64 { self.id }
    pub fn amount(&self) -> f64 { self.amount }
}

fn main() {
    // Happy path
    let app = LoanApplication::new(1, "Alice", 50_000.0);
    let validated = app.validate().unwrap();
    println!("Score: {}", validated.score());
    let approved = validated.approve("Bob").unwrap();
    let executed = approved.execute();
    println!("{}", executed.receipt());

    // Validation failure
    let bad = LoanApplication::new(2, "", 1000.0);
    println!("bad: {:?}", bad.validate().unwrap_err());

    // Approval failure (low score)
    let low = LoanApplication::new(3, "Eve", 999_999.0);
    let v2 = low.validate().unwrap();
    println!("approval: {:?}", v2.approve("Carol").unwrap_err());

    // COMPILE ERRORS (uncomment to verify):
    // let app2 = LoanApplication::new(4, "X", 1000.0);
    // app2.approve("Y"); // ERROR: no `approve` on Uninitialized
    //
    // let validated2 = app.validate().unwrap();
    // validated2.execute(); // ERROR: no `execute` on Validated
}
```

Each step method consumes `self` (old state gone) and returns the next state. The `PhantomData<S>` marker is zero-sized and costs nothing at runtime. Step methods exist only on their specific `impl<LoanApplication<Step>>` block -- missing a step is "method not found", not a runtime error. This pattern is ideal for multi-step forms, document approval workflows, and protocol handshakes.

