use std::sync::{Arc, Condvar, Mutex};
use std::collections::VecDeque;

struct Inner<T> {
    buf: VecDeque<T>,
    capacity: usize,
    closed: bool,
}

pub struct Sender<T>(Arc<(Mutex<Inner<T>>, Condvar, Condvar)>);
pub struct Receiver<T>(Arc<(Mutex<Inner<T>>, Condvar, Condvar)>);

#[derive(Debug, PartialEq)]
pub enum SendError<T> { Full(T), Closed(T) }

#[derive(Debug, PartialEq)]
pub enum RecvError { Empty, Closed }

pub fn channel<T>(capacity: usize) -> (Sender<T>, Receiver<T>) {
    let inner = Inner { buf: VecDeque::with_capacity(capacity), capacity, closed: false };
    let arc = Arc::new((Mutex::new(inner), Condvar::new(), Condvar::new()));
    // condvar0 = "space available" (wakes producers)
    // condvar1 = "item available" (wakes consumers)
    (Sender(Arc::clone(&arc)), Receiver(arc))
}

impl<T> Sender<T> {
    /// Send, blocking until space is available or channel is closed.
    pub fn send(&self, mut item: T) -> Result<(), T> {
        let (lock, space_cv, item_cv) = &*self.0;
        let mut inner = lock.lock().unwrap();
        loop {
            if inner.closed { return Err(item); }
            if inner.buf.len() < inner.capacity { break; }
            inner = space_cv.wait(inner).unwrap(); // release lock, sleep, re-acquire
        }
        inner.buf.push_back(item);
        item_cv.notify_one(); // wake a consumer
        Ok(())
    }

    /// Non-blocking send.
    pub fn try_send(&self, item: T) -> Result<(), SendError<T>> {
        let (lock, _, item_cv) = &*self.0;
        let mut inner = lock.lock().unwrap();
        if inner.closed { return Err(SendError::Closed(item)); }
        if inner.buf.len() >= inner.capacity { return Err(SendError::Full(item)); }
        inner.buf.push_back(item);
        item_cv.notify_one();
        Ok(())
    }
}

impl<T> Drop for Sender<T> {
    fn drop(&mut self) {
        let (lock, _, item_cv) = &*self.0;
        lock.lock().unwrap().closed = true;
        item_cv.notify_all(); // wake all consumers so they can see Closed
    }
}

impl<T> Receiver<T> {
    /// Receive, blocking until an item is available or channel is closed.
    pub fn recv(&self) -> Result<T, RecvError> {
        let (lock, space_cv, item_cv) = &*self.0;
        let mut inner = lock.lock().unwrap();
        loop {
            if let Some(item) = inner.buf.pop_front() {
                space_cv.notify_one(); // wake a producer
                return Ok(item);
            }
            if inner.closed { return Err(RecvError::Closed); }
            inner = item_cv.wait(inner).unwrap();
        }
    }

    /// Iterate until channel is closed and drained.
    pub fn iter(&self) -> impl Iterator<Item = T> + '_ {
        std::iter::from_fn(move || self.recv().ok())
    }
}

fn main() {
    use std::{thread, time::Duration};

    let (tx, rx) = channel::<String>(4);

    // Producer: 10 items, channel capacity 4 -> backpressure kicks in
    let producer = thread::spawn(move || {
        for i in 0..10 {
            let item = format!("item-{i}");
            println!("[producer] sending {item}");
            if tx.send(item).is_err() {
                println!("[producer] channel closed, stopping");
                break;
            }
        }
        println!("[producer] done (drop -> closes channel)");
    });

    // Consumer: slow, to demonstrate backpressure
    let consumer = thread::spawn(move || {
        for item in rx.iter() {
            thread::sleep(Duration::from_millis(30)); // slow consumer
            println!("[consumer] received {item}");
        }
        println!("[consumer] channel closed, exiting");
    });

    producer.join().unwrap();
    consumer.join().unwrap();

    // try_send example
    let (tx2, rx2) = channel::<i32>(2);
    assert!(tx2.try_send(1).is_ok());
    assert!(tx2.try_send(2).is_ok());
    assert!(matches!(tx2.try_send(3), Err(SendError::Full(3)))); // full
    drop(tx2);
    assert_eq!(rx2.recv(), Ok(1));
    assert_eq!(rx2.recv(), Ok(2));
    assert_eq!(rx2.recv(), Err(RecvError::Closed));
}
```

Condvar protocol: `send` waits on `space_cv` when full; after inserting, notifies `item_cv`. `recv` waits on `item_cv` when empty; after removing, notifies `space_cv`. Dropping `Sender` sets `closed = true` and notifies all consumers via `notify_all()` so they can observe the closed state. The Condvar re-checks the predicate in a loop to handle spurious wakeups.

