impl From<Status> for u8 {
    fn from(v: Status) -> u8 {
        match v {
            Status::Pending   => 0u8,
            Status::Active    => 1u8,
            Status::Suspended => 2u8,
            Status::Closed    => 10u8,
        }
    }
}

impl TryFrom<u8> for Status {
    type Error = String;
    fn try_from(n: u8) -> Result<Self, String> {
        match n {
            0  => Ok(Status::Pending),
            1  => Ok(Status::Active),
            2  => Ok(Status::Suspended),
            10 => Ok(Status::Closed),
