package main

import (
	"fmt"
	"sync"
)

// fanOut distributes jobs from a single input channel to N worker channels.
func fanOut(in <-chan int, n int) []<-chan int {
	outs := make([]<-chan int, n)
	for i := 0; i < n; i++ {
		ch := make(chan int)
		outs[i] = ch
		go func(out chan<- int) {
			defer close(out)
			for v := range in {
				out <- v * v // example transform
			}
		}(ch)
	}
	return outs
}

// fanIn merges multiple read-only channels into one.
func fanIn(channels ...<-chan int) <-chan int {
	var wg sync.WaitGroup
	merged := make(chan int)

	forward := func(ch <-chan int) {
		defer wg.Done()
		for v := range ch {
			merged <- v
		}
	}

	wg.Add(len(channels))
	for _, ch := range channels {
		go forward(ch)
	}

	// Close merged once all forwarders finish.
	go func() {
		wg.Wait()
		close(merged)
	}()

	return merged
}

func main() {
	in := make(chan int)
	go func() {
		defer close(in)
		for i := 1; i <= 10; i++ {
			in <- i
		}
	}()

	workers := fanOut(in, 3)
	results := fanIn(workers...)

	for r := range results {
		fmt.Println(r)
	}
}
```

Key points:
- `fanOut` spawns N goroutines all reading from the *same* shared input channel; Go's channel receive is safe for concurrent readers, so work is distributed naturally.
- `fanIn` uses a `sync.WaitGroup` to know when all forwarder goroutines are done, then closes the merged channel — the only correct way to signal completion to downstream consumers.
- Each stage is connected by typed channels, making the data flow explicit and race-free.

```go
package main

import "fmt"

// tee copies each value from `in` to both returned channels.
// Both consumers MUST read; a slow consumer blocks the other.
func tee(in <-chan int) (<-chan int, <-chan int) {
	out1 := make(chan int)
	out2 := make(chan int)

	go func() {
		defer close(out1)
		defer close(out2)
		for v := range in {
			// Shadow loop variable; assign to locals so both sends see the same value.
			var o1, o2 = out1, out2
			// Use a two-armed select loop so neither consumer can starve indefinitely.
			for i := 0; i < 2; i++ {
				select {
				case o1 <- v:
					o1 = nil // disable this arm
				case o2 <- v:
					o2 = nil
				}
			}
		}
	}()
	return out1, out2
}

func main() {
	in := make(chan int)
	go func() {
		defer close(in)
		for i := 0; i < 5; i++ {
			in <- i
		}
	}()

	a, b := tee(in)
	for v := range a {
		fmt.Printf("a=%d b=%d\n", v, <-b)
	}
}
```

The nil-channel trick is idiomatic Go: assigning `nil` to a channel variable inside a `select` permanently disables that `case` because a send/receive on `nil` blocks forever. This guarantees both `out1` and `out2` receive exactly one copy of each value without using a mutex.

```go
package main

import (
	"context"
	"fmt"
)

// bridge flattens <-chan <-chan T into a single <-chan T.
// It respects ctx cancellation and cleans up all goroutines.
func bridge(ctx context.Context, chanStream <-chan (<-chan int)) <-chan int {
	valStream := make(chan int)
	go func() {
		defer close(valStream)
		for {
			var stream <-chan int
			select {
			case maybeStream, ok := <-chanStream:
				if !ok {
					return
				}
				stream = maybeStream
			case <-ctx.Done():
				return
			}
			// Drain this inner channel.
			for val := range orDone(ctx, stream) {
				select {
				case valStream <- val:
				case <-ctx.Done():
					return
				}
			}
		}
	}()
	return valStream
}

// orDone wraps a channel so ranging over it respects ctx.
func orDone(ctx context.Context, c <-chan int) <-chan int {
	valStream := make(chan int)
	go func() {
		defer close(valStream)
		for {
			select {
			case <-ctx.Done():
				return
			case v, ok := <-c:
				if !ok {
					return
				}
				select {
				case valStream <- v:
				case <-ctx.Done():
					return
				}
			}
		}
	}()
	return valStream
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	genChanStream := func() <-chan (<-chan int) {
		chanStream := make(chan (<-chan int))
		go func() {
			defer close(chanStream)
			for i := 0; i < 3; i++ {
				stream := make(chan int, 2)
				stream <- i * 10
				stream <- i*10 + 1
				close(stream)
				chanStream <- stream
			}
		}()
		return chanStream
	}

	for v := range bridge(ctx, genChanStream()) {
		fmt.Println(v)
	}
}
