```go
package main

import (
	"fmt"
	"time"
)

// unbuffered: sender blocks until receiver is ready — a synchronization point.
func unbufferedDemo() {
	ch := make(chan string) // capacity 0

	go func() {
		fmt.Println("goroutine: about to send")
		ch <- "hello" // blocks here until main receives
		fmt.Println("goroutine: send complete")
	}()

	time.Sleep(50 * time.Millisecond)
	fmt.Println("main: about to receive")
	msg := <-ch
	fmt.Println("main: received", msg)
}

// buffered: sender only blocks when buffer is full — decouples producer pace from consumer pace.
func bufferedDemo() {
	ch := make(chan int, 3) // capacity 3

	// All three sends complete without a receiver.
	ch <- 1
	ch <- 2
	ch <- 3
	fmt.Println("buffered: sent 3 items without blocking")

	// Fourth send would block — start consumer first.
	go func() {
		for v := range ch {
			fmt.Println("received", v)
		}
	}()

	ch <- 4 // now blocks until consumer drains space
	close(ch)
	time.Sleep(10 * time.Millisecond)
}

// Semaphore pattern: buffered channel of capacity N limits concurrency.
func semaphoreDemo(n int) {
	sem := make(chan struct{}, n)
	for i := 0; i < 10; i++ {
		sem <- struct{}{} // acquire
		go func(id int) {
			defer func() { <-sem }() // release
			fmt.Println("worker", id, "running")
		}(i)
	}
	// Drain semaphore to wait for all.
	for i := 0; i < n; i++ {
		sem <- struct{}{}
	}
}

func main() {
	fmt.Println("=== Unbuffered ===")
	unbufferedDemo()
	fmt.Println("\n=== Buffered ===")
	bufferedDemo()
	fmt.Println("\n=== Semaphore ===")
	semaphoreDemo(3)
}
```

Rule of thumb: unbuffered channels are for *synchronization* (rendez-vous); buffered channels are for *decoupling* producer/consumer speeds. Using a buffered channel of size N as a semaphore is idiomatic Go for bounding concurrency without importing extra packages.

```go
package main

import (
	"context"
	"fmt"
)

// generate emits integers 1..n then closes.
func generate(ctx context.Context, nums ...int) <-chan int {
	out := make(chan int)
	go func() {
		defer close(out)
		for _, n := range nums {
			select {
			case out <- n:
			case <-ctx.Done():
				return
			}
		}
	}()
	return out
}

// square reads from in, squares each value, emits to out.
func square(ctx context.Context, in <-chan int) <-chan int {
	out := make(chan int)
	go func() {
		defer close(out)
		for v := range in {
			select {
			case out <- v * v:
			case <-ctx.Done():
				return
			}
		}
	}()
	return out
}

// filterEven passes only even values downstream.
func filterEven(ctx context.Context, in <-chan int) <-chan int {
	out := make(chan int)
	go func() {
		defer close(out)
		for v := range in {
			if v%2 != 0 {
				continue
			}
			select {
			case out <- v:
			case <-ctx.Done():
				return
			}
		}
	}()
	return out
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	nums := make([]int, 10)
	for i := range nums {
		nums[i] = i + 1
	}

	// Chain: generate → square → filterEven
	pipeline := filterEven(ctx, square(ctx, generate(ctx, nums...)))

	for v := range pipeline {
		fmt.Println(v) // 4 16 36 64 100
	}
}
```

Every stage owns its output channel and closes it when done. The context flows through every `select` so the entire pipeline can be torn down with a single `cancel()` call — no goroutine leaks.

```go
package main

import (
	"context"
	"fmt"
)

// repeat emits the values in a cycle forever, respecting ctx.
func repeat(ctx context.Context, values ...int) <-chan int {
	out := make(chan int)
	go func() {
		defer close(out)
		for {
			for _, v := range values {
				select {
				case out <- v:
				case <-ctx.Done():
					return
				}
			}
		}
	}()
	return out
}

// repeatFn calls fn repeatedly and emits results, respecting ctx.
func repeatFn(ctx context.Context, fn func() int) <-chan int {
	out := make(chan int)
	go func() {
		defer close(out)
		for {
			select {
			case out <- fn():
			case <-ctx.Done():
				return
			}
		}
	}()
	return out
}

// take reads exactly n values from in then cancels.
func take(ctx context.Context, in <-chan int, n int) <-chan int {
	out := make(chan int)
	go func() {
		defer close(out)
		for i := 0; i < n; i++ {
			select {
			case v, ok := <-in:
				if !ok {
					return
				}
				out <- v
			case <-ctx.Done():
				return
			}
		}
	}()
	return out
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Print first 7 values from a cycling [1,2,3] source.
	for v := range take(ctx, repeat(ctx, 1, 2, 3), 7) {
		fmt.Print(v, " ") // 1 2 3 1 2 3 1
	}
	fmt.Println()

	// Generate 5 random-ish values via repeatFn.
	counter := 0
	for v := range take(ctx, repeatFn(ctx, func() int { counter++; return counter * 3 }), 5) {
		fmt.Print(v, " ") // 3 6 9 12 15
	}
	fmt.Println()
}
```

`take` drives cancellation by simply stopping to read — the context cancel in `defer cancel()` then unblocks the `repeat` goroutine. This is the standard Go approach: downstream consumers control upstream lifecycle through context, not by closing input channels.

```go
package main

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"
)

// Semaphore limits concurrent access using a buffered channel.
type Semaphore chan struct{}

func NewSemaphore(n int) Semaphore {
	return make(Semaphore, n)
}

// Acquire blocks until a slot is available or ctx is cancelled.
func (s Semaphore) Acquire(ctx context.Context) error {
	select {
	case s <- struct{}{}:
		return nil
	case <-ctx.Done():
		return ctx.Err()
	}
}

// Release frees a slot.
func (s Semaphore) Release() { <-s }

func fetchAll(ctx context.Context, urls []string, maxConcurrent int) map[string]int {
	sem := NewSemaphore(maxConcurrent)
	client := &http.Client{Timeout: 5 * time.Second}

	type result struct {
		url    string
		status int
	}

	results := make(chan result, len(urls))
	var wg sync.WaitGroup

	for _, url := range urls {
		wg.Add(1)
		go func(u string) {
			defer wg.Done()
			if err := sem.Acquire(ctx); err != nil {
				results <- result{url: u, status: -1}
				return
			}
			defer sem.Release()

			resp, err := client.Get(u)
			if err != nil {
				results <- result{url: u, status: 0}
				return
			}
			resp.Body.Close()
			results <- result{url: u, status: resp.StatusCode}
		}(url)
	}

	go func() {
		wg.Wait()
		close(results)
	}()

	out := make(map[string]int)
	for r := range results {
		out[r.url] = r.status
	}
	return out
}

func main() {
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	urls := []string{
		"https://example.com",
		"https://httpbin.org/get",
		"https://go.dev",
	}

	status := fetchAll(ctx, urls, 2) // max 2 concurrent requests
	for url, code := range status {
		fmt.Printf("%s -> %d\n", url, code)
	}
}
```

