package main

import (
	"context"
	"errors"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"
)

func slowHandler(w http.ResponseWriter, r *http.Request) {
	select {
	case <-time.After(3 * time.Second):
		fmt.Fprintln(w, "slow response done")
	case <-r.Context().Done():
		// Client disconnected or server is shutting down.
		log.Println("handler: context done:", r.Context().Err())
	}
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/slow", slowHandler)
	mux.HandleFunc("/health", func(w http.ResponseWriter, _ *http.Request) {
		fmt.Fprintln(w, "ok")
	})

	srv := &http.Server{
		Addr:         ":8080",
		Handler:      mux,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	// Start server in background.
	serverErr := make(chan error, 1)
	go func() {
		log.Println("server listening on", srv.Addr)
		if err := srv.ListenAndServe(); !errors.Is(err, http.ErrServerClosed) {
			serverErr <- err
		}
		close(serverErr)
	}()

	// Wait for SIGINT or SIGTERM.
	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)

	select {
	case sig := <-quit:
		log.Println("received signal:", sig)
	case err := <-serverErr:
		log.Fatal("server error:", err)
	}

	// Shutdown: give in-flight requests up to 30 seconds to complete.
	shutdownCtx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	log.Println("shutting down...")
	if err := srv.Shutdown(shutdownCtx); err != nil {
		log.Printf("shutdown error: %v", err)
	} else {
		log.Println("server stopped cleanly")
	}

	// Wait for the ListenAndServe goroutine to confirm it exited.
	if err := <-serverErr; err != nil {
		log.Println("post-shutdown error:", err)
	}
}
```

`http.Server.Shutdown` does the following in order: stops accepting new connections, closes idle connections, then waits for active connections to become idle (handlers return). The context timeout is the escape hatch — if requests don't finish within 30s, Shutdown returns a context error and the process exits anyway.

```go
package main

import (
	"fmt"
	"sync"
)

type Message struct {
	Topic   string
	Payload any
}

type Broker struct {
	mu          sync.RWMutex
	subscribers map[string][]chan Message
}

func NewBroker() *Broker {
	return &Broker{subscribers: make(map[string][]chan Message)}
}

// Subscribe returns a channel that receives messages on topic.
// bufSize controls the channel buffer; a slow consumer blocks Publish if 0.
func (b *Broker) Subscribe(topic string, bufSize int) <-chan Message {
	ch := make(chan Message, bufSize)
	b.mu.Lock()
	b.subscribers[topic] = append(b.subscribers[topic], ch)
	b.mu.Unlock()
	return ch
}

// Unsubscribe removes a subscriber channel from a topic and closes it.
func (b *Broker) Unsubscribe(topic string, sub <-chan Message) {
	b.mu.Lock()
	defer b.mu.Unlock()
	subs := b.subscribers[topic]
	for i, ch := range subs {
		if ch == sub {
			b.subscribers[topic] = append(subs[:i], subs[i+1:]...)
			close(ch)
			return
		}
	}
}

// Publish sends a message to all subscribers of topic.
func (b *Broker) Publish(topic string, payload any) {
	b.mu.RLock()
	subs := make([]chan Message, len(b.subscribers[topic]))
	copy(subs, b.subscribers[topic])
	b.mu.RUnlock()

	msg := Message{Topic: topic, Payload: payload}
	for _, ch := range subs {
		// Non-blocking send: slow consumers drop messages rather than blocking Publish.
		select {
		case ch <- msg:
		default:
			fmt.Printf("subscriber buffer full for topic %s, message dropped\n", topic)
		}
	}
}

// Close shuts down the broker, closing all subscriber channels.
func (b *Broker) Close() {
	b.mu.Lock()
	defer b.mu.Unlock()
	for _, subs := range b.subscribers {
		for _, ch := range subs {
			close(ch)
		}
	}
	b.subscribers = make(map[string][]chan Message)
}

func main() {
	broker := NewBroker()
	defer broker.Close()

	sub1 := broker.Subscribe("events", 10)
	sub2 := broker.Subscribe("events", 10)
	sub3 := broker.Subscribe("alerts", 5)

	var wg sync.WaitGroup
	for name, sub := range map[string]<-chan Message{"sub1": sub1, "sub2": sub2, "sub3": sub3} {
		wg.Add(1)
		go func(n string, ch <-chan Message) {
			defer wg.Done()
			for msg := range ch {
				fmt.Printf("%s received [%s]: %v\n", n, msg.Topic, msg.Payload)
			}
		}(name, sub)
	}

	broker.Publish("events", "user_login")
	broker.Publish("events", "page_view")
	broker.Publish("alerts", "disk_full")

	broker.Unsubscribe("events", sub1)
	broker.Publish("events", "user_logout") // only sub2 gets this
}
```

```go
package main

import (
	"fmt"
	"sync"
	"time"
)

// call represents a single in-flight or completed request.
type call struct {
	wg  sync.WaitGroup
	val any
	err error
}

// Group deduplicates concurrent calls with the same key.
type Group struct {
	mu sync.Mutex
	m  map[string]*call
}

// Do executes fn if no call for key is in flight; otherwise waits for the
// in-flight call and returns its result. All callers get the same (val, err).
func (g *Group) Do(key string, fn func() (any, error)) (any, error) {
	g.mu.Lock()
	if g.m == nil {
		g.m = make(map[string]*call)
	}
	if c, ok := g.m[key]; ok {
		g.mu.Unlock()
		c.wg.Wait() // join in-flight call
		return c.val, c.err
	}

	c := &call{}
	c.wg.Add(1)
	g.m[key] = c
	g.mu.Unlock()

	c.val, c.err = fn()
	c.wg.Done()

	g.mu.Lock()
	delete(g.m, key) // allow future calls for this key
	g.mu.Unlock()

	return c.val, c.err
}

// Simulated expensive fetch.
var fetchCount int
var fetchMu sync.Mutex

func fetchData(key string) (any, error) {
	fetchMu.Lock()
	fetchCount++
	fetchMu.Unlock()

	time.Sleep(100 * time.Millisecond) // simulate DB/network
	return fmt.Sprintf("data-for-%s", key), nil
}

func main() {
	var g Group
	var wg sync.WaitGroup

	// 10 concurrent callers for the same key — only 1 fetch should happen.
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			val, err := g.Do("user:42", func() (any, error) {
				return fetchData("user:42")
			})
			if err != nil {
				fmt.Println("error:", err)
				return
			}
			fmt.Printf("goroutine %d: %v\n", id, val)
		}(i)
	}
	wg.Wait()

	fetchMu.Lock()
	fmt.Println("total fetches:", fetchCount) // should be 1
	fetchMu.Unlock()
}
```

This is a faithful reimplementation of `golang.org/x/sync/singleflight`. In production, use that package directly — it handles panics correctly (a panicking fn is still deregistered). Use singleflight whenever you have cache stampede risk: many goroutines triggering the same expensive computation simultaneously.

```go
package main

import (
	"context"
	"fmt"
	"sync"
	"time"
)

type traceKey struct{}

// TraceID retrieves the trace ID from ctx, or returns empty string.
func TraceID(ctx context.Context) string {
	if v, ok := ctx.Value(traceKey{}).(string); ok {
		return v
	}
	return ""
}

// WithTraceID returns a context carrying the trace ID.
func WithTraceID(ctx context.Context, id string) context.Context {
	return context.WithValue(ctx, traceKey{}, id)
}

// logf logs with the trace ID from ctx.
func logf(ctx context.Context, format string, args ...any) {
	tid := TraceID(ctx)
	fmt.Printf("[%s] %s\n", tid, fmt.Sprintf(format, args...))
}

// worker receives the full context — the trace ID flows automatically.
func worker(ctx context.Context, id int, wg *sync.WaitGroup) {
	defer wg.Done()
	logf(ctx, "worker %d starting", id)
	select {
	case <-time.After(time.Duration(id*10) * time.Millisecond):
		logf(ctx, "worker %d done", id)
	case <-ctx.Done():
		logf(ctx, "worker %d cancelled: %v", id, ctx.Err())
	}
}

// processRequest simulates a request handler that spans multiple goroutines.
func processRequest(ctx context.Context, traceID string) {
	ctx = WithTraceID(ctx, traceID)
	logf(ctx, "request started")

	ctx, cancel := context.WithTimeout(ctx, 50*time.Millisecond)
	defer cancel()

	var wg sync.WaitGroup
	for i := 1; i <= 5; i++ {
		wg.Add(1)
		go worker(ctx, i, &wg)
	}
	wg.Wait()
	logf(ctx, "request finished")
}

func main() {
	// Simulate two concurrent requests with distinct trace IDs.
	var wg sync.WaitGroup
	wg.Add(2)
	go func() {
		defer wg.Done()
		processRequest(context.Background(), "req-abc-123")
	}()
	go func() {
		defer wg.Done()
		processRequest(context.Background(), "req-xyz-789")
	}()
	wg.Wait()
}
```

Because context is passed explicitly to every goroutine, the trace ID travels the full call graph without any global state. This is the foundation of distributed tracing in Go — OpenTelemetry's span context uses the same mechanism.

```go
package main

import (
	"fmt"
	"sync"
	"time"
)

// BoundedQueue is a thread-safe queue with a capacity limit.
// Producers block when full; consumers block when empty.
type BoundedQueue struct {
	mu       sync.Mutex
	cond     *sync.Cond
	items    []int
	cap      int
	closed   bool
}

func NewBoundedQueue(cap int) *BoundedQueue {
	q := &BoundedQueue{cap: cap}
	q.cond = sync.NewCond(&q.mu)
	return q
}

// Push blocks until space is available or queue is closed.
func (q *BoundedQueue) Push(v int) bool {
	q.mu.Lock()
	defer q.mu.Unlock()
	for len(q.items) == q.cap && !q.closed {
		q.cond.Wait() // atomically releases lock and suspends
	}
	if q.closed {
		return false
	}
	q.items = append(q.items, v)
	q.cond.Broadcast() // wake all waiters — both blocked pushes and pops
	return true
}

// Pop blocks until an item is available or queue is closed.
func (q *BoundedQueue) Pop() (int, bool) {
	q.mu.Lock()
	defer q.mu.Unlock()
	for len(q.items) == 0 && !q.closed {
		q.cond.Wait()
	}
	if len(q.items) == 0 {
		return 0, false // closed and empty
	}
	v := q.items[0]
	q.items = q.items[1:]
	q.cond.Broadcast()
	return v, true
}

// Close wakes all waiters so they can exit.
func (q *BoundedQueue) Close() {
	q.mu.Lock()
	q.closed = true
	q.cond.Broadcast()
	q.mu.Unlock()
}

func main() {
	q := NewBoundedQueue(5)
	var wg sync.WaitGroup

	// Producer: pushes 20 items.
	wg.Add(1)
	go func() {
		defer wg.Done()
		for i := 0; i < 20; i++ {
			if !q.Push(i) {
				fmt.Println("producer: queue closed")
				return
			}
			fmt.Println("pushed:", i)
		}
		q.Close()
	}()

	// Consumer: pops items with artificial delay.
	wg.Add(1)
	go func() {
		defer wg.Done()
		for {
			v, ok := q.Pop()
			if !ok {
				fmt.Println("consumer: done")
				return
			}
			fmt.Println("popped:", v)
			time.Sleep(10 * time.Millisecond)
		}
	}()

	wg.Wait()
}
```

`sync.Cond.Wait()` atomically releases the lock and suspends the goroutine. When `Broadcast()` or `Signal()` fires, the goroutine reacquires the lock before returning. Always check the condition in a `for` loop, not `if` — spurious wakeups are possible and multiple waiters may race to consume the newly available slot.

```go
package main

import (
	"context"
	"fmt"
	"sync"
	"time"
)

type Job struct {
	Name     string
	Interval time.Duration
	Fn       func(ctx context.Context)
}

type Scheduler struct {
	mu   sync.Mutex
	jobs []Job
	wg   sync.WaitGroup
}

func NewScheduler() *Scheduler {
	return &Scheduler{}
}

// Add registers a job. Must be called before Start.
func (s *Scheduler) Add(job Job) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.jobs = append(s.jobs, job)
}

// Start launches all registered jobs. Returns when ctx is cancelled.
func (s *Scheduler) Start(ctx context.Context) {
	s.mu.Lock()
	jobs := make([]Job, len(s.jobs))
	copy(jobs, s.jobs)
	s.mu.Unlock()

	for _, job := range jobs {
		job := job
		s.wg.Add(1)
		go func() {
			defer s.wg.Done()
			// Run immediately on start.
			job.Fn(ctx)
			ticker := time.NewTicker(job.Interval)
			defer ticker.Stop()
			for {
				select {
				case <-ticker.C:
					job.Fn(ctx)
				case <-ctx.Done():
					fmt.Printf("job %s: stopping\n", job.Name)
					return
				}
			}
		}()
	}
}

// Wait blocks until all jobs have exited.
func (s *Scheduler) Wait() { s.wg.Wait() }

func main() {
	sched := NewScheduler()

	sched.Add(Job{
		Name:     "health-check",
		Interval: 500 * time.Millisecond,
		Fn: func(ctx context.Context) {
			fmt.Println("health-check:", time.Now().Format("15:04:05.000"))
		},
	})

	sched.Add(Job{
		Name:     "metrics-emit",
		Interval: 1 * time.Second,
		Fn: func(ctx context.Context) {
			fmt.Println("metrics-emit:", time.Now().Format("15:04:05.000"))
		},
	})

	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	sched.Start(ctx)
	sched.Wait()
	fmt.Println("scheduler stopped")
}
