```go
package main

import (
	"cmp"
	"fmt"
	"sort"
	"sync"
)

// OrderedSet is a thread-safe set of ordered elements.
// The zero value is NOT valid; use NewOrderedSet.
type OrderedSet[T cmp.Ordered] struct {
	mu    sync.RWMutex
	items []T
}

func NewOrderedSet[T cmp.Ordered]() *OrderedSet[T] {
	return &OrderedSet[T]{}
}

// Add inserts v into the set if not already present.
func (s *OrderedSet[T]) Add(v T) {
	s.mu.Lock()
	defer s.mu.Unlock()
	idx := s.search(v)
	if idx < len(s.items) && s.items[idx] == v {
		return // already exists
	}
	// Insert at idx to maintain sorted order.
	s.items = append(s.items, v)
	copy(s.items[idx+1:], s.items[idx:])
	s.items[idx] = v
}

// Remove deletes v from the set. No-op if absent.
func (s *OrderedSet[T]) Remove(v T) {
	s.mu.Lock()
	defer s.mu.Unlock()
	idx := s.search(v)
	if idx >= len(s.items) || s.items[idx] != v {
		return
	}
	s.items = append(s.items[:idx], s.items[idx+1:]...)
}

// Contains reports whether v is in the set.
func (s *OrderedSet[T]) Contains(v T) bool {
	s.mu.RLock()
	defer s.mu.RUnlock()
	idx := s.search(v)
	return idx < len(s.items) && s.items[idx] == v
}

// Slice returns a sorted copy of all elements.
func (s *OrderedSet[T]) Slice() []T {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]T, len(s.items))
	copy(out, s.items)
	return out
}

// Len returns the number of elements.
func (s *OrderedSet[T]) Len() int {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return len(s.items)
}

// search returns the insertion index for v (binary search).
// Must be called with mu held.
func (s *OrderedSet[T]) search(v T) int {
	return sort.Search(len(s.items), func(i int) bool {
		return cmp.Compare(s.items[i], v) >= 0
	})
}

func main() {
	set := NewOrderedSet[int]()
	var wg sync.WaitGroup

	for i := 0; i < 50; i++ {
		i := i % 20 // lots of duplicates
		wg.Add(1)
		go func() {
			defer wg.Done()
			set.Add(i)
		}()
	}
	wg.Wait()

	fmt.Println("elements:", set.Slice())
	fmt.Println("len:", set.Len())
	fmt.Println("contains 5:", set.Contains(5))
	set.Remove(5)
	fmt.Println("after remove 5:", set.Contains(5))

	// Works with strings too.
	strSet := NewOrderedSet[string]()
	strSet.Add("banana")
	strSet.Add("apple")
	strSet.Add("cherry")
	strSet.Add("apple") // duplicate
	fmt.Println(strSet.Slice()) // [apple banana cherry]
}
```

The `cmp.Ordered` constraint (Go 1.21+) covers all integer types, float types, and strings. Binary search via `sort.Search` keeps `Add` and `Contains` O(log n) for reads; `Add` is O(n) overall due to the slice shift but is acceptable for small-to-medium sets. For high-write workloads, use a skip list or `btree` package.

```go
package main

import (
	"fmt"
	"sync"
)

// Handler processes a typed event.
type Handler[T any] func(event T)

// subscription holds a handler and its remove function.
type subscription[T any] struct {
	handler Handler[T]
}

// EventBus dispatches typed events to registered handlers.
type EventBus[T any] struct {
	mu   sync.RWMutex
	subs map[uint64]*subscription[T]
	next uint64
}

func NewEventBus[T any]() *EventBus[T] {
	return &EventBus[T]{subs: make(map[uint64]*subscription[T])}
}

// Subscribe registers a handler and returns an unsubscribe function.
func (b *EventBus[T]) Subscribe(h Handler[T]) func() {
	b.mu.Lock()
	defer b.mu.Unlock()
	id := b.next
	b.next++
	b.subs[id] = &subscription[T]{handler: h}
	return func() {
		b.mu.Lock()
		delete(b.subs, id)
		b.mu.Unlock()
	}
}

// Publish sends event to all subscribers concurrently.
func (b *EventBus[T]) Publish(event T) {
	b.mu.RLock()
	subs := make([]*subscription[T], 0, len(b.subs))
	for _, s := range b.subs {
		subs = append(subs, s)
	}
	b.mu.RUnlock()

	var wg sync.WaitGroup
	for _, s := range subs {
		s := s
		wg.Add(1)
		go func() {
			defer wg.Done()
			s.handler(event)
		}()
	}
	wg.Wait()
}

// Example typed events.
type UserCreated struct{ Name, Email string }
type OrderPlaced struct{ OrderID int; Amount float64 }

func main() {
	userBus := NewEventBus[UserCreated]()
	orderBus := NewEventBus[OrderPlaced]()

	unsub1 := userBus.Subscribe(func(e UserCreated) {
		fmt.Printf("email service: welcome %s at %s\n", e.Name, e.Email)
	})
	userBus.Subscribe(func(e UserCreated) {
		fmt.Printf("audit log: user %s created\n", e.Name)
	})
	orderBus.Subscribe(func(e OrderPlaced) {
		fmt.Printf("inventory: process order %d ($%.2f)\n", e.OrderID, e.Amount)
	})

	userBus.Publish(UserCreated{Name: "Alice", Email: "alice@example.com"})
	orderBus.Publish(OrderPlaced{OrderID: 1001, Amount: 99.99})

	// Unsubscribe email service.
	unsub1()
	fmt.Println("--- after unsubscribe ---")
	userBus.Publish(UserCreated{Name: "Bob", Email: "bob@example.com"})
	// Only audit log receives this event.
}
```

Copying the subscriber slice under RLock then calling handlers outside the lock prevents deadlocks when handlers try to subscribe/unsubscribe. Each handler runs in its own goroutine and `Publish` waits for all to finish — for fire-and-forget semantics, remove the WaitGroup and launch handlers without waiting.

```go
package main

import (
	"errors"
	"fmt"
	"sync"
	"time"
)

type State int

const (
	Closed   State = iota // normal operation
	Open                  // fast-fail
	HalfOpen              // probe state
)

func (s State) String() string {
	return [...]string{"Closed", "Open", "HalfOpen"}[s]
}

var ErrCircuitOpen = errors.New("circuit breaker is open")

type CircuitBreaker struct {
	mu            sync.Mutex
	state         State
	failures      int
	successes     int
	maxFailures   int
	successNeeded int
	resetTimeout  time.Duration
	nextAttempt   time.Time
}

func NewCircuitBreaker(maxFailures, successNeeded int, resetTimeout time.Duration) *CircuitBreaker {
	return &CircuitBreaker{
		maxFailures:   maxFailures,
		successNeeded: successNeeded,
		resetTimeout:  resetTimeout,
		state:         Closed,
	}
}

// Do executes fn if the circuit allows it.
func (cb *CircuitBreaker) Do(fn func() error) error {
	cb.mu.Lock()
	switch cb.state {
	case Open:
		if time.Now().Before(cb.nextAttempt) {
			cb.mu.Unlock()
			return ErrCircuitOpen
		}
		// Transition to half-open to probe.
		cb.state = HalfOpen
		cb.successes = 0
	}
	cb.mu.Unlock()

	err := fn()

	cb.mu.Lock()
	defer cb.mu.Unlock()

	if err != nil {
		cb.failures++
		cb.successes = 0
		if cb.state == HalfOpen || cb.failures >= cb.maxFailures {
			cb.state = Open
			cb.nextAttempt = time.Now().Add(cb.resetTimeout)
			cb.failures = 0
			fmt.Println("circuit breaker: OPEN")
		}
		return err
	}

	// Success path.
	cb.successes++
	if cb.state == HalfOpen && cb.successes >= cb.successNeeded {
		cb.state = Closed
		cb.failures = 0
		fmt.Println("circuit breaker: CLOSED (recovered)")
	}
	return nil
}

func (cb *CircuitBreaker) State() State {
	cb.mu.Lock()
	defer cb.mu.Unlock()
	return cb.state
}

func main() {
	cb := NewCircuitBreaker(3, 2, 500*time.Millisecond)

	failUntil := 6
	operation := func() error {
		failUntil--
		if failUntil > 0 {
			return errors.New("service unavailable")
		}
		return nil
	}

	for i := 0; i < 12; i++ {
		err := cb.Do(operation)
		fmt.Printf("call %2d: state=%-9s err=%v\n", i+1, cb.State(), err)
		time.Sleep(100 * time.Millisecond)
	}
}
```

The state machine: Closed → Open (on maxFailures consecutive errors), Open → HalfOpen (after resetTimeout), HalfOpen → Closed (on successNeeded consecutive successes) or back to Open (on any failure). The mutex protects all state transitions atomically.

```go
package main

import (
	"context"
	"log"
	"net/http"
	"time"
)

// Middleware is a function that wraps an http.Handler.
type Middleware func(http.Handler) http.Handler

// Chain applies middlewares in order: first listed = outermost wrapper.
func Chain(h http.Handler, mws ...Middleware) http.Handler {
	for i := len(mws) - 1; i >= 0; i-- {
		h = mws[i](h)
	}
	return h
}

func Logger(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		next.ServeHTTP(w, r)
		log.Printf("%s %s %s", r.Method, r.URL.Path, time.Since(start))
	})
}

func Recovery(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if err := recover(); err != nil {
				log.Printf("panic recovered: %v", err)
				http.Error(w, "internal server error", http.StatusInternalServerError)
			}
		}()
		next.ServeHTTP(w, r)
	})
}

func Timeout(d time.Duration) Middleware {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			ctx, cancel := context.WithTimeout(r.Context(), d)
			defer cancel()
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("ok"))
	})

	handler := Chain(mux,
		Recovery,
		Logger,
		Timeout(5*time.Second),
	)

	log.Fatal(http.ListenAndServe(":8080", handler))
}
```

Key points:
- `Chain` reverses the slice so the first middleware listed wraps outermost — matches reading order.
- `Recovery` must be outermost so it catches panics from every layer below it.
- `Timeout` uses `r.WithContext` to propagate cancellation; handlers must check `ctx.Done()` to actually respect it.
- Each middleware is a plain function — no interface{}, no magic, easy to test in isolation.

```go
package main

import (
	"log"
	"net/http"
	"net/http/httputil"
	"net/url"
	"time"
)

func newProxy(target string) (*httputil.ReverseProxy, error) {
	u, err := url.Parse(target)
	if err != nil {
		return nil, err
	}

	proxy := httputil.NewSingleHostReverseProxy(u)

	// Customize the default Director to add headers.
	original := proxy.Director
	proxy.Director = func(req *http.Request) {
		original(req) // preserves host rewriting, scheme, etc.
		req.Header.Set("X-Forwarded-By", "go-proxy")
		req.Header.Del("X-Internal-Secret") // strip sensitive headers
	}

	// ModifyResponse runs on successful backend responses.
	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("X-Proxy", "go-proxy/1.0")
		return nil
	}

	// ErrorHandler catches dial failures, timeouts, etc.
	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		log.Printf("proxy error to %s: %v", r.URL, err)
		http.Error(w, "upstream unavailable", http.StatusBadGateway)
	}

	// Custom transport with sane timeouts.
	proxy.Transport = &http.Transport{
		ResponseHeaderTimeout: 10 * time.Second,
		IdleConnTimeout:       90 * time.Second,
		MaxIdleConnsPerHost:   100,
	}

	return proxy, nil
}

func main() {
	proxy, err := newProxy("http://localhost:9090")
	if err != nil {
		log.Fatal(err)
	}
	log.Fatal(http.ListenAndServe(":8080", proxy))
}
```

- Always call the original `Director` first — it handles scheme/host rewriting that `NewSingleHostReverseProxy` sets up.
- `ErrorHandler` is only called for transport-level failures (connection refused, timeout). Backend 4xx/5xx go through `ModifyResponse`.
- Set `MaxIdleConnsPerHost` to avoid creating a new TCP connection per request under load.
- Never set `req.RequestURI` manually — `Director` owns that; setting it causes a panic.

```go
package main

import (
	"errors"
	"fmt"
)

// Sentinel error — use for identity checks via errors.Is.
var ErrNotFound = errors.New("not found")

// Custom structured error — use when callers need to inspect fields.
type ValidationError struct {
	Field   string
	Message string
}

func (e *ValidationError) Error() string {
	return fmt.Sprintf("validation error: field %q — %s", e.Field, e.Message)
}

func findUser(id int) error {
	if id <= 0 {
		// Wrap a sentinel with context.
		return fmt.Errorf("findUser(%d): %w", id, ErrNotFound)
	}
	return nil
}

func validateAge(age int) error {
	if age < 0 {
		return &ValidationError{Field: "age", Message: "must be non-negative"}
	}
	return nil
}

func process(id, age int) error {
	if err := findUser(id); err != nil {
		return fmt.Errorf("process: %w", err) // wrap again — chain still works
	}
	if err := validateAge(age); err != nil {
		return fmt.Errorf("process: %w", err)
	}
	return nil
}

func main() {
	err := process(-1, 25)

	// errors.Is unwraps the entire chain.
	if errors.Is(err, ErrNotFound) {
		fmt.Println("user not found — show 404")
	}

	err2 := process(1, -5)

	// errors.As unwraps until it finds a *ValidationError.
	var ve *ValidationError
	if errors.As(err2, &ve) {
		fmt.Printf("bad field: %s — %s\n", ve.Field, ve.Message)
	}
}
```

- `%w` (not `%v`) is what makes `errors.Is`/`errors.As` work through the chain. Using `%v` breaks unwrapping.
- `errors.Is` uses `==` comparison (or an `Is(error) bool` method). It traverses the whole chain.
- `errors.As` needs a pointer to the target type (`&ve`, not `ve`). It sets the target if found.
- Sentinel errors are package-level vars — capitalize them to export, keep them unexported for internal use.
- Never embed raw strings as errors when callers need to branch on error type — use sentinels or typed errors.

```go
package main

import "fmt"

type Set[T comparable] struct {
	m map[T]struct{}
}

func NewSet[T comparable](items ...T) Set[T] {
	s := Set[T]{m: make(map[T]struct{}, len(items))}
	for _, item := range items {
		s.m[item] = struct{}{}
	}
	return s
}

func (s *Set[T]) Add(v T)            { s.m[v] = struct{}{} }
func (s *Set[T]) Remove(v T)         { delete(s.m, v) }
func (s *Set[T]) Contains(v T) bool  { _, ok := s.m[v]; return ok }
func (s *Set[T]) Len() int           { return len(s.m) }

func (s *Set[T]) Slice() []T {
	out := make([]T, 0, len(s.m))
	for k := range s.m {
		out = append(out, k)
	}
	return out
}

// Union returns a new set with all elements from both sets.
func Union[T comparable](a, b Set[T]) Set[T] {
	result := NewSet[T](a.Slice()...)
	for k := range b.m {
		result.Add(k)
	}
	return result
}

// Intersection returns elements present in both sets.
func Intersection[T comparable](a, b Set[T]) Set[T] {
	result := NewSet[T]()
	for k := range a.m {
		if b.Contains(k) {
			result.Add(k)
		}
	}
	return result
}

func main() {
	a := NewSet(1, 2, 3)
	b := NewSet(3, 4, 5)

	u := Union(a, b)
	fmt.Println(u.Slice())             // [1 2 3 4 5] (order varies)
	fmt.Println(Intersection(a, b).Slice()) // [3]

	a.Remove(2)
	fmt.Println(a.Contains(2)) // false
}
```

- `comparable` constraint allows map keys — it includes all types that support `==`.
- `struct{}` as map value uses zero bytes — preferred over `bool` for sets.
- `Union`/`Intersection` are free functions so they can be generic over `T` independently of any receiver.
- Pointer receivers on `Add`/`Remove` so mutations are visible to the caller — value receiver on `Contains`/`Len` is fine.

```go
package main

import (
	"crypto/tls"
	"log"
	"net/http"
)

func tlsConfig() *tls.Config {
	return &tls.Config{
		// Require TLS 1.2 minimum; 1.3 is preferred automatically.
		MinVersion: tls.VersionTLS12,

		// Restrict to strong cipher suites (only matters for TLS 1.2;
		// TLS 1.3 ciphers are not configurable).
		CipherSuites: []uint16{
			tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305_SHA256,
			tls.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305_SHA256,
		},

		// ALPN: advertise h2 so net/http enables HTTP/2 automatically.
		NextProtos: []string{"h2", "http/1.1"},

		// Prefer server's cipher order for TLS 1.2.
		PreferServerCipherSuites: true,

		// Curve preferences — P256 and X25519 are widely supported.
		CurvePreferences: []tls.CurveID{
			tls.X25519,
			tls.CurveP256,
		},
	}
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("TLS OK"))
	})

	srv := &http.Server{
		Addr:      ":443",
		Handler:   mux,
		TLSConfig: tlsConfig(),
	}

	// ListenAndServeTLS loads the cert and starts TLS negotiation.
	log.Fatal(srv.ListenAndServeTLS("cert.pem", "key.pem"))
}
```

- `MinVersion: tls.VersionTLS12` is the current industry minimum — TLS 1.0/1.1 are deprecated.
- TLS 1.3 ciphers are fixed by the spec; the `CipherSuites` field only affects TLS 1.2 connections.
- `NextProtos: ["h2", "http/1.1"]` enables HTTP/2 via ALPN negotiation — without this, `net/http` won't upgrade.
- `X25519` is faster than P-384/P-521 on modern hardware and just as secure for key exchange.
- Never disable `PreferServerCipherSuites` — clients may have weak preferences.

```go
package main

import (
	"compress/gzip"
	"io"
	"log"
	"net/http"
	"os"
)

// streamDownload fetches a URL and writes it directly to dst without
// loading the full response into memory.
func streamDownload(url string, dst io.Writer) error {
	resp, err := http.Get(url)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("unexpected status: %s", resp.Status)
	}

	// io.Copy uses a 32KB internal buffer — never loads full body.
	_, err = io.Copy(dst, resp.Body)
	return err
}

// streamingHandler sends a large response to a client chunk by chunk.
func streamingHandler(w http.ResponseWriter, r *http.Request) {
	f, err := os.Open("large_file.bin")
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer f.Close()

	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Transfer-Encoding", "chunked")

	gw := gzip.NewWriter(w)
	defer gw.Close()
	w.Header().Set("Content-Encoding", "gzip")

	// Flush periodically for long-lived streams.
	pr, pw := io.Pipe()
	go func() {
		defer pw.Close()
		io.Copy(pw, f)
	}()

	buf := make([]byte, 64*1024)
	flusher, canFlush := w.(http.Flusher)
	for {
		n, err := pr.Read(buf)
		if n > 0 {
			gw.Write(buf[:n])
			gw.Flush()
			if canFlush {
				flusher.Flush() // flush HTTP response buffer to client
			}
		}
		if err == io.EOF {
			break
		}
		if err != nil {
			log.Printf("stream error: %v", err)
			return
		}
	}
}

func main() {
	http.HandleFunc("/stream", streamingHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

- `io.Copy` uses a 32KB buffer internally — never materializes the full response body.
- `http.Flusher` type assertion lets you push chunks to the client before the handler returns — critical for real-time streams.
- `gzip.Flush()` flushes the compressor buffer; `http.Flusher.Flush()` flushes the HTTP layer — you need both.
- `resp.Body` must always be fully drained and closed to allow TCP connection reuse.

```go
package main

import (
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
)

const (
	maxMemory  = 10 << 20 // 10 MB for in-memory parts
	maxUpload  = 50 << 20 // 50 MB total file size
	uploadDir  = "/tmp/uploads"
)

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Cap the request body before parsing to prevent OOM.
	r.Body = http.MaxBytesReader(w, r.Body, maxUpload)

	// ParseMultipartForm spills to temp files if part > maxMemory.
	if err := r.ParseMultipartForm(maxMemory); err != nil {
		http.Error(w, "request too large or invalid", http.StatusBadRequest)
		return
	}
	defer r.MultipartForm.RemoveAll() // clean up temp files

	for _, headers := range r.MultipartForm.File {
		for _, header := range headers {
			if err := saveFile(header, uploadDir); err != nil {
				http.Error(w, err.Error(), http.StatusInternalServerError)
				return
			}
		}
	}

	w.WriteHeader(http.StatusCreated)
	fmt.Fprintf(w, "uploaded %d file(s)", len(r.MultipartForm.File))
}

func saveFile(header *multipart.FileHeader, dir string) error {
	src, err := header.Open()
	if err != nil {
		return err
	}
	defer src.Close()

	// Sanitize filename — never trust client input for path components.
	name := filepath.Base(filepath.Clean(header.Filename))
	dst, err := os.Create(filepath.Join(dir, name))
	if err != nil {
		return err
	}
	defer dst.Close()

	_, err = io.Copy(dst, src)
	return err
}

func main() {
	os.MkdirAll(uploadDir, 0o755)
	http.HandleFunc("/upload", uploadHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

- `http.MaxBytesReader` wraps the body before `ParseMultipartForm` — without it, a malicious client can OOM the server by sending an arbitrarily large body.
- `ParseMultipartForm(maxMemory)` keeps small parts in memory and spills large ones to disk automatically.
- Always call `r.MultipartForm.RemoveAll()` to delete the spilled temp files when done.
- `filepath.Base(filepath.Clean(...))` strips directory traversal (`../`) from client-supplied filenames — critical security step.

```go
package main

import (
	"net"
	"net/http"
	"time"
)

// newHTTPClient returns a production-ready http.Client.
// Never use http.DefaultClient in production — it has no timeouts.
func newHTTPClient() *http.Client {
	transport := &http.Transport{
		// Dial timeout — how long to wait for TCP connection.
		DialContext: (&net.Dialer{
			Timeout:   5 * time.Second,
			KeepAlive: 30 * time.Second,
		}).DialContext,

		// TLS handshake timeout.
		TLSHandshakeTimeout: 5 * time.Second,

		// Wait for server to start sending response headers.
		ResponseHeaderTimeout: 10 * time.Second,

		// How long idle connections stay in the pool.
		IdleConnTimeout: 90 * time.Second,

		// Expect: 100-continue handshake timeout.
		ExpectContinueTimeout: 1 * time.Second,

		// Connection pool sizing.
		MaxIdleConns:        200,
		MaxIdleConnsPerHost: 20,
		MaxConnsPerHost:     50,

		// Compression — let the transport handle gzip.
		DisableCompression: false,
	}

	return &http.Client{
		Transport: transport,
		// Total request deadline (includes retries, redirects, body read).
		Timeout: 30 * time.Second,
	}
}

// Reuse the client — it's safe for concurrent use and maintains the pool.
var client = newHTTPClient()
```

Key timeout breakdown:
| Field | Controls |
|---|---|
| `Dialer.Timeout` | TCP connect |
| `TLSHandshakeTimeout` | TLS negotiation |
| `ResponseHeaderTimeout` | First byte of headers |
| `Client.Timeout` | Entire round trip including body |

- `http.DefaultClient` has zero timeouts — a slow server will block your goroutine forever.
- Create one client per service, not per request. The transport maintains the connection pool.
- `MaxIdleConnsPerHost` defaults to 2 — far too low for any real service; set it to your expected concurrency.
- `Client.Timeout` starts the clock at the `Do()` call and cancels via context when it fires.

```go
package main

import (
	"log"
	"net/http"
	"sync"

	"golang.org/x/net/websocket"
)

// Hub tracks connected clients.
type Hub struct {
	mu      sync.RWMutex
	clients map[*websocket.Conn]struct{}
}

func newHub() *Hub {
	return &Hub{clients: make(map[*websocket.Conn]struct{})}
}

func (h *Hub) add(c *websocket.Conn) {
	h.mu.Lock()
	h.clients[c] = struct{}{}
	h.mu.Unlock()
}

func (h *Hub) remove(c *websocket.Conn) {
	h.mu.Lock()
	delete(h.clients, c)
	h.mu.Unlock()
}

// Broadcast sends a message to all connected clients.
func (h *Hub) Broadcast(msg string) {
	h.mu.RLock()
	defer h.mu.RUnlock()
	for c := range h.clients {
		if err := websocket.Message.Send(c, msg); err != nil {
			log.Printf("send error: %v", err)
		}
	}
}

func echoHandler(hub *Hub) websocket.Handler {
	return func(ws *websocket.Conn) {
		hub.add(ws)
		defer func() {
			hub.remove(ws)
			ws.Close()
		}()

		var msg string
		for {
			if err := websocket.Message.Receive(ws, &msg); err != nil {
				break // client disconnected
			}
			if err := websocket.Message.Send(ws, msg); err != nil {
				break
			}
		}
	}
}

func main() {
	hub := newHub()
	http.Handle("/ws", echoHandler(hub))
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

- Each WebSocket connection gets its own goroutine from `net/http` — the handler blocks until the connection closes.
- `sync.RWMutex` protects the client map: `RLock` for broadcast reads, `Lock` for add/remove writes.
- Always `defer ws.Close()` — a dropped connection without close leaks the file descriptor.
- For production, prefer `github.com/gorilla/websocket` — it has better ping/pong, message size limits, and connection state management.

```go
package main

import (
	"context"
	"fmt"
	"log"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/spf13/cobra"
)

var verbose bool

func newRootCmd() *cobra.Command {
	root := &cobra.Command{
		Use:   "mytool",
		Short: "A demo CLI tool",
		// PersistentPreRunE runs before every subcommand.
		PersistentPreRunE: func(cmd *cobra.Command, args []string) error {
			if verbose {
				log.SetFlags(log.LstdFlags | log.Lshortfile)
			}
			return nil
		},
	}
	// Persistent flag — available to all subcommands.
	root.PersistentFlags().BoolVarP(&verbose, "verbose", "v", false, "verbose logging")

	root.AddCommand(newServeCmd(), newRunCmd())
	return root
}

func newServeCmd() *cobra.Command {
	var port int
	cmd := &cobra.Command{
		Use:   "serve",
		Short: "Start the server",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := cmd.Context()
			fmt.Printf("serving on :%d\n", port)
			<-ctx.Done() // block until signal
			fmt.Println("server stopped")
			return nil
		},
	}
	cmd.Flags().IntVarP(&port, "port", "p", 8080, "listen port")
	return cmd
}

func newRunCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "run [task]",
		Short: "Run a named task",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			fmt.Printf("running task: %s\n", args[0])
			return nil
		},
	}
}

func main() {
	ctx, stop := signal.NotifyContext(context.Background(),
		syscall.SIGINT, syscall.SIGTERM)
	defer stop()

	root := newRootCmd()
	if err := root.ExecuteContext(ctx); err != nil {
		os.Exit(1)
	}
}
```

- `signal.NotifyContext` (Go 1.16+) is the cleanest way to wire OS signals to a context — no manual signal channel needed.
- `root.ExecuteContext(ctx)` passes the context into every `RunE` via `cmd.Context()` — subcommands get cancellation for free.
- `PersistentPreRunE` on root runs before every subcommand — use it for global setup (logging, config loading).
- `RunE` (not `Run`) lets subcommands return errors, which cobra prints and converts to a non-zero exit code.

```go
package main

import (
	"log"
	"os"
	"os/signal"
	"sync/atomic"
	"syscall"
	"unsafe"
)

type Config struct {
	LogLevel string
	Port     int
}

func loadConfig() *Config {
	// In reality: read from file/env.
	return &Config{LogLevel: "info", Port: 8080}
}

// Atomic pointer swap for lock-free config access.
var currentConfig atomic.Pointer[Config]

func getConfig() *Config {
	return currentConfig.Load()
}

func reloadConfig() {
	newCfg := loadConfig()
	currentConfig.Store(newCfg)
	log.Printf("config reloaded: %+v", newCfg)
}

func main() {
	currentConfig.Store(loadConfig())

	// Buffered channels prevent signal loss during slow handler startup.
	sigs := make(chan os.Signal, 1)
	signal.Notify(sigs, syscall.SIGTERM, syscall.SIGINT, syscall.SIGHUP)

	log.Println("process started, PID:", os.Getpid())

	for {
		sig := <-sigs
		switch sig {
		case syscall.SIGHUP:
			log.Println("SIGHUP received — reloading config")
			reloadConfig()

		case syscall.SIGTERM, syscall.SIGINT:
			log.Println("shutdown signal received")
			// Perform cleanup here: close DB, drain queues, etc.
			log.Println("clean shutdown complete")
			return
		}
	}
}
```

- `signal.Notify` with a buffered channel (size >= 1) prevents dropping signals if your code isn't blocking on the receive yet.
- `SIGHUP` is the Unix convention for "reload config without restart" — daemons like nginx follow this pattern.
- `atomic.Pointer[T]` (Go 1.19+) allows lock-free pointer swaps — handlers reading config see either the old or new version atomically, never a torn read.
- Call `signal.Stop(sigs)` before process exit if you want to restore default signal behavior (e.g., re-raise SIGTERM to parent).

```go
package main

import (
	"bytes"
	"context"
	"fmt"
	"os/exec"
	"time"
)

type Result struct {
	Stdout   string
	Stderr   string
	ExitCode int
}

func run(ctx context.Context, name string, args ...string) (Result, error) {
	var stdout, stderr bytes.Buffer

	cmd := exec.CommandContext(ctx, name, args...)
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()

	res := Result{
		Stdout: stdout.String(),
		Stderr: stderr.String(),
	}

	if err != nil {
		var exitErr *exec.ExitError
		if errors.As(err, &exitErr) {
			res.ExitCode = exitErr.ExitCode()
			return res, nil // non-zero exit is caller's problem, not an I/O error
		}
		if ctx.Err() != nil {
			return res, fmt.Errorf("command timed out or cancelled: %w", ctx.Err())
		}
		return res, fmt.Errorf("exec: %w", err)
	}

	return res, nil
}

func main() {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	res, err := run(ctx, "ls", "-la", "/tmp")
	if err != nil {
		fmt.Println("error:", err)
		return
	}
	fmt.Printf("exit: %d\nstdout:\n%s", res.ExitCode, res.Stdout)
	if res.Stderr != "" {
		fmt.Printf("stderr:\n%s", res.Stderr)
	}
}
```

- `exec.CommandContext` sends SIGKILL when the context expires — process is hard-killed, not gracefully stopped.
- Non-zero exit codes come back as `*exec.ExitError` — distinguish from actual I/O/spawn failures by type-asserting.
- Never use `cmd.Output()` when you need both stdout and stderr separately; assign `cmd.Stdout` and `cmd.Stderr` directly.
- Never pass user input directly as a single shell string — always pass args as separate elements to avoid shell injection.

```go
package main

import (
	"fmt"
	"io/fs"
	"os"
	"path/filepath"
	"strings"
	"sync"
)

func findFiles(root, ext string, workers int) ([]string, error) {
	paths := make(chan string, 128)
	results := make([]string, 0, 64)
	var mu sync.Mutex
	var wg sync.WaitGroup

	// Workers consume paths and collect matches.
	for i := 0; i < workers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for p := range paths {
				// Could do file inspection here (e.g., magic bytes check).
				mu.Lock()
				results = append(results, p)
				mu.Unlock()
			}
		}()
	}

	// WalkDir is faster than filepath.Walk — it avoids Lstat calls.
	err := filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			// Permission errors etc — log and continue.
			fmt.Fprintf(os.Stderr, "walk error at %s: %v\n", path, err)
			return nil
		}
		if d.IsDir() {
			// Skip hidden directories.
			if strings.HasPrefix(d.Name(), ".") && path != root {
				return filepath.SkipDir
			}
			return nil
		}
		if strings.EqualFold(filepath.Ext(d.Name()), ext) {
			paths <- path
		}
		return nil
	})

	close(paths)
	wg.Wait()
	return results, err
}

func main() {
	files, err := findFiles(".", ".go", 4)
	if err != nil {
		fmt.Fprintln(os.Stderr, err)
		os.Exit(1)
	}
	for _, f := range files {
		fmt.Println(f)
	}
}
```

- `filepath.WalkDir` (Go 1.16+) is preferred over `filepath.Walk` — `DirEntry` avoids a `Lstat` syscall per entry.
- Return `filepath.SkipDir` from the callback to prune entire subtrees without error.
- Return `nil` (not the error) for non-fatal walk errors to continue traversal.
- The channel buffers 128 entries to decouple the walker from workers; tune based on expected directory size.

```go
package main

import (
	"context"
	"database/sql"
	"fmt"
)

// transfer moves amount from src to dst atomically.
func transfer(ctx context.Context, db *sql.DB, src, dst int64, amount float64) error {
	tx, err := db.BeginTx(ctx, &sql.TxOptions{
		Isolation: sql.LevelSerializable,
		ReadOnly:  false,
	})
	if err != nil {
		return fmt.Errorf("begin tx: %w", err)
	}
	// Ensure rollback if we return with an error.
	// If Commit() already succeeded, Rollback() is a no-op.
	defer tx.Rollback()

	// Debit source account.
	result, err := tx.ExecContext(ctx,
		`UPDATE accounts SET balance = balance - $1 WHERE id = $2 AND balance >= $1`,
		amount, src)
	if err != nil {
		return fmt.Errorf("debit: %w", err)
	}
	rows, _ := result.RowsAffected()
	if rows == 0 {
		return fmt.Errorf("insufficient funds in account %d", src)
	}

	// Credit destination account.
	_, err = tx.ExecContext(ctx,
		`UPDATE accounts SET balance = balance + $1 WHERE id = $2`,
		amount, dst)
	if err != nil {
		return fmt.Errorf("credit: %w", err)
	}

	// Commit — if this succeeds, defer Rollback() becomes a no-op.
	if err := tx.Commit(); err != nil {
		return fmt.Errorf("commit: %w", err)
	}
	return nil
}
```

- `defer tx.Rollback()` is idiomatic — put it immediately after `BeginTx`. A successful `Commit()` makes the subsequent `Rollback()` a no-op (it returns `sql.ErrTxDone`, which is ignored).
- `BeginTx` with a context means the transaction is cancelled if the context expires — avoids holding DB locks indefinitely.
- Check `RowsAffected()` after `UPDATE` — zero rows means a logic error, not a SQL error.
- `sql.LevelSerializable` is the strictest isolation but slowest. Use `sql.LevelReadCommitted` for most OLTP workloads.

```go
package main

import (
	"context"
	"database/sql"
	"fmt"
	"log"

	_ "github.com/lib/pq"
)

type UserStore struct {
	db         *sql.DB
	getByID    *sql.Stmt
	insert     *sql.Stmt
	deleteByID *sql.Stmt
}

func NewUserStore(ctx context.Context, db *sql.DB) (*UserStore, error) {
	prepare := func(q string) (*sql.Stmt, error) {
		stmt, err := db.PrepareContext(ctx, q)
		if err != nil {
			return nil, fmt.Errorf("prepare %q: %w", q, err)
		}
		return stmt, nil
	}

	getByID, err := prepare(`SELECT id, name, email FROM users WHERE id = $1`)
	if err != nil { return nil, err }

	insert, err := prepare(`INSERT INTO users (name, email) VALUES ($1, $2) RETURNING id`)
	if err != nil { return nil, err }

	delByID, err := prepare(`DELETE FROM users WHERE id = $1`)
	if err != nil { return nil, err }

	return &UserStore{db: db, getByID: getByID, insert: insert, deleteByID: delByID}, nil
}

func (s *UserStore) Close() {
	s.getByID.Close()
	s.insert.Close()
	s.deleteByID.Close()
}

type User struct { ID int64; Name, Email string }

func (s *UserStore) Get(ctx context.Context, id int64) (*User, error) {
	var u User
	err := s.getByID.QueryRowContext(ctx, id).Scan(&u.ID, &u.Name, &u.Email)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get user: %w", err)
	}
	return &u, nil
}

func (s *UserStore) Insert(ctx context.Context, name, email string) (int64, error) {
	var id int64
	err := s.insert.QueryRowContext(ctx, name, email).Scan(&id)
	if err != nil {
		return 0, fmt.Errorf("insert user: %w", err)
	}
	return id, nil
}
```

- Prepare statements once at startup (not per query) — each `PrepareContext` does a round-trip to the DB server.
- Parameterized queries (`$1`, `?`) prevent SQL injection — the DB driver handles quoting.
- Close prepared statements in `Close()` to release server-side resources.
- `sql.ErrNoRows` from `QueryRowContext` is a normal "not found" — handle it, don't treat it as an error.

