package concat_test

import (
	"strings"
	"testing"
)

const n = 1000

// BenchmarkPlusConcat uses += — O(n²) copies.
func BenchmarkPlusConcat(b *testing.B) {
	for i := 0; i < b.N; i++ {
		var s string
		for j := 0; j < n; j++ {
			s += "hello"
		}
		_ = s
	}
}

// BenchmarkBuilderConcat uses strings.Builder — O(n) amortized.
func BenchmarkBuilderConcat(b *testing.B) {
	for i := 0; i < b.N; i++ {
		var sb strings.Builder
		sb.Grow(n * 5) // pre-allocate to eliminate growth copies
		for j := 0; j < n; j++ {
			sb.WriteString("hello")
		}
		_ = sb.String()
	}
}

// BenchmarkBuilderNoGrow shows cost of missing Grow.
func BenchmarkBuilderNoGrow(b *testing.B) {
	for i := 0; i < b.N; i++ {
		var sb strings.Builder
		for j := 0; j < n; j++ {
			sb.WriteString("hello")
		}
		_ = sb.String()
	}
}

// Sub-benchmark: vary N to find scaling behavior.
func BenchmarkBuilderScale(b *testing.B) {
	for _, size := range []int{10, 100, 1000, 10000} {
		size := size
		b.Run(fmt.Sprintf("n=%d", size), func(b *testing.B) {
			for i := 0; i < b.N; i++ {
				var sb strings.Builder
				sb.Grow(size * 5)
				for j := 0; j < size; j++ {
					sb.WriteString("hello")
				}
				_ = sb.String()
			}
		})
	}
}
