package main

import (
	"context"
	"fmt"
	"sync"
)

type Task func(ctx context.Context) error

type Pool struct {
	tasks chan Task
	wg    sync.WaitGroup
	mu    sync.Mutex
	errs  []error
}

func NewPool(ctx context.Context, workers int) *Pool {
	p := &Pool{
		tasks: make(chan Task, workers*2),
	}
	for i := 0; i < workers; i++ {
		p.wg.Add(1)
		go p.run(ctx)
	}
	return p
}

func (p *Pool) run(ctx context.Context) {
	defer p.wg.Done()
	for {
		select {
		case task, ok := <-p.tasks:
			if !ok {
				return // channel closed — drain complete
			}
			if err := task(ctx); err != nil {
				p.mu.Lock()
				p.errs = append(p.errs, err)
				p.mu.Unlock()
			}
		case <-ctx.Done():
			return
		}
	}
}

// Submit enqueues a task. Blocks if pool is at capacity.
func (p *Pool) Submit(task Task) { p.tasks <- task }

// Wait closes the queue and waits for all workers to finish.
func (p *Pool) Wait() []error {
	close(p.tasks)
	p.wg.Wait()
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.errs
}

func main() {
	ctx := context.Background()
	pool := NewPool(ctx, 4)

	for i := 0; i < 20; i++ {
		i := i
		pool.Submit(func(ctx context.Context) error {
			fmt.Printf("task %d\n", i)
			if i == 7 {
				return fmt.Errorf("task 7 failed")
			}
			return nil
		})
	}

	if errs := pool.Wait(); len(errs) > 0 {
		for _, e := range errs {
			fmt.Println("error:", e)
		}
	}
}
```

- Closing `p.tasks` signals workers to drain remaining tasks then exit — never close from inside a worker.
- `p.wg.Add(1)` is called before `go p.run()` — adding after the goroutine starts is a race condition.
- Buffered task channel (`workers*2`) decouples submitters from workers.
- Context cancellation causes workers to exit after their current task — no abandoned in-flight work.

```go
package main

import (
	"context"
	"fmt"
	"time"
)

type RateLimiter struct {
	tokens chan struct{}
	stop   chan struct{}
}

// NewRateLimiter allows `rate` operations per second with a burst of `burst`.
func NewRateLimiter(rate int, burst int) *RateLimiter {
	rl := &RateLimiter{
		tokens: make(chan struct{}, burst),
		stop:   make(chan struct{}),
	}
	// Pre-fill burst capacity.
	for i := 0; i < burst; i++ {
		rl.tokens <- struct{}{}
	}

	ticker := time.NewTicker(time.Second / time.Duration(rate))
	go func() {
		defer ticker.Stop()
		for {
			select {
			case <-ticker.C:
				select {
				case rl.tokens <- struct{}{}: // refill one token
				default: // bucket full, discard
				}
			case <-rl.stop:
				return
			}
		}
	}()
	return rl
}

// Wait blocks until a token is available or ctx is cancelled.
func (rl *RateLimiter) Wait(ctx context.Context) error {
	select {
	case <-rl.tokens:
		return nil
	case <-ctx.Done():
		return ctx.Err()
	}
}

// TryAcquire returns true immediately if a token is available.
func (rl *RateLimiter) TryAcquire() bool {
	select {
	case <-rl.tokens:
		return true
	default:
		return false
	}
}

func (rl *RateLimiter) Stop() { close(rl.stop) }

func main() {
	rl := NewRateLimiter(10, 5) // 10 req/s, burst 5
	defer rl.Stop()

	ctx := context.Background()
	for i := 0; i < 15; i++ {
		if err := rl.Wait(ctx); err != nil {
			fmt.Println("cancelled")
			break
		}
		fmt.Printf("request %d at %s\n", i, time.Now().Format("15:04:05.000"))
	}
}
```

- The buffered `tokens` channel IS the bucket — capacity equals the burst size.
- The inner non-blocking `select` in the ticker goroutine discards overflow — bucket stays bounded.
- `Wait` uses `select` so it respects context cancellation — no goroutine leaks on shutdown.
- For production, use `golang.org/x/time/rate` which handles fractional rates and is well-tested.

```go
package main

import (
	"context"
	"fmt"
	"net/http"
	_ "net/http/pprof"
	"time"
)

// LEAKY: goroutine blocks forever — channel never closed.
func leakyWorker(ch <-chan int) {
	go func() {
		for v := range ch { // blocks forever if ch never closes
			_ = v
		}
	}()
}

// FIXED: goroutine exits on context cancellation or channel close.
func fixedWorker(ctx context.Context, ch <-chan int) {
	go func() {
		for {
			select {
			case v, ok := <-ch:
				if !ok {
					return // channel closed
				}
				_ = v
			case <-ctx.Done():
				return // context cancelled
			}
		}
	}()
}

func main() {
	// Expose pprof — listen on localhost only.
	go http.ListenAndServe("localhost:6060", nil)

	ctx, cancel := context.WithCancel(context.Background())
	ch := make(chan int)

	fixedWorker(ctx, ch)

	time.Sleep(2 * time.Second)
	cancel()  // signal goroutine to exit
	close(ch) // close channel for range-based path

	time.Sleep(100 * time.Millisecond)
	fmt.Println("clean shutdown")
}
```

Detecting leaks:
```bash
# Count goroutines — watch for growth over time.
curl http://localhost:6060/debug/pprof/goroutine?debug=1

# Full stack traces — look for "chan receive" blocks.
curl http://localhost:6060/debug/pprof/goroutine?debug=2

# Diff before/after exercising suspect code.
curl -s http://localhost:6060/debug/pprof/goroutine > before.txt
# trigger suspected leak ...
curl -s http://localhost:6060/debug/pprof/goroutine > after.txt
diff before.txt after.txt
```

- Goroutine leaks always involve blocking on: channel receive, channel send, mutex, or `select`.
- The pprof goroutine dump shows each goroutine's stack — `chan receive` is the telltale sign.
- Every goroutine must have a clear exit: a closed channel, cancelled context, or explicit done signal.
- In tests, use `defer goleak.VerifyNone(t)` — fails the test if any goroutines leak.

```go
package store

import (
	"errors"
	"fmt"
)

// Sentinel errors — fixed identity, comparable via errors.Is.
var (
	ErrNotFound     = errors.New("not found")
	ErrUnauthorized = errors.New("unauthorized")
	ErrConflict     = errors.New("conflict")
)

// fetchUser wraps sentinels with context using %w.
// errors.Is still works because %w preserves the chain.
func fetchUser(id int) error {
	if id <= 0 {
		return fmt.Errorf("fetchUser(id=%d): %w", id, ErrNotFound)
	}
	if id > 1000 {
		return fmt.Errorf("fetchUser(id=%d): requires admin: %w", id, ErrUnauthorized)
	}
	return nil
}

func Handler(id int) string {
	err := fetchUser(id)
	if err == nil {
		return "ok"
	}
	switch {
	case errors.Is(err, ErrNotFound):
		return "404: user not found"
	case errors.Is(err, ErrUnauthorized):
		return "403: forbidden"
	default:
		return fmt.Sprintf("500: %v", err)
	}
}

// WRONG: string comparison — fragile, breaks on message changes.
func badHandler(err error) bool {
	return err.Error() == "not found" // never do this
}

// WRONG: direct == after wrapping — errors.Is handles chain unwrapping.
func alsoWrong(err error) bool {
	return err == ErrNotFound // fails after fmt.Errorf("%w", ...)
}
```

- Sentinel errors are package-level `var` — their identity is the pointer to the `errorString`. `errors.Is` compares by identity, not message.
- `fmt.Errorf("...: %w", sentinel)` wraps the sentinel — `errors.Is` unwraps the chain automatically.
- `err == ErrNotFound` fails after wrapping — always use `errors.Is`.
- Never compare `err.Error()` strings — message text is for humans. Sentinel vars are for code branching.

```go
package main

import (
	"context"
	"database/sql"
	"fmt"
	"log"
	"net/http"
	"time"

	_ "github.com/lib/pq"
)

var db *sql.DB

func slowQueryHandler(w http.ResponseWriter, r *http.Request) {
	// r.Context() is cancelled when the client disconnects.
	ctx := r.Context()

	// Add server-side timeout on top of client cancellation.
	ctx, cancel := context.WithTimeout(ctx, 10*time.Second)
	defer cancel()

	rows, err := db.QueryContext(ctx,
		`SELECT id, data FROM heavy_table WHERE expensive_condition($1) LIMIT 100`,
		r.URL.Query().Get("filter"))

	if err != nil {
		if ctx.Err() != nil {
			log.Printf("query cancelled: %v", ctx.Err())
			return // client gone — no point writing response
		}
		http.Error(w, "database error", http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	w.Header().Set("Content-Type", "application/json")
	fmt.Fprint(w, "[")
	first := true
	for rows.Next() {
		if ctx.Err() != nil {
			return // client disconnected mid-stream
		}
		var id int
		var data string
		rows.Scan(&id, &data)
		if !first {
			fmt.Fprint(w, ",")
		}
		fmt.Fprintf(w, `{"id":%d,"data":%q}`, id, data)
		first = false
	}
	fmt.Fprint(w, "]")

	if err := rows.Err(); err != nil && ctx.Err() == nil {
		log.Printf("rows error: %v", err)
	}
}

func main() {
	var err error
	db, err = sql.Open("postgres", "postgres://localhost/mydb?sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}
	db.SetMaxOpenConns(25)

	http.HandleFunc("/query", slowQueryHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

- `r.Context()` is cancelled by `net/http` when the client closes the connection — no polling needed.
- `db.QueryContext(ctx, ...)` propagates cancellation to the DB driver — PostgreSQL cancels via `pg_cancel_backend`.
- Check `ctx.Err()` before writing to `w` after long operations — writing to a disconnected client wastes work.
- `context.WithTimeout` wrapping adds a server-side deadline even if the client stays connected indefinitely.

