package store_test

import (
	"context"
	"database/sql"
	"testing"
	"time"
)

type User struct {
	ID    int
	Name  string
	Email string
}

// setupDB opens a test DB and registers cleanup automatically.
// t.Helper() makes failure lines point to the caller, not this function.
func setupDB(t *testing.T) *sql.DB {
	t.Helper()
	db, err := sql.Open("postgres", "postgres://localhost/testdb?sslmode=disable")
	if err != nil {
		t.Fatalf("open db: %v", err)
	}
	t.Cleanup(func() {
		db.Exec("TRUNCATE users")
		db.Close()
	})
	return db
}

func TestGetUser(t *testing.T) {
	db := setupDB(t)
	ctx := context.Background()

	// Seed test data.
	db.ExecContext(ctx, `INSERT INTO users (id, name, email) VALUES (1, 'Alice', 'alice@example.com')`)

	tests := []struct {
		name     string
		id       int
		wantName string
		wantNil  bool
	}{
		{"existing user", 1, "Alice", false},
		{"missing user", 9999, "", true},
	}

	for _, tc := range tests {
		tc := tc // capture for parallel subtests
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()

			ctx, cancel := context.WithTimeout(ctx, 2*time.Second)
			defer cancel()

			var name string
			err := db.QueryRowContext(ctx, `SELECT name FROM users WHERE id = $1`, tc.id).Scan(&name)

			if tc.wantNil {
				if err != sql.ErrNoRows {
					t.Errorf("expected ErrNoRows, got %v", err)
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			if name != tc.wantName {
				t.Errorf("got name=%q, want %q", name, tc.wantName)
			}
		})
	}
}
```

- `t.Helper()` in helper functions makes failure output point to the test line, not the helper — essential for readable test failures.
- `t.Cleanup(f)` runs `f` when the test and all its subtests finish — preferred over `defer` for setup functions.
- `tc := tc` captures the loop variable before `t.Parallel()` — without it, all subtests share the last value.
- Table-driven subtests give individual pass/fail per case, parallel execution, and clear names in output.

```go
package main

import (
	"context"
	"fmt"
	"sync"
)

// fanOut distributes items from in to n workers, each applying process.
func fanOut[T, R any](ctx context.Context, in <-chan T, n int, process func(T) R) []<-chan R {
	outs := make([]<-chan R, n)
	for i := 0; i < n; i++ {
		ch := make(chan R)
		outs[i] = ch
		go func(out chan<- R) {
			defer close(out)
			for {
				select {
				case item, ok := <-in:
					if !ok {
						return
					}
					select {
					case out <- process(item):
					case <-ctx.Done():
						return
					}
				case <-ctx.Done():
					return
				}
			}
		}(ch)
	}
	return outs
}

// fanIn merges multiple channels into one output channel.
func fanIn[R any](ctx context.Context, channels ...<-chan R) <-chan R {
	out := make(chan R)
	var wg sync.WaitGroup

	forward := func(ch <-chan R) {
		defer wg.Done()
		for {
			select {
			case v, ok := <-ch:
				if !ok {
					return
				}
				select {
				case out <- v:
				case <-ctx.Done():
					return
				}
			case <-ctx.Done():
				return
			}
		}
	}

	wg.Add(len(channels))
	for _, ch := range channels {
		go forward(ch)
	}
	go func() {
		wg.Wait()
		close(out)
	}()
	return out
}

func main() {
	ctx := context.Background()

	in := make(chan int, 10)
	for i := 0; i < 20; i++ {
		in <- i
	}
	close(in)

	workers := fanOut(ctx, in, 4, func(n int) string {
		return fmt.Sprintf("processed:%d", n*n)
	})

	results := fanIn(ctx, workers...)
	for r := range results {
		fmt.Println(r)
	}
}
```

- Fan-out reads from a single shared input channel — Go's channel receive is safe for concurrent goroutines; each item goes to exactly one worker.
- Fan-in uses one goroutine per input channel, all forwarding to a shared output. A separate goroutine closes `out` after all forwarders finish.
- Both functions check `ctx.Done()` on every select — prevents goroutine leaks on cancellation.
- The consumer ranges over `results` — the closed `out` channel signals completion.

```go
package main

import (
	"fmt"
	"sync"
)

// --- sync.Once: lazy initialization ---

type ExpensiveService struct{ name string }

var (
	service *ExpensiveService
	once    sync.Once
)

// GetService is safe for concurrent calls — initService runs exactly once.
func GetService() *ExpensiveService {
	once.Do(func() {
		service = &ExpensiveService{name: "heavy-service"}
		fmt.Println("service initialized")
	})
	return service
}

// Per-instance Once pattern.
type Config struct {
	once  sync.Once
	value string
}

func (c *Config) Value() string {
	c.once.Do(func() {
		c.value = "loaded-from-disk"
	})
	return c.value
}

// --- sync.Map: concurrent map without external locking ---

func syncMapDemo() {
	var m sync.Map

	m.Store("key1", 42)
	m.Store("key2", "hello")

	// Load — returns (value, ok).
	if v, ok := m.Load("key1"); ok {
		fmt.Println("key1:", v.(int))
	}

	// LoadOrStore — atomic get-or-set.
	actual, loaded := m.LoadOrStore("key3", "default")
	fmt.Println("loaded:", loaded, "value:", actual)

	// Range — unordered iteration.
	m.Range(func(k, v interface{}) bool {
		fmt.Printf("%v -> %v\n", k, v)
		return true // return false to stop early
	})

	m.Delete("key1")
}

func main() {
	var wg sync.WaitGroup
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			GetService() // only one initialization happens
		}()
	}
	wg.Wait()
	syncMapDemo()
}
```

When to use `sync.Map` vs `map` + `sync.RWMutex`:
| Scenario | Use |
|---|---|
| Mostly reads, rare writes | `sync.RWMutex` |
| Many goroutines, disjoint keys | `sync.Map` |
| Need range + delete atomically | `sync.Map` |
| Known key set at startup | `sync.RWMutex` |

- `sync.Once` guarantees the function runs exactly once — even under high concurrency.
- After the first successful call, subsequent `Do` calls are no-ops (no locking cost).
- `sync.Map` stores `interface{}` — callers must type-assert on retrieval. Prefer a typed map + mutex when types are known.

```go
package main

import (
	"context"
	"fmt"
	"io"
	"log"
	"net"
	"time"

	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"

	pb "example.com/myservice/gen/proto"
)

type server struct {
	pb.UnimplementedUserServiceServer
}

// Unary RPC — one request, one response.
func (s *server) GetUser(ctx context.Context, req *pb.GetUserRequest) (*pb.User, error) {
	// Read incoming metadata.
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.InvalidArgument, "missing metadata")
	}
	traceID := md.Get("x-trace-id")
	log.Printf("GetUser id=%d trace=%v", req.Id, traceID)

	if req.Id <= 0 {
		// Return a gRPC status error — clients can inspect the code.
		return nil, status.Errorf(codes.InvalidArgument, "id must be positive, got %d", req.Id)
	}
	if req.Id > 1000 {
		return nil, status.Errorf(codes.NotFound, "user %d not found", req.Id)
	}

	// Send response metadata before returning.
	grpc.SetHeader(ctx, metadata.Pairs("x-processed-at", time.Now().Format(time.RFC3339)))

	return &pb.User{Id: req.Id, Name: fmt.Sprintf("user_%d", req.Id)}, nil
}

// Server-streaming RPC — one request, stream of responses.
func (s *server) ListUsers(req *pb.ListUsersRequest, stream pb.UserService_ListUsersServer) error {
	for i := int32(0); i < req.Limit; i++ {
		// Check if client cancelled.
		if err := stream.Context().Err(); err != nil {
			return status.FromContextError(err).Err()
		}
		if err := stream.Send(&pb.User{Id: i, Name: fmt.Sprintf("user_%d", i)}); err != nil {
			return err // client disconnected
		}
		time.Sleep(10 * time.Millisecond)
	}
	return nil
}

func main() {
	lis, err := net.Listen("tcp", ":50051")
	if err != nil {
		log.Fatal(err)
	}

	srv := grpc.NewServer(
		grpc.ChainUnaryInterceptor(loggingInterceptor),
	)
	pb.RegisterUserServiceServer(srv, &server{})

	log.Println("gRPC server listening on :50051")
	log.Fatal(srv.Serve(lis))
}

func loggingInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler) (interface{}, error) {
	start := time.Now()
	resp, err := handler(ctx, req)
	code := codes.OK
	if s, ok := status.FromError(err); ok {
		code = s.Code()
	}
	log.Printf("RPC %s code=%s duration=%s", info.FullMethod, code, time.Since(start))
	return resp, err
}
```

- `status.Errorf(codes.NotFound, ...)` returns a gRPC status error — clients receive a typed error code, not a raw string.
- `status.FromContextError(err)` converts `context.Canceled` and `context.DeadlineExceeded` to gRPC codes.
- `stream.Context().Err()` in streaming RPCs detects client disconnection — always check it before sending.
- `grpc.ChainUnaryInterceptor` composes multiple interceptors; apply in order (first listed = outermost).

