// Unpack peels one layer: Promise → T, () => T → T, T[] → T, else T
type Unpack<T> =
  T extends Promise<infer U>            ? U :
  T extends (...args: any[]) => infer U ? U :
  T extends (infer U)[]                 ? U :
  T;

// --- examples ---
type A = Unpack<Promise<string>>;           // string
type B = Unpack<() => number[]>;            // number[]  (one layer)
type C = Unpack<boolean[]>;                 // boolean
type D = Unpack<Map<string, number>>;       // Map<string, number> (no match)

// Deep variant — keep unpeeling until stable
type DeepUnpack<T> = T extends Unpack<T> ? T : DeepUnpack<Unpack<T>>;

type E = DeepUnpack<Promise<Promise<string>>>;  // string
type F = DeepUnpack<() => () => number>;        // number

// Practical use: infer API response body from an async fetch function
async function fetchUser(): Promise<{ id: number; name: string }> {
  return { id: 1, name: 'Alice' };
}

type UserShape = Unpack<ReturnType<typeof fetchUser>>;
// { id: number; name: string }

function processUser(u: UserShape) {
  console.log(u.id, u.name);
}
