// Transform each property into a zero-arg function returning that type
type Getters<T> = {
  [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K];
};

// Transform each property into a setter function
type Setters<T> = {
  [K in keyof T as `set${Capitalize<string & K>}`]: (value: T[K]) => void;
};

// Full accessor interface
type Accessors<T> = Getters<T> & Setters<T>;

// --- practical example: generate a reactive store ---
interface UserState {
  id: number;
  name: string;
  email: string;
  isAdmin: boolean;
}

function createStore<T extends object>(initial: T): T & Accessors<T> {
  const state = { ...initial } as T;

  const accessors = {} as Accessors<T>;

  for (const key of Object.keys(initial) as (keyof T)[]) {
    const cap = (String(key)[0].toUpperCase() + String(key).slice(1)) as string;
    (accessors as any)[`get${cap}`] = () => state[key];
    (accessors as any)[`set${cap}`] = (v: T[keyof T]) => { state[key] = v; };
  }

  return Object.assign(state, accessors);
}

const store = createStore<UserState>({
  id: 1, name: 'Alice', email: 'a@example.com', isAdmin: false
});

console.log(store.getName());   // 'Alice'
store.setIsAdmin(true);
console.log(store.getIsAdmin()); // true
