import type { Request, Response, NextFunction } from 'express';

// Extract the parameter types of each handler in a variadic middleware tuple
type MiddlewareParams<T> = T extends (req: infer R, res: infer S, next: infer N) => any
  ? [R, S, N]
  : never;

// Infer async handler return
