/**
 * Memoize a function with a GC-aware cache.
 * Cached results are held weakly — if GC reclaims a result,
 * the entry is automatically pruned from the cache.
 *
 * NOTE: Only works for functions returning objects (primitives can't be WeakRef'd).
 */
function weakMemo(fn, keyFn = (...args) => JSON.stringify(args)) {
  const cache    = new Map();   // key → WeakRef<result>
  const registry = new FinalizationRegistry(cacheKey => {
    // Called after GC collects the result object
    const ref = cache.get(cacheKey);
    if (ref && ref.deref() === undefined) {
      cache.delete(cacheKey);
      console.debug(`[weakMemo] evicted key: ${cacheKey}`);
    }
  });

  return function memoized(...args) {
    const key = keyFn(...args);

    const ref = cache.get(key);
    if (ref) {
      const cached = ref.deref();
      if (cached !== undefined) return cached;  // cache hit
      cache.delete(key);                        // GC'd — fall through
    }

    const result = fn.apply(this, args);
    if (result === null || typeof result !== 'object') {
      throw new TypeError('weakMemo only supports object return values');
    }

    const weakRef = new WeakRef(result);
    cache.set(key, weakRef);
    registry.register(result, key, weakRef);  // token = weakRef for unregistration
    return result;
  };
}

// --- usage ---
const expensiveParse = weakMemo((schema) => {
  console.log('Parsing schema…');
  return { parsed: true, fields: Object.keys(schema) };
});

const s1 = expensiveParse({ name: '', age: 0 });  // logs 'Parsing schema…'
const s2 = expensiveParse({ name: '', age: 0 });  // cache hit — no log
console.log(s1 === s2); // true (same object reference)

// When s1/s2 go out of scope and GC runs, the cache entry is pruned automatically
