function createDefensive(target, label = 'object') {
  const accessLog = [];

  const handler = {
    get(target, key, receiver) {
      // Allow standard symbol lookups silently
      if (typeof key === 'symbol') return Reflect.get(target, key, receiver);

      const value = Reflect.get(target, key, receiver);
      accessLog.push({ op: 'get', key, at: new Date().toISOString() });
      console.log(`[${label}] GET ${String(key)} → ${JSON.stringify(value)}`);

      // Return functions bound to target (not proxy) to avoid re-entrancy
      if (typeof value === 'function') return value.bind(target);
      // Recursively wrap nested objects
      if (value !== null && typeof value === 'object') {
        return createDefensive(value, `${label}.${String(key)}`);
      }
      return value;
    },

    set(target, key) {
      throw new TypeError(`[${label}] Cannot assign to property '${String(key)}': object is defensive`);
    },

    deleteProperty(target, key) {
      throw new TypeError(`[${label}] Cannot delete property '${String(key)}': object is defensive`);
    },

    has(target, key) {
      const result = Reflect.has(target, key);
      accessLog.push({ op: 'has', key });
      return result;
    },

    getPrototypeOf(target) {
      return Reflect.getPrototypeOf(target); // preserve prototype chain
    },
  };

  const proxy = new Proxy(target, handler);

  // Attach log inspector without going through proxy
  Object.defineProperty(proxy, '__log', {
    get: () => [...accessLog],
    enumerable: false,
  });

  return proxy;
}

// --- usage ---
const config = createDefensive({ db: { host: 'localhost', port: 5432 }, debug: true });

console.log(config.db.host);  // logs GET, returns 'localhost'
console.log('db' in config);  // has check logged

try {
  config.debug = false;       // throws TypeError
} catch (e) {
  console.error(e.message);
}
