// ring-buffer.js — shared between main and worker
export const RING_SIZE   = 1024;  // must be power of 2
export const HEADER_SIZE = 8;     // 2 x Int32 (head, tail)

// Indices in the Int32 header
export const HEAD = 0;
export const TAIL = 1;

export function encodeMessage(obj) {
  return new TextEncoder().encode(JSON.stringify(obj));
}
export function decodeMessage(bytes) {
  return JSON.parse(new TextDecoder().decode(bytes));
}

// --- main.js ---
const sab = new SharedArrayBuffer(HEADER_SIZE * 4 + RING_SIZE);
const header = new Int32Array(sab, 0, HEADER_SIZE);
const ring   = new Uint8Array(sab, HEADER_SIZE * 4);

const worker = new Worker('./worker.js', { type: 'module' });
worker.postMessage({ sab }); // transfer SAB reference

function push(bytes) {
  const tail = Atomics.load(header, TAIL);
  const head = Atomics.load(header, HEAD);
  const used = (tail - head + RING_SIZE) & (RING_SIZE - 1);
  if (used + bytes.length + 4 >= RING_SIZE) throw new Error('Ring full');

  // Write 4-byte length prefix then payload
  const lenView = new DataView(sab, HEADER_SIZE * 4 + tail, 4);
  lenView.setUint32(0, bytes.length);
  for (let i = 0; i < bytes.length; i++) {
    ring[(tail + 4 + i) & (RING_SIZE - 1)] = bytes[i];
  }
  Atomics.store(header, TAIL, (tail + 4 + bytes.length) & (RING_SIZE - 1));
  Atomics.notify(header, TAIL, 1);
}

push(encodeMessage({ type: 'task', id: 1, payload: 'hello' }));

// --- worker.js ---
self.onmessage = function({ data: { sab } }) {
  const header = new Int32Array(sab, 0, HEADER_SIZE);
  const ring   = new Uint8Array(sab, HEADER_SIZE * 4);

  function pop() {
    let head = Atomics.load(header, HEAD);
    let tail = Atomics.load(header, TAIL);
    while (head === tail) {
      Atomics.wait(header, TAIL, tail); // block until notify
      tail = Atomics.load(header, TAIL);
    }
    const lenView = new DataView(sab, HEADER_SIZE * 4 + head, 4);
    const len = lenView.getUint32(0);
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = ring[(head + 4 + i) & (RING_SIZE - 1)];
    Atomics.store(header, HEAD, (head + 4 + len) & (RING_SIZE - 1));
    return decodeMessage(bytes);
  }

  while (true) {
    const msg = pop();
    console.log('[worker] received:', msg);
  }
};
