import { Transform } from 'stream';

/**
 * A Transform stream that throttles byte throughput.
 * @param {object} opts
 * @param {number} opts.bytesPerSecond  - target throughput limit
 * @param {number} [opts.chunkSize=512] - internal chunk size for smooth throttling
 */
class ThrottleStream extends Transform {
  #bps;
  #chunkSize;
  #sent    = 0;
  #startTs = null;

  constructor({ bytesPerSecond, chunkSize = 512, ...streamOpts } = {}) {
    super(streamOpts);
    this.#bps       = bytesPerSecond;
    this.#chunkSize = chunkSize;
  }

  _transform(chunk, _encoding, callback) {
    if (this.#startTs === null) this.#startTs = Date.now();
    this.#processChunk(Buffer.from(chunk), 0, callback);
  }

  #processChunk(buf, offset, callback) {
    if (offset >= buf.length) return callback();

    const slice = buf.subarray(offset, offset + this.#chunkSize);
    this.#sent += slice.length;

    // How long should have elapsed to send this.#sent bytes at the target rate?
    const expectedMs = (this.#sent / this.#bps) * 1000;
    const actualMs   = Date.now() - this.#startTs;
    const delay      = Math.max(0, expectedMs - actualMs);

    const next = () => {
      this.push(slice);
      this.#processChunk(buf, offset + this.#chunkSize, callback);
    };

    if (delay > 0) {
      setTimeout(next, delay);
    } else {
      // Avoid stack overflow on fast paths
      setImmediate(next);
    }
  }

  _flush(callback) { callback(); }
}

// --- usage ---
import { createReadStream, createWriteStream } from 'fs';
import { pipeline } from 'stream/promises';

await pipeline(
  createReadStream('large-file.bin'),
  new ThrottleStream({ bytesPerSecond: 50 * 1024 }), // 50 KB/s
  createWriteStream('/dev/null')
);
console.log('Done — streamed at 50 KB/s max');
