import { watch, open, rename, mkdir, readdir } from 'fs/promises';
import { join, basename }                       from 'path';
import { existsSync }                           from 'fs';

const LOCK_EXT    = '.processing';
const ARCHIVE_DIR = 'archive';

/**
 * Watch `dir` for new files and process each exactly once.
 * Uses a `.processing` lock file as a distributed-safe mutex.
 */
async function watchAndProcess(dir, processor) {
  await mkdir(join(dir, ARCHIVE_DIR), { recursive: true });

  async function handleFile(filePath) {
    const lockPath = filePath + LOCK_EXT;

    // Atomic "claim" via O_CREAT | O_EXCL — fails if another process got there first
    let lockFd;
    try {
      lockFd = await open(lockPath, 'wx'); // exclusive create
    } catch {
      return; // another process claimed it
    }

    try {
      await processor(filePath);
      const dest = join(dir, ARCHIVE_DIR, basename(filePath));
      await rename(filePath, dest);
      console.log(`Archived ${basename(filePath)} → ${ARCHIVE_DIR}/`);
    } catch (err) {
      console.error(`Failed to process ${filePath}:`, err);
    } finally {
      await lockFd.close();
      try { await rename(lockPath, lockPath + '.done'); } catch { /* best effort */ }
    }
  }

  // Process existing files on startup
  const existing = await readdir(dir);
  for (const f of existing) {
    if (f.endsWith(LOCK_EXT) || f.endsWith(LOCK_EXT + '.done') || f === ARCHIVE_DIR) continue;
    const full = join(dir, f);
    if (!existsSync(full + LOCK_EXT)) await handleFile(full);
  }

  // Watch for new files
  const watcher = watch(dir, { persistent: true });
  console.log(`Watching ${dir} for new files…`);

  for await (const event of watcher) {
    if (event.eventType !== 'rename') continue;
    const filePath = join(dir, event.filename ?? '');
    if (
      !existsSync(filePath) ||
      event.filename?.endsWith(LOCK_EXT) ||
      event.filename?.endsWith('.done')
    ) continue;

    // Small debounce to wait for file to be fully written
    setTimeout(() => handleFile(filePath), 200);
  }
}

// --- usage ---
await watchAndProcess('./incoming', async (filePath) => {
  console.log(`Processing ${filePath}…`);
  // parse, validate, insert to DB, etc.
  await new Promise(r => setTimeout(r, 100)); // simulate work
});
