class MessageBus {
  #subscriptions = new Map(); // pattern → Set<WeakRef<handler>>
  #history       = [];        // { topic, payload, ts }[]
  #maxHistory;

  constructor({ maxHistory = 100 } = {}) {
    this.#maxHistory = maxHistory;
  }

  // Convert glob pattern to RegExp
  #patternToRegex(pattern) {
    const escaped = pattern.replace(/[.+^${}()|[\]\\]/g, '\\$&').replace(/\*/g, '[^.]+');
    return new RegExp(`^${escaped}$`);
  }

  subscribe(pattern, handler, { replay = false } = {}) {
    if (!this.#subscriptions.has(pattern)) {
      this.#subscriptions.set(pattern, new Set());
    }
    const ref = new WeakRef(handler);
    this.#subscriptions.get(pattern).add(ref);

    if (replay) {
      const regex = this.#patternToRegex(pattern);
      for (const { topic, payload } of this.#history) {
        if (regex.test(topic)) {
          try { handler(payload, topic); } catch { /* swallow replay errors */ }
        }
      }
    }

    // Return unsubscribe function
    return () => this.#subscriptions.get(pattern)?.delete(ref);
  }

  publish(topic, payload) {
    const event = { topic, payload, ts: Date.now() };
    this.#history.push(event);
    if (this.#history.length > this.#maxHistory) this.#history.shift();

    for (const [pattern, refs] of this.#subscriptions) {
      const regex = this.#patternToRegex(pattern);
      if (!regex.test(topic)) continue;

      for (const ref of refs) {
        const handler = ref.deref();
        if (!handler) {
          refs.delete(ref); // GC'd — prune
          continue;
        }
        try { handler(payload, topic); } catch (e) { console.error(e); }
      }
    }
  }
}

// --- usage ---
const bus = new MessageBus({ maxHistory: 50 });

const unsubAll = bus.subscribe('user.*', (payload, topic) => {
  console.log(`[user.*] ${topic}:`, payload);
});

bus.subscribe('*.created', (payload) => {
  console.log('Something was created:', payload.id);
});

bus.publish('user.created',  { id: 'u1', name: 'Alice' });
// logs: [user.*] user.created: {...}  AND  Something was created: u1

bus.publish('user.deleted',  { id: 'u1' });
// logs: [user.*] user.deleted: {...}

bus.publish('order.created', { id: 'o1' });
// logs: Something was created: o1

// Late subscriber gets history replay
bus.subscribe('user.*', (p) => console.log('Late:', p), { replay: true });
// Immediately fires for both historical user.* events

unsubAll(); // clean up
