const CLONE_SYMBOL = Symbol('clone');

/**
 * Deep clone with support for:
 * - Circular references (WeakMap tracking)
 * - Map, Set, Date, RegExp, ArrayBuffer, TypedArrays
 * - Custom [Symbol.clone]() hook on class instances
 * - Preserves prototype chain for plain objects
 */
function deepClone(value, seen = new WeakMap()) {
  // Primitives pass through
  if (value === null || typeof value !== 'object' && typeof value !== 'function') {
    return value;
  }

  // Circular reference guard
  if (seen.has(value)) return seen.get(value);

  // Custom clone hook
  if (typeof value[CLONE_SYMBOL] === 'function') {
    const cloned = value[CLONE_SYMBOL]();
    seen.set(value, cloned);
    return cloned;
  }

  // Special built-ins
  if (value instanceof Date)        return new Date(value.getTime());
  if (value instanceof RegExp)      return new RegExp(value.source, value.flags);
  if (value instanceof ArrayBuffer) return value.slice(0);
  if (ArrayBuffer.isView(value)) {
    const buf = deepClone(value.buffer, seen);
    return new (value.constructor)(buf, value.byteOffset, value.length ?? undefined);
  }

  if (value instanceof Map) {
    const m = new Map();
    seen.set(value, m);
    value.forEach((v, k) => m.set(deepClone(k, seen), deepClone(v, seen)));
    return m;
  }

  if (value instanceof Set) {
    const s = new Set();
    seen.set(value, s);
    value.forEach(v => s.add(deepClone(v, seen)));
    return s;
  }

  if (Array.isArray(value)) {
    const arr = [];
    seen.set(value, arr);
    value.forEach((v, i) => { arr[i] = deepClone(v, seen); });
    return arr;
  }

  // Plain objects and class instances — preserve prototype
  const clone = Object.create(Object.getPrototypeOf(value));
  seen.set(value, clone);
  for (const key of Reflect.ownKeys(value)) {
    const desc = Object.getOwnPropertyDescriptor(value, key);
    if (desc.get || desc.set) {
      Object.defineProperty(clone, key, desc); // preserve accessors
    } else {
      clone[key] = deepClone(desc.value, seen);
    }
  }
  return clone;
}

// --- usage ---
const a = { x: 1 };
a.self = a; // circular

const b = deepClone(a);
console.log(b.x);      // 1
console.log(b.self === b); // true (circular preserved)

// Custom clone
class Vector {
  constructor(x, y) { this.x = x; this.y = y; }
  [CLONE_SYMBOL]() { return new Vector(this.x, this.y); }
}

const v = new Vector(3, 4);
const vc = deepClone(v);
console.log(vc instanceof Vector, vc.x, vc.y); // true 3 4

// Map and Set
const m = new Map([['a', new Set([1, 2, 3])]]);
const mc = deepClone(m);
console.log(mc.get('a') instanceof Set); // true
console.log(mc.get('a') !== m.get('a')); // true (deep copy)
