// ─── Domain ───────────────────────────────────────────────────────────────────
interface DomainEvent {
  readonly type:        string;
  readonly aggregateId: string;
  readonly version:     number;
  readonly timestamp:   number;
  readonly payload:     unknown;
}

type EventHandler<S, E extends DomainEvent> = (state: S, event: E) => S;

// ─── Store ────────────────────────────────────────────────────────────────────
class ConcurrencyError extends Error {
  constructor(aggregateId: string, expected: number, actual: number) {
    super(`Concurrency conflict on ${aggregateId}: expected v${expected}, found v${actual}`);
    this.name = 'ConcurrencyError';
  }
}

class EventStore {
  private streams = new Map<string, DomainEvent[]>(); // aggregateId → events[]

  append(
    aggregateId:     string,
    events:          Omit<DomainEvent, 'version' | 'timestamp'>[],
    expectedVersion: number  // -1 = new stream, n = current version
  ): DomainEvent[] {
    const stream       = this.streams.get(aggregateId) ?? [];
    const currentVer   = stream.length === 0 ? -1 : stream[stream.length - 1].version;

    if (currentVer !== expectedVersion) {
      throw new ConcurrencyError(aggregateId, expectedVersion, currentVer);
    }

    const stored = events.map((e, i) => ({
      ...e,
      aggregateId,
      version:   currentVer + 1 + i,
      timestamp: Date.now(),
    } satisfies DomainEvent));

    this.streams.set(aggregateId, [...stream, ...stored]);
    return stored;
  }

  load(aggregateId: string, fromVersion = 0): DomainEvent[] {
    return (this.streams.get(aggregateId) ?? [])
      .filter(e => e.version >= fromVersion);
  }

  replay<S>(
    aggregateId: string,
    initialState: S,
    reducer:     (state: S, event: DomainEvent) => S
  ): { state: S; version: number } {
    const events  = this.load(aggregateId);
    const state   = events.reduce(reducer, initialState);
    const version = events.length === 0 ? -1 : events[events.length - 1].version;
    return { state, version };
  }
}

// ─── Example aggregate ────────────────────────────────────────────────────────
type BankAccountEvent =
  | { type: 'AccountOpened'; aggregateId: string; version: number; timestamp: number; payload: { owner: string; initialBalance: number } }
  | { type: 'MoneyDeposited'; aggregateId: string; version: number; timestamp: number; payload: { amount: number } }
  | { type: 'MoneyWithdrawn'; aggregateId: string; version: number; timestamp: number; payload: { amount: number } };

interface AccountState { owner: string; balance: number; }

const accountReducer = (state: AccountState, event: DomainEvent): AccountState => {
  switch (event.type) {
    case 'AccountOpened':  return { owner: (event.payload as any).owner, balance: (event.payload as any).initialBalance };
    case 'MoneyDeposited': return { ...state, balance: state.balance + (event.payload as any).amount };
    case 'MoneyWithdrawn': return { ...state, balance: state.balance - (event.payload as any).amount };
    default: return state;
  }
};

const store  = new EventStore();
const id     = 'account-001';

store.append(id, [{ type: 'AccountOpened', aggregateId: id, payload: { owner: 'Alice', initialBalance: 1000 } }], -1);
store.append(id, [{ type: 'MoneyDeposited', aggregateId: id, payload: { amount: 500 } }], 0);
store.append(id, [{ type: 'MoneyWithdrawn', aggregateId: id, payload: { amount: 200 } }], 1);

const { state, version } = store.replay(id, { owner: '', balance: 0 }, accountReducer);
console.log(state);   // { owner: 'Alice', balance: 1300 }
console.log(version); // 2

// Optimistic concurrency — this should fail
try {
  store.append(id, [{ type: 'MoneyDeposited', aggregateId: id, payload: { amount: 100 } }], 0);
} catch (e) {
  console.error(e.message); // ConcurrencyError
}
