type DeepMerge<T, U> = {
  [K in keyof T | keyof U]:
    K extends keyof U
      ? K extends keyof T
        ? T[K] extends object
          ? U[K] extends object
            ? DeepMerge<T[K], U[K]>  // both are objects — recurse
            : U[K]                   // U wins (override)
          : U[K]                     // T is primitive — U wins
        : U[K]                       // only in U
      : K extends keyof T
        ? T[K]                       // only in T
        : never;
};

type MergeStrategy = 'override' | 'keep' | 'concat';

function deepMerge<T extends object, U extends object>(
  target: T,
  source: U,
  strategy: MergeStrategy = 'override'
): DeepMerge<T, U> {
  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source) as (keyof U)[]) {
    const tVal = (target as any)[key];
    const sVal = (source as any)[key];

    if (Array.isArray(tVal) && Array.isArray(sVal)) {
      result[key as string] =
        strategy === 'concat' ? [...tVal, ...sVal] :
        strategy === 'keep'   ? tVal :
        sVal; // override
    } else if (
      sVal !== null && typeof sVal === 'object' &&
      tVal !== null && typeof tVal === 'object' &&
      !Array.isArray(sVal)
    ) {
      result[key as string] = deepMerge(tVal, sVal, strategy);
    } else {
      result[key as string] = strategy === 'keep' && key in target ? tVal : sVal;
    }
  }

  return result as DeepMerge<T, U>;
}

// Variadic merge of many objects
function mergeAll<T extends object[]>(
  ...objects: T
): T extends [infer A extends object, ...infer Rest extends object[]]
  ? Rest extends []
    ? A
    : DeepMerge<A, ReturnType<typeof mergeAll<Rest>>>
  : object {
  return objects.reduce((acc, obj) => deepMerge(acc, obj)) as any;
}

