```typescript
/**
 * Bounded async queue. Producers await `push()` when full.
 * Consumers await `pop()` when empty. Supports closing.
 */
class AsyncQueue<T> {
  private buffer:   T[]               = [];
  private waiters:  Array<() => void> = [];  // consumers waiting for items
  private pushers:  Array<() => void> = [];  // producers waiting for space
  private _closed = false;
  private readonly capacity: number;

  constructor(capacity = Infinity) {
    this.capacity = capacity;
  }

  async push(item: T): Promise<void> {
    if (this._closed) throw new Error('Queue is closed');

    // Block if full
    while (this.buffer.length >= this.capacity) {
      await new Promise<void>(resolve => this.pushers.push(resolve));
      if (this._closed) throw new Error('Queue closed while waiting to push');
    }

    this.buffer.push(item);

    // Wake up a waiting consumer
    this.waiters.shift()?.();
  }

  async pop(): Promise<T> {
    // Block if empty
    while (this.buffer.length === 0) {
      if (this._closed) throw new Error('Queue is closed and empty');
      await new Promise<void>(resolve => this.waiters.push(resolve));
    }

    const item = this.buffer.shift()!;

    // Wake up a waiting producer
    this.pushers.shift()?.();

    return item;
  }

  // Try to pop without blocking — returns undefined if empty
  tryPop(): T | undefined {
    if (this.buffer.length === 0) return undefined;
    const item = this.buffer.shift()!;
    this.pushers.shift()?.();
    return item;
  }

  close(): void {
    this._closed = true;
    // Wake all blocked consumers/producers so they can throw
    this.waiters.forEach(r => r());
    this.pushers.forEach(r => r());
    this.waiters = [];
    this.pushers = [];
  }

  async *[Symbol.asyncIterator](): AsyncIterator<T> {
    while (true) {
      try { yield await this.pop(); }
      catch { break; } // closed
    }
  }

  get size()   { return this.buffer.length; }
  get closed() { return this._closed; }
  get full()   { return this.buffer.length >= this.capacity; }
  get empty()  { return this.buffer.length === 0; }
}

// --- usage: producer-consumer pipeline ---
const queue = new AsyncQueue<number>(5); // bounded to 5

// Producer
async function produce() {
  for (let i = 0; i < 20; i++) {
    await queue.push(i);
    console.log(`Pushed ${i} (size=${queue.size})`);
  }
  queue.close();
}

// Consumer
async function consume() {
  for await (const value of queue) {
    await new Promise(r => setTimeout(r, 50)); // simulate slow processing
    console.log(`Consumed ${value}`);
  }
  console.log('Queue exhausted');
}

await Promise.all([produce(), consume()]);
