const State = Object.freeze({ CLOSED: 'CLOSED', OPEN: 'OPEN', HALF_OPEN: 'HALF_OPEN' });

class CircuitBreaker {
  #state          = State.CLOSED;
  #failureCount   = 0;
  #successCount   = 0;
  #lastFailureAt  = null;

  #threshold;       // failures before opening
  #recoveryMs;      // ms before attempting half-open
  #halfOpenMaxTry;  // attempts allowed in half-open before closing

  constructor({ threshold = 5, recoveryMs = 30_000, halfOpenMaxTry = 1 } = {}) {
    this.#threshold      = threshold;
    this.#recoveryMs     = recoveryMs;
    this.#halfOpenMaxTry = halfOpenMaxTry;
  }

  get state() { return this.#state; }

  #transition(next, reason) {
    const prev   = this.#state;
    this.#state  = next;
    console.log(`[CircuitBreaker] ${prev} → ${next} (${reason})`);
  }

  #shouldAttempt() {
    if (this.#state === State.CLOSED)    return true;
    if (this.#state === State.OPEN) {
      const elapsed = Date.now() - (this.#lastFailureAt ?? 0);
      if (elapsed >= this.#recoveryMs) {
        this.#transition(State.HALF_OPEN, `recovery window elapsed (${elapsed}ms)`);
        this.#successCount = 0;
        return true;
      }
      return false;
    }
    // HALF_OPEN — allow limited probes
    return this.#successCount < this.#halfOpenMaxTry;
  }

  async call(fn) {
    if (!this.#shouldAttempt()) {
      throw new Error(`Circuit is OPEN — fast-fail (will retry in ${Math.round(
        (this.#recoveryMs - (Date.now() - this.#lastFailureAt)) / 1000
      )}s)`);
    }

    try {
      const result = await fn();
      this.#onSuccess();
      return result;
    } catch (err) {
      this.#onFailure(err);
      throw err;
    }
  }

  #onSuccess() {
    this.#failureCount = 0;
    if (this.#state === State.HALF_OPEN) {
      this.#successCount++;
      if (this.#successCount >= this.#halfOpenMaxTry) {
        this.#transition(State.CLOSED, 'probe succeeded');
      }
    }
  }

  #onFailure(err) {
    this.#lastFailureAt = Date.now();
    this.#failureCount++;
    if (this.#state === State.HALF_OPEN) {
      this.#transition(State.OPEN, `probe failed: ${err.message}`);
    } else if (this.#failureCount >= this.#threshold) {
      this.#transition(State.OPEN, `${this.#failureCount} failures reached threshold`);
    }
  }

  stats() {
    return { state: this.#state, failures: this.#failureCount, lastFailure: this.#lastFailureAt };
  }
}

// --- usage ---
const breaker = new CircuitBreaker({ threshold: 3, recoveryMs: 5_000 });

async function callApi() {
  return breaker.call(() => fetch('/api/unstable').then(r => {
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    return r.json();
  }));
}

for (let i = 0; i < 5; i++) {
  try { await callApi(); }
  catch (e) { console.warn(e.message); }
}
// After 3 failures: CLOSED → OPEN
// Attempts 4 & 5: fast-fail immediately
