// Overloads for up to 9 stages — common pattern in fp-ts, remeda, etc.
function pipe<A>(a: A): A;
function pipe<A, B>(a: A, f1: (a: A) => B): B;
function pipe<A, B, C>(a: A, f1: (a: A) => B, f2: (b: B) => C): C;
function pipe<A, B, C, D>(a: A, f1: (a: A) => B, f2: (b: B) => C, f3: (c: C) => D): D;
function pipe<A, B, C, D, E>(
  a: A,
  f1: (a: A) => B, f2: (b: B) => C, f3: (c: C) => D, f4: (d: D) => E
): E;
function pipe<A, B, C, D, E, F>(
  a: A,
  f1: (a: A) => B, f2: (b: B) => C, f3: (c: C) => D,
  f4: (d: D) => E, f5: (e: E) => F
): F;
function pipe(a: unknown, ...fns: Array<(x: unknown) => unknown>): unknown {
  return fns.reduce((acc, fn) => fn(acc), a);
}

// compose: right-to-left variant
function compose<A>(): (a: A) => A;
function compose<A, B>(f1: (a: A) => B): (a: A) => B;
function compose<A, B, C>(f2: (b: B) => C, f1: (a: A) => B): (a: A) => C;
function compose<A, B, C, D>(
  f3: (c: C) => D, f2: (b: B) => C, f1: (a: A) => B
): (a: A) => D;
function compose(...fns: Array<(x: any) => any>) {
  return (x: unknown) => [...fns].reverse().reduce((acc, fn) => fn(acc), x);
}

