```typescript
type Option<T> = Some<T> | None;

class Some<T> {
  readonly _tag = 'Some' as const;
  constructor(readonly value: T) {}

  isSome(): this is Some<T> { return true; }
  isNone(): this is None    { return false; }

  map<U>(fn: (value: T) => U): Option<U> {
    return new Some(fn(this.value));
  }

  flatMap<U>(fn: (value: T) => Option<U>): Option<U> {
    return fn(this.value);
  }

  filter(pred: (value: T) => boolean): Option<T> {
    return pred(this.value) ? this : none;
  }

  getOrElse(_default: T): T       { return this.value; }
  getOrNull(): T | null            { return this.value; }
  getOrUndefined(): T | undefined  { return this.value; }

  orElse(_alt: () => Option<T>): Option<T> { return this; }

  zip<U>(other: Option<U>): Option<[T, U]> {
    return other.isSome() ? new Some([this.value, other.value]) : none;
  }

  match<R>(cases: { some: (v: T) => R; none: () => R }): R {
    return cases.some(this.value);
  }

  toString() { return `Some(${JSON.stringify(this.value)})`; }
}

class None {
  readonly _tag = 'None' as const;

  isSome(): this is Some<never> { return false; }
  isNone(): this is None        { return true; }

  map<U>(_fn: (value: never) => U): Option<U>               { return none; }
  flatMap<U>(_fn: (value: never) => Option<U>): Option<U>   { return none; }
  filter(_pred: (value: never) => boolean): Option<never>   { return none; }

  getOrElse<T>(default_: T): T            { return default_; }
  getOrNull(): null                        { return null; }
  getOrUndefined(): undefined              { return undefined; }

  orElse<T>(alt: () => Option<T>): Option<T> { return alt(); }
  zip<U>(_other: Option<U>): Option<never>   { return none; }

  match<R>(cases: { some: (v: never) => R; none: () => R }): R {
    return cases.none();
  }

  toString() { return 'None'; }
}

const none = new None();
const some = <T>(value: T): Some<T> => new Some(value);

// Helpers
const optionOf = <T>(v: T | null | undefined): Option<T> =>
  v === null || v === undefined ? none : some(v);

const optionFromPredicate =
  <T>(pred: (v: T) => boolean) =>
  (v: T): Option<T> =>
    pred(v) ? some(v) : none;

// --- usage ---
const parsed = optionOf('42')
  .map(Number)
  .filter(n => !isNaN(n) && n > 0)
  .map(n => n * 2);

console.log(parsed.getOrElse(0)); // 84
console.log(parsed.toString());   // 'Some(84)'

const missing = optionOf<string>(null)
  .map(s => s.toUpperCase())
  .getOrElse('default');
console.log(missing); // 'default'

// Zip
const pos = some(3).zip(some(4));
console.log(pos.map(([x, y]) => Math.hypot(x, y)).getOrElse(0)); // 5

// Pattern match
const msg = optionOf(process.env['HOME']).match({
  some: path => `Home is ${path}`,
  none: ()   => 'No HOME set',
});
console.log(msg);
```

