```typescript
// Event map: namespaced keys → payload types
interface AppEventMap {
  'user:login':       { userId: string; ip: string };
  'user:logout':      { userId: string };
  'user:updated':     { userId: string; changes: Partial<{ name: string; email: string }> };
  'order:created':    { orderId: string; total: number };
  'order:fulfilled':  { orderId: string; trackingId: string };
  'system:error':     Error;
  'system:startup':   { version: string };
}

type EventKey = keyof AppEventMap;

// Extract namespace from 'ns:event' → 'ns'
type Namespace<K extends string> = K extends `${infer NS}:${string}` ? NS : never;
type AllNamespaces = Namespace<EventKey>; // 'user' | 'order' | 'system'

// All events in a namespace
type EventsInNS<NS extends string> = {
  [K in EventKey]: K extends `${NS}:${string}` ? K : never;
}[EventKey];

type Handler<K extends EventKey> = (payload: AppEventMap[K], event: K) => void;

class NamespacedEventBus {
  private handlers = new Map<string, Set<{ fn: Handler<any>; once: boolean }>>();

  on<K extends EventKey>(event: K, handler: Handler<K>): () => void {
    return this.#add(event, handler, false);
  }

  once<K extends EventKey>(event: K, handler: Handler<K>): () => void {
    return this.#add(event, handler, true);
  }

  // Subscribe to all events in a namespace
  onNamespace<NS extends AllNamespaces>(
    ns:      NS,
    handler: <K extends EventsInNS<NS>>(payload: AppEventMap[K], event: K) => void
  ): () => void {
    return this.#add(`${ns}:*`, handler as any, false);
  }

  emit<K extends EventKey>(event: K, payload: AppEventMap[K]): void {
    // Exact listeners
    this.#dispatch(event, event, payload);

    // Wildcard listeners for this namespace
    const ns = event.split(':')[0];
    this.#dispatch(`${ns}:*`, event, payload);
  }

  #add(pattern: string, fn: Handler<any>, once: boolean): () => void {
    if (!this.handlers.has(pattern)) this.handlers.set(pattern, new Set());
    const entry = { fn, once };
    this.handlers.get(pattern)!.add(entry);
    return () => this.handlers.get(pattern)?.delete(entry);
  }

  #dispatch(pattern: string, event: EventKey, payload: unknown): void {
    const set = this.handlers.get(pattern);
    if (!set) return;
    for (const entry of set) {
      entry.fn(payload, event);
      if (entry.once) set.delete(entry);
    }
  }
}

// --- usage ---
const bus = new NamespacedEventBus();

// Exact subscription
const off = bus.on('user:login', ({ userId, ip }) => {
  console.log(`User ${userId} logged in from ${ip}`);
});

// Namespace wildcard
bus.onNamespace('order', (payload, event) => {
  console.log(`Order event [${event}]:`, payload);
});

// Once
bus.once('system:startup', ({ version }) => {
  console.log(`System started — v${version}`);
});

bus.emit('user:login',      { userId: 'u1', ip: '127.0.0.1' });
bus.emit('order:created',   { orderId: 'o1', total: 49.99 });
bus.emit('order:fulfilled', { orderId: 'o1', trackingId: 'T-123' });
bus.emit('system:startup',  { version: '2.0.0' });
bus.emit('system:startup',  { version: '2.0.0' }); // once — no output

off(); // unsubscribe user:login
```

```typescript
// Type-level state machine: transitions are checked at compile time
type Transition<State extends string, Event extends string> = {
  [S in State]?: {
    [E in Event]?: State;
  };
};

type MachineConfig<
  State extends string,
  Event extends string,
  Context
> = {
  initial: State;
  context: Context;
  transitions: Transition<State, Event>;
  onTransition?: (from: State, to: State, event: Event, ctx: Context) => Context;
};

function useStateMachine<
  State extends string,
  Event extends string,
  Context
>(config: MachineConfig<State, Event, Context>) {
  const [state, setState] = useState<State>(config.initial);
  const [context, setContext] = useState<Context>(config.context);
  const configRef = useRef(config);
  useEffect(() => { configRef.current = config; });

  const send = useCallback((event: Event) => {
    setState(current => {
      const { transitions, onTransition } = configRef.current;
      const nextState = transitions[current]?.[event];
      if (nextState === undefined) {
        // Invalid transition — stay in current state (or throw in dev)
        if (process.env.NODE_ENV === 'development') {
          console.warn(`No transition from '${current}' on '${event}'`);
        }
        return current;
      }
      if (onTransition) {
        setContext(ctx => onTransition(current, nextState, event, ctx));
      }
      return nextState;
    });
  }, []);

  return { state, context, send };
}

// ---- Fetch lifecycle example ----
type FetchState = 'idle' | 'loading' | 'success' | 'error';
type FetchEvent = 'FETCH' | 'RESOLVE' | 'REJECT' | 'RESET';
type FetchContext = { data: unknown; error: string | null };

const fetchMachine: MachineConfig<FetchState, FetchEvent, FetchContext> = {
  initial: 'idle',
  context: { data: null, error: null },
  transitions: {
    idle:    { FETCH: 'loading' },
    loading: { RESOLVE: 'success', REJECT: 'error' },
    success: { RESET: 'idle', FETCH: 'loading' },
    error:   { RESET: 'idle', FETCH: 'loading' },
  },
  onTransition: (_from, to, _event, ctx) => {
    if (to === 'idle') return { data: null, error: null };
    return ctx; // data/error updated externally via setContext
  },
};

function UserProfile({ id }: { id: string }) {
  const { state, context, send } = useStateMachine(fetchMachine);

  useEffect(() => {
    if (state !== 'loading') return;
    fetch(`/api/users/${id}`)
      .then(r => r.json())
      .then(data => { /* update context then */ send('RESOLVE'); })
      .catch(() => send('REJECT'));
  }, [state, id, send]);

  return (
    <div>
      {state === 'idle'    && <button onClick={() => send('FETCH')}>Load</button>}
      {state === 'loading' && <span>Loading...</span>}
      {state === 'error'   && <button onClick={() => send('RESET')}>Retry</button>}
      {state === 'success' && <pre>{JSON.stringify(context.data)}</pre>}
    </div>
  );
}
```

**Why this pattern matters:** Explicit state machines eliminate impossible UI states (e.g., `loading && error` simultaneously) and make transition rules inspectable. The type-level enforcement means TypeScript will catch calls like `send('RESOLVE')` in 'idle' state at runtime in dev and at design-time with stricter type guards.

```typescript
import { Component, ReactNode, ErrorInfo } from 'react';

// Low-level class — required because getDerivedStateFromError is class-only
interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

interface ErrorBoundaryProps {
  fallback: (error: Error, reset: () => void) => ReactNode;
  onError?: (error: Error, info: ErrorInfo) => void;
  children: ReactNode;
}

class ErrorBoundaryCore extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  state: ErrorBoundaryState = { hasError: false, error: null };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    // Called during render — keep it pure (no side effects)
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    // Side effects go here — logging, analytics
    this.props.onError?.(error, info);
    console.error('[ErrorBoundary]', error, info.componentStack);
  }

  reset = () => this.setState({ hasError: false, error: null });

  render() {
    if (this.state.hasError && this.state.error) {
      return this.props.fallback(this.state.error, this.reset);
    }
    return this.props.children;
  }
}

// Functional wrapper for ergonomic usage
export function ErrorBoundary({
  fallback,
  onError,
  children,
}: ErrorBoundaryProps) {
  return (
    <ErrorBoundaryCore fallback={fallback} onError={onError}>
      {children}
    </ErrorBoundaryCore>
  );
}

// Default fallback component
function DefaultFallback({ error, reset }: { error: Error; reset: () => void }) {
  return (
    <div role="alert" style={{ padding: 16, border: '1px solid red' }}>
      <h2>Something went wrong</h2>
      <pre style={{ fontSize: 12 }}>{error.message}</pre>
      <button onClick={reset}>Try again</button>
    </div>
  );
}

// Usage
function App() {
  return (
    <ErrorBoundary
      fallback={(err, reset) => <DefaultFallback error={err} reset={reset} />}
      onError={(err, info) => {
        // Send to Sentry, Datadog, etc.
        fetch('/api/errors', {
          method: 'POST',
          body: JSON.stringify({ message: err.message, stack: info.componentStack }),
        });
      }}
    >
      <UserDashboard />
    </ErrorBoundary>
  );
}
```

**Gotchas:**
- Error boundaries do NOT catch errors in: event handlers (use try/catch there), async code (useEffect fetch), server-side rendering
- `getDerivedStateFromError` must be pure — side effects in `componentDidCatch`
- The `reset` callback resets boundary state but the child component also needs to reset its own broken state — consider adding a `key` prop that changes on reset to fully remount

```typescript
// ============================================================
// APPROACH 1: React Context with splitting to avoid over-renders
// ============================================================
import { createContext, useContext, useState, useCallback, ReactNode } from 'react';

type User = { id: string; name: string };
type AuthState = { user: User | null; isLoading: boolean };
type AuthActions = { login: (u: User) => void; logout: () => void };

// Split state from actions — action context never changes reference
const AuthStateCtx  = createContext<AuthState | null>(null);
const AuthActionsCtx = createContext<AuthActions | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser]     = useState<User | null>(null);
  const [isLoading, setLoading] = useState(false);

  const login = useCallback((u: User) => {
    setLoading(false);
    setUser(u);
  }, []);

  const logout = useCallback(() => setUser(null), []);

  return (
    <AuthActionsCtx.Provider value={{ login, logout }}>
      {/* State context re-renders when user/isLoading changes */}
      <AuthStateCtx.Provider value={{ user, isLoading }}>
        {children}
      </AuthStateCtx.Provider>
    </AuthActionsCtx.Provider>
  );
}

// Components that only dispatch never re-render on state change
export const useAuthActions = () => useContext(AuthActionsCtx)!;
export const useAuthState   = () => useContext(AuthStateCtx)!;

// ============================================================
// APPROACH 2: Zustand — selector-based subscriptions
// ============================================================
import { create } from 'zustand';
import { immer } from 'zustand/middleware/immer';

interface AuthStore {
  user: User | null;
  isLoading: boolean;
  login: (u: User) => void;
  logout: () => void;
}

const useAuthStore = create<AuthStore>()(immer(set => ({
  user: null,
  isLoading: false,
  login: (u) => set(s => { s.user = u; s.isLoading = false; }),
  logout: () => set(s => { s.user = null; }),
})));

// Fine-grained subscriptions — component only re-renders if selected slice changes
const useUser      = () => useAuthStore(s => s.user);
const useIsLoading = () => useAuthStore(s => s.isLoading);
const useLogin     = () => useAuthStore(s => s.login);  // stable reference
const useLogout    = () => useAuthStore(s => s.logout);

// ============================================================
// When to use each
// ============================================================
/*
Context:
  + Zero extra dependencies
  + Co-located with component tree (great for feature-scoped state)
  + Works naturally with SSR/RSC (no hydration mismatch risk)
  - Re-render control requires manual splitting/memoization
  - No devtools integration
  Best for: auth, theme, locale — slow-changing, tree-scoped state

Zustand:
  + Fine-grained re-renders via selectors (no splitting needed)
  + Redux devtools support out of the box
  + Accessible outside React (in services, websocket handlers)
  + Middleware: immer, persist, subscribeWithSelector
  - Adds a dependency
  - Global stores can become implicit coupling
  Best for: client-side caches, high-frequency updates, cross-tree state

Rule of thumb: <3 consumers and slow-changing → Context. Multiple consumers
with different slices OR high update frequency → Zustand.
*/
```

## Tree-Shaking Gotchas

Tree-shaking (dead code elimination) relies on **static analysis of ES module imports/exports**. It breaks whenever a bundler cannot prove that importing a module has no observable side effects.

---

### 1. Side-effect-ful imports that defeat tree-shaking

```typescript
// BAD: This import has a side effect — it registers a global handler
// The bundler MUST include it even if nothing from it is used
import './polyfills/array-flat'; // modifies Array.prototype
import 'reflect-metadata';       // installs Reflect API globally

// BAD: CJS-style code executed at module level
export const registry = new Map(); // fine
registry.set('default', heavyObject()); // side effect at import time!

// BAD: IIFE that modifies globals
(function patchFetch() {
  const orig = window.fetch;
  window.fetch = (url, opts) => { log(url); return orig(url, opts); };
})();
// ^^^ bundler sees this is a call expression, marks module as side-effectful

// GOOD: Pure factory — no side effects at module scope
export function createRegistry() {
  const registry = new Map();
  registry.set('default', heavyObject());
  return registry;
}
```

### 2. Marking a package as side-effect-free

```json
// package.json — tells bundlers every module in this package is pure
{
  "name": "my-utils",
  "version": "1.0.0",
  "sideEffects": false
}

// Granular — only these files have side effects
{
  "sideEffects": [
    "./src/polyfills.js",
    "./src/global-styles.css",
    "**/*.css"
  ]
}
```

```javascript
// rollup.config.js equivalent — treeshake option
export default {
  input: 'src/index.ts',
  treeshake: {
    moduleSideEffects: false,         // treat all modules as pure
    propertyReadSideEffects: false,   // reading props has no side effects
    unknownGlobalSideEffects: false,  // window.foo access is pure
  },
};
```

### 3. Barrel file anti-pattern

```typescript
// BAD: Barrel file — importing ONE thing forces bundler to evaluate ALL
// src/utils/index.ts
export { formatDate } from './formatDate';
export { parseCSV  } from './parseCSV';   // pulls in papaparse (50KB)
export { renderPDF } from './renderPDF';  // pulls in pdfjs (300KB!)

// Consumer only needs formatDate, but gets everything:
import { formatDate } from '@/utils'; // 350KB bundle impact

// GOOD: Direct imports — bundler only includes what's needed
import { formatDate } from '@/utils/formatDate'; // ~2KB

// ALSO GOOD: Named barrel that works with sideEffects:false + ESM
// The bundler CAN tree-shake barrel files IF:
// 1. Package is marked sideEffects:false
// 2. All re-exports are named (not namespace: export * from)
// 3. Bundler has module graph visibility (Vite/Rollup yes, webpack sometimes)

// Namespace re-export defeats tree-shaking:
export * from './heavyModule'; // BAD — bundler must assume all exports used

// Named re-export allows it:
export { specificThing } from './heavyModule'; // GOOD
```

**Diagnosis tools:**
- `rollup-plugin-visualizer` — bundle size treemap
- `webpack-bundle-analyzer` — equivalent for webpack
- `vite-bundle-visualizer` — for Vite projects
- Look for modules with `(!) X is imported from... but never used` warnings

