**Smells fixed:**
- `string` → `OrderId`, `Email`; `number` → `Money`: domain rules encoded once, validated at construction
- `string` status → `OrderStatus` union: only valid values computable at type level
- `string` address → `ShippingAddress`: individual fields accessible, formatting centralized
- Inappropriate intimacy: `OrderProcessor` no longer directly modifies `customer.wallet.balance` or `customer.wallet.transactions` — `Customer` owns that logic

```typescript
// Semaphore — limits concurrent executions
class Semaphore {
  private queue: (() => void)[] = [];
  private running = 0;

  constructor(private readonly limit: number) {
    if (limit < 1) throw new Error('Semaphore limit must be >= 1');
  }

  async acquire(): Promise<void> {
    if (this.running < this.limit) {
      this.running++;
      return;
    }
    // Queue the waiter
    await new Promise<void>(resolve => this.queue.push(resolve));
  }

  release(): void {
    const next = this.queue.shift();
    if (next) {
      next();  // wake next waiter (running count stays the same)
    } else {
      this.running--;
    }
  }

  async run<T>(fn: () => Promise<T>): Promise<T> {
    await this.acquire();
    try { return await fn(); }
    finally { this.release(); }
  }

  get stats() { return { running: this.running, queued: this.queue.length, limit: this.limit }; }
}

// Bulkhead — wraps a semaphore with queue depth limiting and timeout
interface BulkheadOptions {
  name:            string;
  maxConcurrent:   number;   // thread pool size
  maxQueue:        number;   // max pending requests before rejection
  timeoutMs?:      number;   // max wait time in queue
  onReject?:       (name: string, reason: 'full' | 'timeout') => void;
}

class Bulkhead {
  private semaphore: Semaphore;
  private queueDepth = 0;
  private rejected   = 0;
  private completed  = 0;

  constructor(private opts: BulkheadOptions) {
    this.semaphore = new Semaphore(opts.maxConcurrent);
  }

  async execute<T>(fn: () => Promise<T>): Promise<T> {
    const { maxQueue, timeoutMs, name, onReject } = this.opts;

    // Check queue capacity BEFORE acquiring semaphore
    if (this.queueDepth >= maxQueue) {
      this.rejected++;
      onReject?.(name, 'full');
      throw new BulkheadRejectedError(name, 'Queue full');
    }

    this.queueDepth++;
    try {
      // Optionally time-box the queue wait
      const acquire = this.semaphore.acquire();
      if (timeoutMs) {
        const timeout = new Promise<never>((_, reject) =>
          setTimeout(() => reject(new BulkheadRejectedError(name, 'Queue timeout')), timeoutMs)
        );
        await Promise.race([acquire, timeout]).catch(err => {
          this.rejected++;
          onReject?.(name, 'timeout');
          throw err;
        });
      } else {
        await acquire;
      }
    } finally {
      this.queueDepth--;
    }

    try {
      return await fn();
    } finally {
      this.semaphore.release();
      this.completed++;
    }
  }

  getStats() {
    return {
      name:      this.opts.name,
      ...this.semaphore.stats,
      rejected:  this.rejected,
      completed: this.completed,
    };
  }
}

class BulkheadRejectedError extends Error {
  constructor(bulkhead: string, reason: string) {
    super(`Bulkhead '${bulkhead}' rejected request: ${reason}`);
    this.name = 'BulkheadRejectedError';
  }
}

// ============================================================
// ISOLATION: payment and reporting use separate bulkheads
// ============================================================

// Payment bulkhead: small, strict — never let reporting starve payments
const paymentBulkhead = new Bulkhead({
  name: 'payments',
  maxConcurrent: 10,    // only 10 concurrent payment calls
  maxQueue: 20,         // up to 20 waiting
  timeoutMs: 5_000,     // fail fast if waiting more than 5s
  onReject: (name, reason) => metrics.increment(`bulkhead.${name}.rejected.${reason}`),
});

// Reporting bulkhead: larger pool, longer timeout — slower but isolated
const reportingBulkhead = new Bulkhead({
  name: 'reporting',
  maxConcurrent: 5,     // reports can be slow, fewer concurrent
  maxQueue: 50,         // larger queue — reports can wait
  timeoutMs: 30_000,
  onReject: (name, reason) => metrics.increment(`bulkhead.${name}.rejected.${reason}`),
});

// ---- Services using bulkheads ----
class PaymentService {
  async chargeCard(token: string, amount: number) {
    return paymentBulkhead.execute(() => stripe.charges.create({ amount, source: token }));
  }
}

class ReportingService {
  async generateSalesReport(dateRange: DateRange) {
    return reportingBulkhead.execute(() => db.query(heavyAggregationQuery(dateRange)));
  }
}

// ---- Health endpoint ----
app.get('/health/bulkheads', (_, res) => {
  res.json({
    payments:  paymentBulkhead.getStats(),
    reporting: reportingBulkhead.getStats(),
  });
});

// Example output when reporting is hammered:
// { payments:  { running: 2, queued: 0,  limit: 10, rejected: 0 } }
// { reporting: { running: 5, queued: 50, limit: 5,  rejected: 847 } }
// ↑ Reporting fully saturated but payment bulkhead is unaffected
```

**Why bulkheads matter:** Without isolation, a spike in slow report queries consumes all available async capacity (Node.js event loop isn't blocking but DB connection pools are shared). With bulkheads, the reporting pool saturates and new report requests get rejected with 503, while the payment pool remains at zero queue depth — business-critical operations are unaffected.

## Sidecar Pattern

The sidecar pattern deploys an auxiliary process alongside the main application container in the same pod (Kubernetes) or process group. The sidecar intercepts or augments the main service's traffic and telemetry — the main service stays clean of infrastructure concerns.

```
┌─────────────────────────────────────────────┐
│  Kubernetes Pod                             │
│  ┌─────────────────┐  ┌──────────────────┐  │
│  │  Main Service   │  │  Sidecar         │  │
│  │  (business      │◄─┤  - TLS termination│  │
│  │   logic only)   │  │  - Log enrichment │  │
│  │  :3000 HTTP     │  │  - Metrics        │  │
│  └─────────────────┘  │  :8443 HTTPS     │  │
│                        └──────────────────┘  │
└─────────────────────────────────────────────┘
```

### Main Service — pure business logic, plain HTTP

```typescript
// main-service/src/app.ts — knows NOTHING about TLS, observability, auth
import express from 'express';

const app = express();

app.get('/users/:id', async (req, res) => {
  const user = await db.users.findById(req.params.id);
  if (!user) return res.status(404).json({ error: 'Not found' });
  res.json(user);
});

app.post('/orders', async (req, res) => {
