## Chain of Responsibility: Composable Middleware Pipeline

```typescript
type NextFn = () => Promise<void>;

interface Middleware<TCtx> {
  handle(ctx: TCtx, next: NextFn): Promise<void>;
}

class Pipeline<TCtx> {
  private middlewares: Middleware<TCtx>[] = [];

  use(mw: Middleware<TCtx>): this { this.middlewares.push(mw); return this; }

  useFunction(fn: (ctx: TCtx, next: NextFn) => Promise<void>): this {
    return this.use({ handle: fn });
  }

  async execute(ctx: TCtx): Promise<void> {
    let index = -1;
    const dispatch = async (i: number): Promise<void> => {
      if (i <= index) throw new Error('next() called multiple times');
      index = i;
      const mw = this.middlewares[i];
      if (!mw) return; // end of chain
      await mw.handle(ctx, () => dispatch(i + 1));
    };
    return dispatch(0);
  }
}

interface ReqCtx {
  method: string;
  path: string;
  headers: Record<string, string>;
  userId?: string;
  response: { status: number; body: unknown };
  startTime: number;
}

// Stops chain if no valid auth token
class AuthMiddleware implements Middleware<ReqCtx> {
  async handle(ctx: ReqCtx, next: NextFn): Promise<void> {
    const token = ctx.headers['authorization']?.replace('Bearer ', '');
    if (!token) {
      ctx.response = { status: 401, body: { error: 'Unauthorized' } };
      return; // omit next() — chain stops here
    }
    ctx.userId = await verifyToken(token);
    await next(); // pass to next handler
  }
}

// Stops chain if rate limit exceeded
class RateLimitMiddleware implements Middleware<ReqCtx> {
  private buckets = new Map<string, { count: number; resetAt: number }>();
  async handle(ctx: ReqCtx, next: NextFn): Promise<void> {
    const key = ctx.userId ?? 'anon';
    const now = Date.now();
    const b   = this.buckets.get(key) ?? { count: 0, resetAt: now + 60_000 };
    if (now > b.resetAt) { b.count = 0; b.resetAt = now + 60_000; }
    b.count++;
    this.buckets.set(key, b);
    if (b.count > 100) {
      ctx.response = { status: 429, body: { error: 'Rate limit exceeded' } };
      return;
    }
    await next();
  }
}

// Calls next() first, then logs — wraps entire downstream chain
class LoggingMiddleware implements Middleware<ReqCtx> {
  async handle(ctx: ReqCtx, next: NextFn): Promise<void> {
    await next();
    console.log(`${ctx.method} ${ctx.path} ${ctx.response.status} ${Date.now() - ctx.startTime}ms`);
  }
}

// Fluent pipeline construction
const pipeline = new Pipeline<ReqCtx>()
  .use(new LoggingMiddleware())    // outermost — runs after all others
  .use(new AuthMiddleware())       // short-circuits on missing token
  .use(new RateLimitMiddleware())  // short-circuits on excess requests
  .useFunction(async ctx => {     // leaf handler — business logic
    ctx.response = { status: 200, body: { userId: ctx.userId } };
  });

await pipeline.execute({
  method: 'GET', path: '/api/me',
  headers: { authorization: 'Bearer valid-token' },
  response: { status: 0, body: null },
  startTime: Date.now(),
});
```

**Chain vs if/else:** Each handler is decoupled — `AuthMiddleware` has no knowledge of `RateLimitMiddleware`. Adding `CorsMiddleware` is a single `.use()` call with zero changes to existing handlers. Reordering is a config change, not a code change.

**Execution model (koa-style):** Calling `next()` dives deeper into the chain. Omitting `next()` short-circuits — nothing downstream executes. `LoggingMiddleware` wraps by calling `next()` first then logging, giving it access to the final response status.

## Template Method Pattern: ETL Pipeline

```python
from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Any
import csv, json, time

@dataclass
class Record:
    id: str
    data: dict[str, Any]

class DataPipeline(ABC):
    def run(self, source: str, destination: str) -> int:
        """Template method — defines the fixed algorithm skeleton."""
        start   = time.perf_counter()
        raw     = self.extract(source)           # must override
        records = self.transform(raw)            # must override
        records = self._validate(records)        # final — cannot override
        count   = self.load(records, destination) # must override
        self._on_complete(count, time.perf_counter() - start)  # hook
        return count

    @abstractmethod
    def extract(self, source: str) -> list[dict]: ...

    @abstractmethod
    def transform(self, raw: list[dict]) -> list[Record]: ...

    @abstractmethod
    def load(self, records: list[Record], destination: str) -> int: ...

    # Final step — base class always runs validation, subclasses cannot bypass
    def _validate(self, records: list[Record]) -> list[Record]:
        valid   = [r for r in records if r.id and r.data]
        skipped = len(records) - len(valid)
        if skipped:
            print(f'  Warning: skipped {skipped} invalid records')
        return valid

    # Hook — has a default, subclasses may optionally override
    def _on_complete(self, count: int, elapsed: float) -> None:
        print(f'  Loaded {count} records in {elapsed:.2f}s')

class CsvPipeline(DataPipeline):
    def __init__(self, delimiter: str = ',', encoding: str = 'utf-8'):
        self.delimiter = delimiter
        self.encoding  = encoding

    def extract(self, source: str) -> list[dict]:
        with open(source, encoding=self.encoding) as f:
            return list(csv.DictReader(f, delimiter=self.delimiter))

    def transform(self, raw: list[dict]) -> list[Record]:
        return [
            Record(
                id=row.get('id', ''),
                data={k: v.strip() for k, v in row.items() if k != 'id'}
            )
            for row in raw
        ]

    def load(self, records: list[Record], destination: str) -> int:
        with open(destination, 'w') as f:
            json.dump([{'id': r.id, **r.data} for r in records], f, indent=2)
        return len(records)

class JsonPipeline(DataPipeline):
    def __init__(self, id_field: str = '_id'):
        self.id_field = id_field

    def extract(self, source: str) -> list[dict]:
        with open(source) as f:
            data = json.load(f)
        return data if isinstance(data, list) else data.get('items', [])

    def transform(self, raw: list[dict]) -> list[Record]:
        return [
            Record(id=str(item.pop(self.id_field, item.get('id', ''))), data=item)
            for item in raw
        ]

    def load(self, records: list[Record], destination: str) -> int:
        import sqlite3
        con = sqlite3.connect(destination)
        con.execute('CREATE TABLE IF NOT EXISTS records (id TEXT PRIMARY KEY, data TEXT)')
        con.executemany('INSERT OR REPLACE INTO records VALUES (?, ?)',
                        [(r.id, json.dumps(r.data)) for r in records])
        con.commit()
        con.close()
        return len(records)

    # Override hook: JSON pipeline uses a different log format
    def _on_complete(self, count: int, elapsed: float) -> None:
        print(f'  [JsonPipeline] {count} records -> SQLite in {elapsed*1000:.0f}ms')

# Usage
CsvPipeline(delimiter=';').run('input.csv', 'output.json')
JsonPipeline(id_field='_id').run('data.json', 'records.db')
```

**Three method categories:**
- `extract/transform/load` — abstract, must be overridden (Python raises TypeError if not)
- `_validate` — concrete base implementation, intentionally not overridable by convention (prefix `_`)
- `_on_complete` — hook: has a working default but subclasses may specialize it

**Template Method vs Strategy:** Template Method uses class inheritance — subclasses fill in variable steps within a fixed skeleton. Strategy uses composition — the algorithm object is injected and can be swapped at runtime. Choose Template Method when the skeleton is stable and extension happens through subclassing; choose Strategy when you need runtime algorithm swapping.

## Data Clumps: From Raw Primitives to Value Objects

Data clumps are groups of fields/parameters that always appear together but have no enclosing type. Test: remove one field — if the rest lose meaning, it is a clump.

### Before: Primitives scattered across the codebase

```typescript
// BAD: lat/lng always appear together — 2-field clump
function findNearby(userLat: number, userLng: number, radiusKm: number): Place[] { return []; }

function calculateDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
  return 0; // haversine formula scattered here
}

function isInBounds(
  lat: number, lng: number,           // point
  minLat: number, maxLat: number,     // bounds — 6-field clump
  minLng: number, maxLng: number
): boolean { return true; }

// BAD: startDate/endDate always together — date range clump
function getReservations(userId: string, startDate: Date, endDate: Date): Reservation[] { return []; }
function countWorkdays(startDate: Date, endDate: Date): number { return 0; }
function datesOverlap(aStart: Date, aEnd: Date, bStart: Date, bEnd: Date): boolean { return false; }

// Caller: easy to swap lat/lng or start/end
const d = calculateDistance(user.lat, user.lng, venue.lat, venue.lng);
```

### After: Value objects

```typescript
class Coordinates {
  constructor(
    public readonly lat: number,
    public readonly lng: number,
  ) {
    if (lat < -90  || lat > 90)  throw new RangeError(`Invalid latitude: ${lat}`);
    if (lng < -180 || lng > 180) throw new RangeError(`Invalid longitude: ${lng}`);
  }

  // Domain logic lives HERE, not scattered across callers
  distanceTo(other: Coordinates): number {
    const R    = 6371;
    const dLat = toRad(other.lat - this.lat);
    const dLng = toRad(other.lng - this.lng);
    const a    = Math.sin(dLat/2)**2 +
                 Math.cos(toRad(this.lat)) * Math.cos(toRad(other.lat)) * Math.sin(dLng/2)**2;
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  }

  isWithinRadius(center: Coordinates, radiusKm: number): boolean {
    return this.distanceTo(center) <= radiusKm;
  }

  static fromGeoJSON([lng, lat]: [number, number]) { return new Coordinates(lat, lng); }
  toString() { return `(${this.lat.toFixed(6)}, ${this.lng.toFixed(6)})`; }
}

class BoundingBox {
  constructor(
    public readonly southwest: Coordinates,
    public readonly northeast: Coordinates,
  ) {}

  contains(p: Coordinates): boolean {
    return p.lat >= this.southwest.lat && p.lat <= this.northeast.lat &&
           p.lng >= this.southwest.lng && p.lng <= this.northeast.lng;
  }

  static fromCenter(center: Coordinates, radiusKm: number): BoundingBox {
    const dLat = radiusKm / 111;
    const dLng = radiusKm / (111 * Math.cos(toRad(center.lat)));
    return new BoundingBox(
      new Coordinates(center.lat - dLat, center.lng - dLng),
      new Coordinates(center.lat + dLat, center.lng + dLng),
    );
  }
}

class DateRange {
  constructor(public readonly start: Date, public readonly end: Date) {
    if (start > end) throw new RangeError('Start must be before end');
  }

  get durationDays() { return (this.end.getTime() - this.start.getTime()) / 86_400_000; }

  overlaps(other: DateRange): boolean {
    return this.start < other.end && this.end > other.start;
  }

  contains(date: Date): boolean { return date >= this.start && date <= this.end; }

  countWorkdays(): number {
    let count = 0;
    const d   = new Date(this.start);
    while (d <= this.end) {
      if (d.getDay() !== 0 && d.getDay() !== 6) count++;
      d.setDate(d.getDate() + 1);
    }
    return count;
  }

  static lastNDays(n: number): DateRange {
    return new DateRange(new Date(Date.now() - n * 86_400_000), new Date());
  }
}

// Clean, impossible-to-swap signatures
function findNearby(location: Coordinates, radiusKm: number): Place[] {
  return allPlaces.filter(p => p.location.isWithinRadius(location, radiusKm));
}

function getReservations(userId: string, period: DateRange): Reservation[] {
  return db.reservations.where({ userId, overlaps: period });
}

// Usage
const userLoc   = new Coordinates(51.5074, -0.1278);
const nearby    = findNearby(userLoc, 5.0);

const thisWeek  = new DateRange(new Date('2024-03-11'), new Date('2024-03-15'));
const workdays  = thisWeek.countWorkdays();  // 5
```

**Result of refactoring:**
- `(lat, lng)` → `Coordinates`: 2 params → 1, validation + haversine centralized
- `(lat, lng, minLat, maxLat, minLng, maxLng)` → `(Coordinates, BoundingBox)`: 6 params → 2
- `(startDate, endDate)` → `DateRange`: overlap/workday logic is now a method, not repeated everywhere
- Argument swap bugs impossible: `new Coordinates(lat, lng)` is self-documenting

## Proxy Pattern: Virtual and Protection Proxies

```typescript
// ---- Virtual Proxy: lazy loading ----
interface ImageLoader {
  render(): Promise<HTMLImageElement | null>;
  getMetadata(): { width: number; height: number; url: string };
}

class HeavyImage implements ImageLoader {
  private element: HTMLImageElement;
  constructor(private url: string, private width: number, private height: number) {
    this.element = new Image(width, height);
    this.element.src = url;
    console.log(`[HeavyImage] Loaded: ${url}`);
  }
  async render() {
    await new Promise<void>((res, rej) => {
      if (this.element.complete) return res();
      this.element.onload  = () => res();
      this.element.onerror = () => rej(new Error(`Load failed: ${this.url}`));
    });
    return this.element;
  }
  getMetadata() { return { width: this.width, height: this.height, url: this.url }; }
}

// Proxy: HeavyImage not created until first call to render()
class LazyImageProxy implements ImageLoader {
  private real: HeavyImage | null = null;
  constructor(private url: string, private width: number, private height: number) {}

  async render() {
    if (!this.real) {
      console.log(`[Proxy] Creating HeavyImage for ${this.url}`);
      this.real = new HeavyImage(this.url, this.width, this.height);
    }
    return this.real.render();
  }

  // Metadata available without loading the image
  getMetadata() { return { width: this.width, height: this.height, url: this.url }; }
}

// 100 images — none loaded until scrolled into view
const gallery: ImageLoader[] = Array.from({ length: 100 }, (_, i) =>
  new LazyImageProxy(`/img/photo-${i}.jpg`, 800, 600)
);

// Only img[0] loads when user scrolls to it
await gallery[0].render();
// All metadata available instantly (no network)
gallery.map(img => img.getMetadata().url); // fast

// ---- Protection Proxy: access control ----
interface DocumentService {
  read(docId: string): Promise<string>;
  write(docId: string, content: string): Promise<void>;
  delete(docId: string): Promise<void>;
}

class RealDocumentService implements DocumentService {
  async read(id: string)             { return `Content of ${id}`; }
  async write(id: string, c: string) { console.log(`Written ${id}`); }
  async delete(id: string)           { console.log(`Deleted ${id}`); }
}

type DocAction = 'read' | 'write' | 'delete';

class ProtectionProxy implements DocumentService {
  private acl: Record<DocAction, string[]> = {
    read:   ['viewer', 'editor', 'admin'],
    write:  ['editor', 'admin'],
    delete: ['admin'],
  };

  constructor(private real: DocumentService, private userRoles: string[]) {}

  private guard(action: DocAction): void {
    const permitted = this.acl[action].some(r => this.userRoles.includes(r));
    if (!permitted) throw new Error(`Permission denied: cannot ${action}`);
  }

  async read(id: string)             { this.guard('read');   return this.real.read(id); }
  async write(id: string, c: string) { this.guard('write');  return this.real.write(id, c); }
  async delete(id: string)           { this.guard('delete'); return this.real.delete(id); }
}

// Caller cannot distinguish proxy from real — same interface
function useDocService(svc: DocumentService) {
  return svc.read('doc-1'); // works with real or proxy
}

const editorSvc = new ProtectionProxy(new RealDocumentService(), ['editor']);
await editorSvc.read('doc-1');           // OK — editor can read
await editorSvc.write('doc-1', 'text'); // OK — editor can write
await editorSvc.delete('doc-1');        // throws: Permission denied
```

**Three canonical proxy variants:**
- **Virtual**: defers creation/loading until first use — lazy loading, connection pools, ORM relationships
- **Protection**: gates access without touching the real subject — RBAC, capability-based auth
- **Remote**: makes a network resource look local — gRPC stubs, REST client wrappers

All implement the target interface; the caller receives `ImageLoader` or `DocumentService` and cannot tell which variant it holds.

## Replace Conditional with Polymorphism

### Before: Type-switching across multiple functions

```typescript
// BAD: adding a new carrier ('fedex') requires touching 3 functions
type Carrier = 'ups' | 'usps' | 'dhl';

function calculateShipping(carrier: Carrier, weightKg: number, distanceKm: number): number {
  if (carrier === 'ups')  return 5.00 + weightKg * 0.85 + distanceKm * 0.02;
  if (carrier === 'usps') return 3.50 + weightKg * 0.70;       // flat rate after base
  if (carrier === 'dhl')  return 8.00 + weightKg * 1.20 + distanceKm * 0.03;
  throw new Error(`Unknown carrier: ${carrier}`);
}

function estimateDeliveryDays(carrier: Carrier, distanceKm: number): number {
  if (carrier === 'ups')  return Math.ceil(distanceKm / 800);
  if (carrier === 'usps') return Math.ceil(distanceKm / 500);
  if (carrier === 'dhl')  return Math.ceil(distanceKm / 1200); // faster
  throw new Error(`Unknown carrier: ${carrier}`);
}

function formatTrackingUrl(carrier: Carrier, trackingId: string): string {
  if (carrier === 'ups')  return `https://ups.com/track?id=${trackingId}`;
  if (carrier === 'usps') return `https://usps.com/track/${trackingId}`;
  if (carrier === 'dhl')  return `https://dhl.com/tracking?n=${trackingId}`;
  throw new Error(`Unknown carrier: ${carrier}`);
}
```

### After: Polymorphism — each carrier is self-contained

```typescript
// Strategy interface — each carrier implements this contract
interface ShippingCarrier {
  readonly id: string;
  readonly name: string;
  calculateCost(weightKg: number, distanceKm: number): number;
  estimateDeliveryDays(distanceKm: number): number;
  formatTrackingUrl(trackingId: string): string;
}

class UPSCarrier implements ShippingCarrier {
  readonly id   = 'ups';
  readonly name = 'UPS';
  calculateCost(w: number, d: number)     { return 5.00 + w * 0.85 + d * 0.02; }
  estimateDeliveryDays(d: number)         { return Math.ceil(d / 800); }
  formatTrackingUrl(id: string)           { return `https://ups.com/track?id=${id}`; }
}

class USPSCarrier implements ShippingCarrier {
  readonly id   = 'usps';
  readonly name = 'USPS';
  calculateCost(w: number, _d: number)   { return 3.50 + w * 0.70; }
  estimateDeliveryDays(d: number)        { return Math.ceil(d / 500); }
  formatTrackingUrl(id: string)          { return `https://usps.com/track/${id}`; }
}

class DHLCarrier implements ShippingCarrier {
  readonly id   = 'dhl';
  readonly name = 'DHL';
  calculateCost(w: number, d: number)   { return 8.00 + w * 1.20 + d * 0.03; }
  estimateDeliveryDays(d: number)       { return Math.ceil(d / 1200); }
  formatTrackingUrl(id: string)         { return `https://dhl.com/tracking?n=${id}`; }
}

// Adding FedEx: write ONE class, nothing else changes (Open/Closed Principle)
class FedExCarrier implements ShippingCarrier {
  readonly id   = 'fedex';
  readonly name = 'FedEx';
  calculateCost(w: number, d: number)   { return 6.50 + w * 0.95 + d * 0.025; }
  estimateDeliveryDays(d: number)       { return Math.ceil(d / 1000); }
  formatTrackingUrl(id: string)         { return `https://fedex.com/tracking?tracknumbers=${id}`; }
}

// Registry maps string IDs to carrier instances
class CarrierRegistry {
  private carriers = new Map<string, ShippingCarrier>();

  register(carrier: ShippingCarrier): this {
    this.carriers.set(carrier.id, carrier);
    return this;
  }

  get(id: string): ShippingCarrier {
    const carrier = this.carriers.get(id);
    if (!carrier) throw new Error(`Unknown carrier: ${id}`);
    return carrier;
  }

  all(): ShippingCarrier[] { return [...this.carriers.values()]; }

  cheapest(weightKg: number, distanceKm: number): ShippingCarrier {
    return this.all().reduce((best, c) =>
      c.calculateCost(weightKg, distanceKm) < best.calculateCost(weightKg, distanceKm) ? c : best
    );
  }
}

const registry = new CarrierRegistry()
  .register(new UPSCarrier())
  .register(new USPSCarrier())
  .register(new DHLCarrier())
  .register(new FedExCarrier()); // no other files changed

// Application code
function quoteShipment(carrierId: string, weightKg: number, distanceKm: number) {
  const carrier = registry.get(carrierId);
  return {
    cost:     carrier.calculateCost(weightKg, distanceKm),
    days:     carrier.estimateDeliveryDays(distanceKm),
    carrier:  carrier.name,
  };
}

// Find cheapest carrier automatically
const best = registry.cheapest(2.5, 500);
console.log(`Best: ${best.name} at $${best.calculateCost(2.5, 500).toFixed(2)}`);
```

**Open/Closed Principle in action:** The carrier interface is closed for modification (callers never change). Adding a new carrier is open via a new class + one `.register()` call. The three type-switching functions (calculateShipping, estimateDeliveryDays, formatTrackingUrl) are now zero lines of branching code.

