from __future__ import annotations
from typing import Any


class OrderTracker(dict):
    """Dict subclass that records insertion order of callables."""

    def __init__(self) -> None:
        super().__init__()
        self._method_order: list[str] = []

    def __setitem__(self, key: str, value: Any) -> None:
        if callable(value) and not key.startswith("__"):
            self._method_order.append(key)
        super().__setitem__(key, value)


class OrderedMeta(type):
    @classmethod
    def __prepare__(mcs, name: str, bases: tuple[type, ...], **kwargs) -> OrderTracker:
        # Python calls this before executing the class body
        # The returned mapping becomes the class namespace
        return OrderTracker()

    def __new__(mcs, name: str, bases: tuple[type, ...], ns: OrderTracker, **kwargs):
        cls = super().__new__(mcs, name, bases, dict(ns))
        cls._method_order = ns._method_order  # freeze for inspection
        return cls


class Pipeline(metaclass=OrderedMeta):
    def ingest(self, data): ...
    def clean(self, data): ...
    def transform(self, data): ...
    def load(self, data): ...


print(Pipeline._method_order)
# ['ingest', 'clean', 'transform', 'load']

# Practical use: run pipeline stages in definition order
class ETL(metaclass=OrderedMeta):
    def __init__(self, data):
        self.data = data

    def step_extract(self):
        print("extract")
        return self

    def step_transform(self):
        print("transform")
        return self

    def step_load(self):
        print("load")
        return self

    def run(self):
        for name in self._method_order:
            if name.startswith("step_"):
                getattr(self, name)()


ETL(None).run()
# extract
# transform
# load
```

`__prepare__` is called before the class body executes, giving you control over the namespace object Python uses to collect names. This is how `enum.EnumMeta` tracks member definition order.

```python
from __future__ import annotations
from typing import Callable, TypeVar, ParamSpec, Concatenate
from functools import wraps
import time
import logging

P = ParamSpec('P')   # captures the wrapped function's original parameter spec
R = TypeVar('R')     # return type

logger = logging.getLogger(__name__)


def retry(
    max_attempts: int = 3,
    delay: float = 0.5,
    exceptions: tuple[type[Exception], ...] = (Exception,),
) -> Callable[[Callable[P, R]], Callable[P, R]]:
    def decorator(func: Callable[P, R]) -> Callable[P, R]:
        @wraps(func)
        def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
            last_exc: Exception | None = None
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except exceptions as exc:
                    last_exc = exc
                    logger.warning('Attempt %d/%d failed: %s', attempt+1, max_attempts, exc)
                    if attempt < max_attempts - 1:
                        time.sleep(delay * (2 ** attempt))
            raise RuntimeError(f'All {max_attempts} attempts failed') from last_exc
        return wrapper
    return decorator


@retry(max_attempts=3, delay=0.001, exceptions=(ValueError,))
def parse_int(text: str, *, base: int = 10) -> int:
    return int(text, base)


# mypy knows: parse_int(text: str, *, base: int = 10) -> int
print(parse_int('ff', base=16))  # 255
print(parse_int('42'))           # 42


# Concatenate: inject/consume one specific leading argument
def logged(func: Callable[Concatenate[str, P], R]) -> Callable[P, R]:
    @wraps(func)
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        return func('[LOG]', *args, **kwargs)
    return wrapper


@logged
def send(prefix: str, message: str, *, priority: int = 0) -> str:
    return f'{prefix} priority={priority}: {message}'


# Caller only sees (message: str, *, priority: int = 0) -> str
print(send('hello', priority=1))  # [LOG] priority=1: hello
```

`P.args` and `P.kwargs` must always be used together as a pair in `wrapper(*args: P.args, **kwargs: P.kwargs)`. Without `ParamSpec`, the wrapper has type `(*Any, **Any) -> Any` and mypy cannot validate call sites.

