from __future__ import annotations
from typing import TypeVar, Generic, Callable, Iterator


# Invariant (default): read AND write
T = TypeVar('T')

class Stack(Generic[T]):
    def __init__(self) -> None:
        self._items: list[T] = []
    def push(self, item: T) -> None: self._items.append(item)
    def pop(self) -> T: return self._items.pop()
    def __len__(self) -> int: return len(self._items)


# Covariant: read-only (Producer/Source)
T_co = TypeVar('T_co', covariant=True)

class ReadOnlyBox(Generic[T_co]):
    def __init__(self, value: T_co) -> None: self._value = value
    def get(self) -> T_co: return self._value


def print_float_box(box: ReadOnlyBox[float]) -> None:
    print(box.get())


int_box: ReadOnlyBox[int] = ReadOnlyBox(42)
print_float_box(int_box)  # OK: ReadOnlyBox[int] is-a ReadOnlyBox[float]


# Contravariant: write-only (Consumer/Sink)
T_contra = TypeVar('T_contra', contravariant=True)

class Sink(Generic[T_contra]):
    def __init__(self, handler: Callable[[T_contra], None]) -> None:
        self._handler = handler
    def send(self, value: T_contra) -> None: self._handler(value)


def log_float(x: float) -> None: print(f'float: {x}')


float_sink: Sink[float] = Sink(log_float)


def process_ints(sink: Sink[int]) -> None:
    sink.send(1)
    sink.send(2)


process_ints(float_sink)  # OK: Sink[float] is-a Sink[int] (contravariance)


# Bounded TypeVar
from typing import SupportsFloat
Numeric = TypeVar('Numeric', bound=SupportsFloat)

def to_float(value: Numeric) -> float:
    return float(value)


print(to_float(42))     # 42.0
print(to_float(3.14))   # 3.14
print(to_float('2.71')) # 2.71
```

Rule of thumb: **Invariant** (default) — containers you both read and write; **Covariant** (`T_co`) — producers/read-only like `Iterator[T_co]`, `Sequence[T_co]`; **Contravariant** (`T_contra`) — consumers/sinks like `Callable[[T_contra], None]`. Invariance prevents the classic `list[int]` is-not-`list[float]` pitfall.

