# Overload with Literal for exhaustive branching
@overload
def get_mode(strict: Literal[True]) -> int: ...
@overload
def get_mode(strict: Literal[False]) -> int | None: ...
@overload
def get_mode(strict: bool = ...) -> int | None: ...

def get_mode(strict: bool = False) -> int | None:
    result = 42
    if result is None and strict:
        raise ValueError('Not found')
    return result


val: int       = get_mode(True)   # guaranteed non-None
val2: int|None = get_mode(False)  # may be None


# TypeIs: two-way narrowing (True -> T, False -> NOT T)
def is_str_list(val: list[object]) -> TypeIs[list[str]]:
    return all(isinstance(x, str) for x in val)


def process(data: list[str] | list[int]) -> None:
    if is_str_list(data):  # type: ignore[arg-type]
        print(' '.join(data))      # type checker: list[str]
    else:
        print(sum(data))           # type checker (TypeIs): list[int]


process(['a', 'b', 'c'])
process([1, 2, 3])
