from hypothesis import given, settings
from hypothesis import strategies as st
from hypothesis.stateful import RuleBasedStateMachine, rule, invariant
import bisect


class SortedList:
    def __init__(self):
        self._data: list[int] = []
    def add(self, value: int) -> None:
        bisect.insort(self._data, value)
    def remove(self, value: int) -> None:
        i = bisect.bisect_left(self._data, value)
        if i < len(self._data) and self._data[i] == value:
            self._data.pop(i)
    def __contains__(self, value: int) -> bool:
        i = bisect.bisect_left(self._data, value)
        return i < len(self._data) and self._data[i] == value
    def is_sorted(self) -> bool:
        return self._data == sorted(self._data)
    def __len__(self) -> int:
        return len(self._data)


@given(st.lists(st.integers()))
def test_add_maintains_sort(values: list[int]) -> None:
    sl = SortedList()
    for v in values:
        sl.add(v)
    assert sl.is_sorted()
    assert len(sl) == len(values)


@given(st.lists(st.integers(min_value=-100, max_value=100), min_size=1))
def test_added_elements_are_findable(values: list[int]) -> None:
    sl = SortedList()
    for v in values:
        sl.add(v)
    for v in values:
        assert v in sl


# Custom composite strategy
@st.composite
def sorted_list_and_element(draw):
    values = draw(st.lists(st.integers(), min_size=1, max_size=20))
    sl = SortedList()
    for v in values:
        sl.add(v)
    element = draw(st.sampled_from(values))
    return sl, element


@given(sorted_list_and_element())
def test_remove_works(args) -> None:
    sl, element = args
    sl.remove(element)
    assert sl.is_sorted()


# Stateful testing: explore sequences of operations
class SortedListMachine(RuleBasedStateMachine):
    def __init__(self):
        super().__init__()
        self.model: set[int] = set()  # reference
        self.sut = SortedList()        # system under test

    @rule(value=st.integers())
    def add(self, value: int) -> None:
        self.model.add(value)
        self.sut.add(value)

    @rule(value=st.integers())
    def remove(self, value: int) -> None:
        self.model.discard(value)
        self.sut.remove(value)

    @invariant()
    def stays_sorted(self) -> None:
        assert self.sut.is_sorted()

    @invariant()
    def size_matches_model(self) -> None:
        assert len(self.sut) == len(self.model)


TestSortedList = SortedListMachine.TestCase
```

When Hypothesis finds a failure it **shrinks** the input to the minimal reproducing case — a list of 200 elements becomes `[0, 1]`. Stateful testing with `RuleBasedStateMachine` explores sequences of operations (up to 200 steps by default) rather than single inputs, uncovering bugs that only appear after specific operation sequences.

```python
from __future__ import annotations
import inspect
from typing import Any, Callable, TypeVar, get_type_hints

T = TypeVar('T')


class Container:
    def __init__(self) -> None:
        self._factories: dict[type, Callable[[], Any]] = {}
        self._singletons: dict[type, Any] = {}
        self._singleton_types: set[type] = set()

    def register(self, iface: type[T], factory: Callable[[], T], singleton: bool = False) -> None:
        self._factories[iface] = factory
        if singleton:
            self._singleton_types.add(iface)

    def register_instance(self, iface: type[T], instance: T) -> None:
        self._singletons[iface] = instance

    def resolve(self, iface: type[T]) -> T:
        if iface in self._singletons:
            return self._singletons[iface]
        if iface in self._factories:
            instance = self._factories[iface]()
            if iface in self._singleton_types:
                self._singletons[iface] = instance
            return instance
        return self._autowire(iface)

    def _autowire(self, cls: type[T]) -> T:
        try:
            hints = get_type_hints(cls.__init__)
        except Exception:
            return cls()
        kwargs: dict[str, Any] = {}
        for name, param in inspect.signature(cls.__init__).parameters.items():
            if name == 'self':
                continue
            dep_type = hints.get(name)
            if dep_type:
                kwargs[name] = self.resolve(dep_type)
            elif param.default is inspect.Parameter.empty:
                raise TypeError(f'Cannot autowire {cls.__name__}.{name}: no type hint')
        return cls(**kwargs)


# Concrete classes
class Logger:
    def log(self, msg: str) -> None: print(f'[LOG] {msg}')


class Database:
    def __init__(self, logger: Logger) -> None:
        self.logger = logger
    def query(self, sql: str) -> list:
        self.logger.log(f'Query: {sql}')
        return [{'id': 1}]


class UserService:
    def __init__(self, db: Database, logger: Logger) -> None:
        self.db = db
        self.logger = logger
    def get_user(self, uid: int) -> dict:
        self.logger.log(f'Getting user {uid}')
        return self.db.query(f'SELECT * FROM users WHERE id={uid}')[0]


# Production wiring
container = Container()
container.register(Logger, Logger, singleton=True)
# Database and UserService auto-wired
svc = container.resolve(UserService)
print(svc.get_user(42))  # {'id': 1}

# Test wiring: swap Logger without touching production code
class SilentLogger:
    def log(self, msg: str) -> None: pass

test_container = Container()
test_container.register_instance(Logger, SilentLogger())  # type: ignore
test_svc = test_container.resolve(UserService)
test_svc.get_user(1)  # silent
```

Constructor injection is the most testable form of DI: dependencies are explicit in the signature and easy to replace in tests. Auto-wiring by type hint eliminates boilerplate registration for leaf classes. Singleton scope ensures expensive resources (DB connections, loggers) are shared.

```python
from __future__ import annotations
from abc import ABC, abstractmethod
from copy import deepcopy
from dataclasses import dataclass, field
from contextlib import contextmanager
from typing import Iterator


@dataclass
class User:
    id: int
    name: str
    email: str

    def rename(self, new_name: str) -> None:
        self.name = new_name


class UserRepository(ABC):
    @abstractmethod
    def get(self, user_id: int) -> User | None: ...
    @abstractmethod
    def add(self, user: User) -> None: ...
    @abstractmethod
    def list_all(self) -> list[User]: ...


class InMemoryUserRepository(UserRepository):
    def __init__(self, store: dict[int, User]) -> None:
        self._store = store
    def get(self, user_id: int) -> User | None:
        u = self._store.get(user_id)
        return deepcopy(u) if u else None
    def add(self, user: User) -> None:
        self._store[user.id] = deepcopy(user)
    def list_all(self) -> list[User]:
        return [deepcopy(u) for u in self._store.values()]


class UnitOfWork:
    def __init__(self, shared_store: dict[int, User]) -> None:
        self._shared = shared_store
        self._snapshot = deepcopy(shared_store)  # working copy
        self.users = InMemoryUserRepository(self._snapshot)
        self._committed = False

    def commit(self) -> None:
        self._shared.clear()
        self._shared.update(deepcopy(self._snapshot))
        self._committed = True

    def rollback(self) -> None:
        self._snapshot.clear()
        self._snapshot.update(deepcopy(self._shared))

    def __enter__(self) -> 'UnitOfWork':
        return self

    def __exit__(self, exc_type, exc_val, exc_tb) -> bool:
        if exc_type is None and not self._committed:
            self.commit()
        elif exc_type is not None:
            self.rollback()
        return False


class UserService:
    def __init__(self, store: dict[int, User]) -> None:
        self._store = store

    @contextmanager
    def _uow(self) -> Iterator[UnitOfWork]:
        with UnitOfWork(self._store) as uow:
            yield uow

    def create_user(self, user_id: int, name: str, email: str) -> User:
        with self._uow() as uow:
            if uow.users.get(user_id):
                raise ValueError(f'User {user_id} exists')
            user = User(id=user_id, name=name, email=email)
            uow.users.add(user)
        return user

    def rename_user(self, user_id: int, new_name: str) -> None:
        with self._uow() as uow:
            user = uow.users.get(user_id)
            if user is None:
                raise KeyError(user_id)
            user.rename(new_name)
            uow.users.add(user)


store: dict[int, User] = {}
svc = UserService(store)
svc.create_user(1, 'Alice', 'alice@example.com')
svc.rename_user(1, 'Alicia')

with UnitOfWork(store) as uow:
    print(uow.users.get(1))  # User(id=1, name='Alicia', ...)
```

The Unit of Work works on a snapshot of the store. `commit()` atomically flushes to the shared store; `rollback()` silently discards all changes. The `__exit__` auto-commit on no-exception makes the common path ergonomic. In tests, start each test with a fresh `{}` store — no database cleanup needed.

```python
from __future__ import annotations
import importlib
import importlib.util
import sys
from pathlib import Path
from abc import ABC, abstractmethod


class FormatterPlugin(ABC):
    name: str
    version: str = '1.0'

    @abstractmethod
    def format(self, data: dict) -> str: ...

    def __init_subclass__(cls, **kwargs):
        super().__init_subclass__(**kwargs)
        if hasattr(cls, 'name') and cls.name:
            PluginRegistry.register(cls)


class PluginRegistry:
    _plugins: dict[str, type[FormatterPlugin]] = {}

    @classmethod
    def register(cls, plugin_cls: type[FormatterPlugin]) -> None:
        cls._plugins[plugin_cls.name] = plugin_cls
        print(f'  Registered: {plugin_cls.name} v{plugin_cls.version}')

    @classmethod
    def get(cls, name: str) -> type[FormatterPlugin]:
        if name not in cls._plugins:
            raise KeyError(f"Plugin '{name}' not found. Available: {list(cls._plugins)}")
        return cls._plugins[name]

    @classmethod
    def all(cls) -> dict[str, type[FormatterPlugin]]:
        return dict(cls._plugins)


class JsonFormatter(FormatterPlugin):
    name = 'json'
    version = '1.2'
    def format(self, data: dict) -> str:
        import json
        return json.dumps(data, indent=2)


def load_plugins_from_dir(plugin_dir: Path) -> None:
    for path in sorted(plugin_dir.glob('*.py')):
        if path.stem.startswith('_'):
            continue
        module_name = f'_plugins.{path.stem}'
        spec = importlib.util.spec_from_file_location(module_name, path)
        if spec and spec.loader:
            module = importlib.util.module_from_spec(spec)
            sys.modules[module_name] = module
            try:
                spec.loader.exec_module(module)  # type: ignore
                print(f'  Loaded: {path.name}')
            except Exception as e:
                print(f'  Failed {path.name}: {e}')


def load_plugins_from_entry_points(group: str = 'myapp.formatters') -> None:
    # Plugins declare in pyproject.toml:
    # [project.entry-points."myapp.formatters"]
    # csv = "myplugin.formatters:CsvFormatter"
    try:
        from importlib.metadata import entry_points
        for ep in entry_points(group=group):
            try:
                ep.load()
                print(f'  Entry point: {ep.name}')
            except Exception as e:
                print(f'  Failed {ep.name}: {e}')
    except Exception as e:
        print(f'  EP discovery failed: {e}')


if __name__ == '__main__':
    print('Built-in:', list(PluginRegistry.all().keys()))  # ['json']
    fmt = PluginRegistry.get('json')()
    print(fmt.format({'hello': 'world'}))
    plugin_dir = Path('./plugins')
    if plugin_dir.exists():
        load_plugins_from_dir(plugin_dir)
        load_plugins_from_entry_points()
```

Entry points are the production pattern: plugins declare themselves in `pyproject.toml`, and the host app discovers them with `importlib.metadata.entry_points()` — no hardcoded imports. `__init_subclass__` auto-registers every `FormatterPlugin` subclass the moment its module is imported, making both discovery strategies work identically from the registry's perspective.

```python
from __future__ import annotations
import ast
import importlib
import importlib.abc
import importlib.machinery
import importlib.util
import sys
import time
from pathlib import Path
from typing import Any


# ── AST transformer: wrap every function body in a timer ──────────────────────
class ProfileInjector(ast.NodeTransformer):
    def visit_FunctionDef(self, node: ast.FunctionDef) -> ast.AST:
        self.generic_visit(node)  # recurse into nested functions
        # Inject: _t0 = time.perf_counter() at start
        t0_assign = ast.parse(
            f'_profiler_t0_{node.name} = __import__("time").perf_counter()'
        ).body[0]
        # Inject: print(...) at end — simplified; production would use try/finally
        print_stmt = ast.parse(
            f'print(f"{node.name} took {{__import__(\"time\").perf_counter() - _profiler_t0_{node.name}:.6f}}s")'
        ).body[0]
        node.body = [t0_assign] + node.body[:-1] + [print_stmt, node.body[-1]]
        return node

    visit_AsyncFunctionDef = visit_FunctionDef


# ── Custom loader that transforms source before compiling ──────────────────────
class ProfilingLoader(importlib.abc.SourceLoader):
    def __init__(self, fullname: str, path: str) -> None:
        self.fullname = fullname
        self.path = path

    def get_filename(self, fullname: str) -> str:
        return self.path

    def get_data(self, path: str) -> bytes:
        with open(path, 'rb') as f:
            return f.read()

    def source_to_code(self, data: bytes | str, path: str, *, _optimize: int = -1):
        source = data if isinstance(data, str) else data.decode('utf-8')
        try:
            tree = ast.parse(source, filename=path)
            tree = ProfileInjector().visit(tree)
            ast.fix_missing_locations(tree)
            source = ast.unparse(tree)
        except SyntaxError:
            pass  # fall through to unmodified source on parse error
        return compile(source, path, 'exec', optimize=_optimize)


# ── Finder: intercept imports of modules in 'profiled' package ────────────────
class ProfilingFinder(importlib.abc.MetaPathFinder):
    def __init__(self, prefix: str) -> None:
        self.prefix = prefix

    def find_spec(self, fullname: str, path: Any, target: Any = None):
        if not fullname.startswith(self.prefix):
            return None
        spec = importlib.util.find_spec(fullname)
        if spec is None or spec.origin is None or not spec.origin.endswith('.py'):
            return None
        loader = ProfilingLoader(fullname, spec.origin)
        return importlib.machinery.ModuleSpec(
            fullname, loader, origin=spec.origin,
            is_package=spec.submodule_search_locations is not None,
        )


def install_profiling(prefix: str = 'myapp.') -> None:
    sys.meta_path.insert(0, ProfilingFinder(prefix))
    print(f'Profiling hook active for {prefix!r}')


def remove_profiling() -> None:
    sys.meta_path[:] = [f for f in sys.meta_path if not isinstance(f, ProfilingFinder)]


# Demonstration with an in-memory module
if __name__ == '__main__':
    install_profiling('demo_')
    # Any import of demo_* would now get auto-profiled
    print('Import hooks:', [type(f).__name__ for f in sys.meta_path[:3]])
    remove_profiling()
    print('Hook removed:', [type(f).__name__ for f in sys.meta_path[:3]])
```

`ast.NodeTransformer.visit_*` methods return the replacement node (or `None` to delete). `ast.fix_missing_locations()` propagates line number info to any nodes we inserted — without it `compile()` raises `ValueError: required field lineno missing`. `ast.unparse()` (3.9+) converts the modified AST back to source for `compile()`. This pattern is how coverage.py, typeguard, and beartype instrument code at import time.

