import math
import array
import struct
from typing import Iterator


class Vec2:
    """
    High-performance 2D vector: __slots__ + array buffer.
    Avoids per-instance dict, enables buffer protocol, fast arithmetic.
    """
    __slots__ = ('_buf',)

    def __init__(self, x: float, y: float) -> None:
        self._buf = array.array('d', [x, y])  # contiguous C doubles

    @property
    def x(self) -> float: return self._buf[0]
    @property
    def y(self) -> float: return self._buf[1]

    def __add__(self, other: 'Vec2') -> 'Vec2':
        return Vec2(self._buf[0] + other._buf[0], self._buf[1] + other._buf[1])

    def __sub__(self, other: 'Vec2') -> 'Vec2':
        return Vec2(self._buf[0] - other._buf[0], self._buf[1] - other._buf[1])

    def __mul__(self, scalar: float) -> 'Vec2':
        return Vec2(self._buf[0] * scalar, self._buf[1] * scalar)

    __rmul__ = __mul__

    def dot(self, other: 'Vec2') -> float:
        return self._buf[0] * other._buf[0] + self._buf[1] * other._buf[1]

    def length(self) -> float:
        return math.hypot(self._buf[0], self._buf[1])

    def normalized(self) -> 'Vec2':
        mag = self.length()
        if mag == 0:
            raise ValueError('Cannot normalize zero vector')
        return self * (1.0 / mag)

    def __iter__(self) -> Iterator[float]:
        return iter(self._buf)

    def __repr__(self) -> str:
        return f'Vec2({self._buf[0]:.4f}, {self._buf[1]:.4f})'

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, Vec2):
            return NotImplemented
        return self._buf[0] == other._buf[0] and self._buf[1] == other._buf[1]

    def __hash__(self):
        return hash((self._buf[0], self._buf[1]))

    # Buffer protocol: allows numpy to wrap Vec2 without copying
    def __buffer__(self, flags: int):
        return memoryview(self._buf)


# Bulk operations over many vectors
def sum_vectors(vecs: list[Vec2]) -> Vec2:
    # Faster than repeated __add__ for large lists
    xs = array.array('d', (v.x for v in vecs))
    ys = array.array('d', (v.y for v in vecs))
    return Vec2(sum(xs), sum(ys))


import sys
v1 = Vec2(3.0, 4.0)
v2 = Vec2(1.0, 2.0)
print(v1 + v2)              # Vec2(4.0000, 6.0000)
print(v1.length())          # 5.0
print(v1.normalized())      # Vec2(0.6000, 0.8000)
print(v1.dot(v2))           # 11.0
print(sys.getsizeof(v1))    # smaller than dict-based instance
print(hasattr(v1, '__dict__'))  # False
print(list(v1))             # [3.0, 4.0]
```

`__slots__` + `array.array` gives three wins: no per-instance `__dict__` allocation, contiguous C memory layout for the payload, and buffer protocol compatibility so numpy can view the data without copying. `math.hypot` is faster and more numerically stable than `sqrt(x**2+y**2)`. For truly hot inner loops, delegate to numpy arrays of Vec2 data rather than Python objects.

```python
from __future__ import annotations
from typing import Iterator
from collections import defaultdict
import math


class SparseMatrix:
    """
    Dictionary-of-keys sparse matrix.
    Stores only non-zero values; O(nnz) memory.
    """

    def __init__(self, rows: int, cols: int) -> None:
        if rows <= 0 or cols <= 0:
            raise ValueError('Dimensions must be positive')
        self.rows = rows
        self.cols = cols
        self._data: dict[tuple[int, int], float] = {}

    def _check(self, r: int, c: int) -> None:
        if not (0 <= r < self.rows and 0 <= c < self.cols):
            raise IndexError(f'Index ({r},{c}) out of bounds for {self.rows}x{self.cols}')

    def __getitem__(self, key: tuple[int, int]) -> float:
        r, c = key
        self._check(r, c)
        return self._data.get((r, c), 0.0)

    def __setitem__(self, key: tuple[int, int], value: float) -> None:
        r, c = key
        self._check(r, c)
        if value == 0.0:
            self._data.pop((r, c), None)  # keep sparse: remove explicit zeros
        else:
            self._data[(r, c)] = value

    def __matmul__(self, other: 'SparseMatrix') -> 'SparseMatrix':
        if self.cols != other.rows:
            raise ValueError(f'Shape mismatch: ({self.rows},{self.cols}) @ ({other.rows},{other.cols})')
        result = SparseMatrix(self.rows, other.cols)
        # Only iterate over non-zero pairs: O(nnz_A * nnz_B_per_col) not O(n^3)
        # Group other's data by row for efficient column lookup
        other_by_row: dict[int, list[tuple[int, float]]] = defaultdict(list)
        for (r, c), v in other._data.items():
            other_by_row[r].append((c, v))
        for (ar, ac), av in self._data.items():
            for bc, bv in other_by_row.get(ac, []):
                result[ar, bc] = result[ar, bc] + av * bv
        return result

    def __add__(self, other: 'SparseMatrix') -> 'SparseMatrix':
        if self.rows != other.rows or self.cols != other.cols:
            raise ValueError('Shape mismatch')
        result = SparseMatrix(self.rows, self.cols)
        result._data = dict(self._data)
        for key, val in other._data.items():
            result._data[key] = result._data.get(key, 0.0) + val
            if result._data[key] == 0.0:
                del result._data[key]
        return result

    def __repr__(self) -> str:
        lines = [f'SparseMatrix({self.rows}x{self.cols}, nnz={len(self._data)})']
        for (r, c), v in sorted(self._data.items()):
            lines.append(f'  [{r},{c}] = {v}')
        return '\n'.join(lines)

    def nnz(self) -> int:
        return len(self._data)

    def density(self) -> float:
        return self.nnz() / (self.rows * self.cols)

    def frobenius_norm(self) -> float:
        return math.sqrt(sum(v * v for v in self._data.values()))


# ── Usage ─────────────────────────────────────────────────────────────────────
A = SparseMatrix(3, 3)
A[0, 0] = 1.0
A[1, 1] = 2.0
A[2, 2] = 3.0
A[0, 2] = 0.5

B = SparseMatrix(3, 3)
B[0, 0] = 1.0
B[1, 1] = 1.0
B[2, 2] = 1.0  # identity

C = A @ B
print(C)         # A @ I = A
print(A[0, 2])   # 0.5
A[0, 2] = 0.0    # removes from storage
print(A.nnz())   # 3
print(A.frobenius_norm())  # sqrt(1+4+9) = 3.742
```

`__matmul__` (the `@` operator since Python 3.5) is the standard hook for matrix multiplication. The sparse implementation iterates only non-zero entries of A, then looks up B's non-zero entries in the same column — reducing the inner loop from O(n) to O(nnz_per_col). Removing explicit zero assignments from `_data` keeps the representation truly sparse.
